 *         premium: 99.99;
 *         enterprise: 999.99;
 *       }>;
 *     status: string &
 *       Examples<{
 *         active: "active";
 *         discontinued: "discontinued";
 *         preorder: "preorder";
 *       }>;
 *   }
 *
 * @template Value Record mapping example names to their values
 */
