@typia/interface/src/tags/Exclude.ts:
import { TagBase } from "./TagBase";

/**
 * Excluded literal values.
 *
 * `Exclude<Values>` is a type tag that rejects the listed literal values while
 * keeping the rest of the base type valid. List every excluded value in one
 * tuple — the tag is exclusive, so a second `Exclude` on the same type is a
 * compile error (their JSON schema fragments could not merge).
 *
 * In JSON schema the constraint appears as `not: { enum: [...] }`. Strict LLM
 * schemas reject this tag. `typia.random` does not consult it either: generated
 * values may collide with the excluded list.
 *
 * @author Jeongho Nam - https://github.com/samchon
 * @example
 *   interface IConfig {
 *     port: number & tags.Exclude<[0, 22, 80]>;
 *     name: string & tags.Exclude<["admin", "root"]>;
 *   }
 *
 * @template Values Tuple of excluded literal values
 */
export type Exclude<Values extends readonly (bigint | number | string)[]> =
  TagBase<{
    target: "bigint" | "number" | "string";
    kind: "exclude";
    value: undefined;
    exclusive: true;
    schema: {
      not: {
        enum: Values;
      };
    };
  }>;

@typia/interface/src/tags/ExclusiveMaxim:
import { TagBase } from "./TagBase";

/**
 * Exclusive maximum value constraint (value < max).
 *
 * `ExclusiveMaximum<N>` is a type tag that validates numeric values are
 * strictly less than the specified bound (not equal). Apply it to `number` or
 * `bigint` properties using TypeScript intersection types.
 *
 * This constraint is **mutually exclusive** with {@link Maximum} - you cannot
 * use both on the same property. Use `ExclusiveMaximum` for exclusive bounds
 * (<) and `Maximum` for inclusive bounds (<=).
 *
 * The constraint is enforced at runtime by `typia.is()`, `typia.assert()`, and
 * `typia.validate()`. It also generates `exclusiveMaximum` in JSON Schema.
 *
 * @author Jeongho Nam - https://github.com/samchon
 * @example
 *   interface Temperature {
 *     // Must be less than 100 (boiling point), not equal
 *     celsius: number & ExclusiveMaximum<100>;
 *   }
 *
 * @template Value The maximum bound (exclusive - value must be less)
 */
export type ExclusiveMaximum<Value extends number | bigint> = TagBase<{
  target: Value extends bigint ? "bigint" : "number";
  kind: "exclusiveMaximum";
  value: Value;
  validate: `$input < ${Cast<Value>}`;
  exclusive: ["exclusiveMaximum", "maximum"];
  schema: Value extends bigint
    ? {
        exclusiveMaximum: Numeric<Value>;
      }
    : {
        exclusiveMaximum: Value;
      };
}>;

type Cast<Value extends number | bigint> = Value extends number
  ? Value
  : `BigInt(${Value})`;
type Numeric<T extends bigint> = `${T}` extends `${infer N extends number}`
  ? N
  : never;

