@typia/utils/src/converters/internal/Llm:
import { ILlmSchema, OpenApi } from "@typia/interface";

import { OpenApiExclusiveEmender } from "./OpenApiExclusiveEmender";

/**
 * Reader for the constraints `OpenApiConstraintShifter` moved into a
 * description.
 *
 * The shifter and this reader are one pair, so they share one gate. The shifter
 * moves constraints into the description only under `strict`, so this reader
 * reads them back only under `strict` too: every function here takes the config
 * that produced the schema and reports nothing outside that mode.
 *
 * Without that gate an `@minimum 3` written by a documentation author would be
 * promoted to a constraint the type never declared, and, because these results
 * are spread over the live schema, the lookups that found nothing would delete
 * the real keywords a non-strict schema still carries.
 */
export namespace LlmDescriptionInverter {
  export const numeric = (props: {
    config: ILlmSchema.IConfig;
    description: string | undefined;
  }): Pick<
    OpenApi.IJsonSchema.INumber,
    | "minimum"
    | "maximum"
    | "exclusiveMinimum"
    | "exclusiveMaximum"
    | "multipleOf"
    | "default"
    | "description"
  > => {
    const description: string | undefined = read(props);
    if (description === undefined) return {};

    const lines: string[] = description.split("\n");
    return {
      ...compact({
        ...OpenApiExclusiveEmender.emend({
          minimum: find({
            type: "number",
            name: "minimum",
            lines,
          }),
          maximum: find({
            type: "number",
            name: "maximum",
            lines,
          }),
          exclusiveMinimum: find({
            type: "number",
            name: "exclusiveMinimum",
            lines,
          }),
          exclusiveMaximum: find({
            type: "number",
            name: "exclusiveMaximum",
            lines,
          }),
          multipleOf: find({
            type: "number",
            name: "multipleOf",
            lines,
          }),
        }),
        // The write half shifts `default` into the description as `@default 7`
        // just like every other numeric keyword; restore it here so the numeric
        // path round-trips symmetrically with the string path.
        default: find({
          type: "number",
          name: "default",
          lines,
        }),
      }),
      description: describe(lines, [
        "minimum",
        "maximum",
        "exclusiveMinimum",
        "exclusiveMaximum",
        "multipleOf",
        "default",
      ]),
    };
  };

  export const string = (props: {
    config: ILlmSchema.IConfig;
    description: string | undefined;
  }): Pick<
    OpenApi.IJsonSchema.IString,
    | "format"
    | "pattern"
    | "contentMediaType"
    | "minLength"
    | "maxLength"
    | "default"
    | "description"
  > => {
    const description: string | undefined = read(props);
    if (description === undefined) return {};

    const lines: string[] = description.split("\n");
    return {
      ...compact({
        format: find({
          type: "string",
          name: "format",
          lines,
        }),
        pattern: find({
          type: "string",
          name: "pattern",
          lines,
        }),
        contentMediaType: find({
          type: "string",
          name: "contentMediaType",
          lines,
        }),
        minLength: find({
          type: "number",
          name: "minLength",
          lines,
        }),
        maxLength: find({
          type: "number",
          name: "maxLength",
          lines,
        }),
        // The write half shifts `default` into the description as
        // `@default value`; restore it here so a documented string default is
        // read back rather than left behind as prose.
        default: find({
          type: "string",
          name: "default",
          lines,
        }),
      }),
      description: describe(lines, [
        "format",
        "pattern",
        "contentMediaType",
        "minLength",
        "maxLength",
        "default",
      ]),
    };
  };

  export const array = (props: {
    config: ILlmSchema.IConfig;
    description: string | undefined;
  }): Pick<
    OpenApi.IJsonSchema.IArray,
    "minItems" | "maxItems" | "uniqueItems" | "description"
  > => {
    const description: string | undefined = read(props);
    if (description === undefined) return {};

    const lines: string[] = description.split("\n");
    return {
      ...compact({
        minItems: find({
          type: "number",
          name: "minItems",
          lines,
        }),
        maxItems: find({
          type: "number",
          name: "maxItems",
          lines,
        }),
        uniqueItems: find({
          type: "boolean",
          name: "uniqueItems",
          lines,
        }),
      }),
      description: describe(lines, ["minItems", "maxItems", "uniqueItems"]),
    };
  };

  /**
   * Yield the description to read, or nothing when this mode wrote no tags.
   *
   * Only a `strict` conversion shifts constraints into the description. Under
   * any other config there is nothing to read back, whatever the description
   * happens to say.
   */
  const read = (props: {
    config: ILlmSchema.IConfig;
    description: string | undefined;
  }): string | undefined =>
    props.config.strict === true ? props.description : undefined;

  /**
   * Drop the keys whose tag lookup found nothing.
   *
   * Every value returned from here is spread over a real schema, so a key
   * present with an `undefined` value does not mean "no constraint" — it is an
   * instruction to delete the schema's own constraint. Only a tag that was
   * actually found may reach that spread. `description` is exempt and stays on
   * the result even when `undefined`, because rewriting it to drop the consumed
   * tag lines is the point rather than an accident of a failed lookup.
   */
  const compact = <T extends object>(record: T): Partial<T> =>
    Object.fromEntries(
      Object.entries(record).filter(([, value]) => value !== undefined),
    ) as Partial<T>;

  const find = <Type extends "boolean" | "number" | "string">(props: {
    type: Type;
    name: string;
    lines: string[];
  }):
    | (Type extends "boolean" ? true : Type extends "number" ? number : string)
    | undefined => {
    if (props.type === "boolean")
      return props.lines.some((line) => line.startsWith(`@${props.name}`))
        ? (true as any)
        : (undefined as any);
    for (const line of props.lines) {
      if (line.startsWith(`@${props.name} `) === false) continue;
      const value: string = line.replace(`@${props.name} `, "").trim();
      if (props.type === "number")
        return (isNaN(Number(value)) ? undefined : Number(value)) satisfies
          | number
          | undefined as any;
      return value as any;
    }
    return undefined as any;
  };

  const describe = (lines: string[], tags: string[]): string | undefined => {
    const ret: string = trimArray(
      lines
        .map((str) => str.trim())
        .filter((str) =>
          tags.every((tag) => str.startsWith(`@${tag}`) === false),
        ),
    ).join("\n");
    return ret.length === 0 ? undefined : ret;
  };

  const trimArray = (array: string[]): string[] => {
    let first: number = 0;
    let last: number = array.length - 1;

    for (; first < array.length; ++first)
      if (array[first]!.trim().length !== 0) break;
    for (; last >= 0; --last) if (array[last]!.trim().length !== 0) break;
    return array.slice(first, last + 1);
  };
}

import { IJsonSchemaTransformError, IResult, OpenApi } from "@typia/interface";

import { LlmReference } from "../../utils/internal/LlmReference";
import { ObjectDictionary } from "../../utils/internal/ObjectDictionary";
import { OpenApiTypeChecker } from "../../validators/OpenApiTypeChecker";

/** @internal */
export namespace LlmParametersFinder {
  export const parameters = (props: {
    components: OpenApi.IComponents;
    schema: OpenApi.IJsonSchema.IObject | OpenApi.IJsonSchema.IReference;
    method: string;
    accessor?: string;
    refAccessor?: string;
  }): IResult<OpenApi.IJsonSchema.IObject, IJsonSchemaTransformError> => {
    let entity: OpenApi.IJsonSchema = props.schema;
    const visited: Set<string> = new Set();
    while (OpenApiTypeChecker.isReference(entity)) {
      const key: string | undefined = LlmReference.readOpenApi(entity.$ref);
      if (key === undefined)
        return reportError({
          ...props,
          schema: entity,
          message: `Invalid local schema reference ${JSON.stringify(entity.$ref)}.`,
        });
      if (visited.has(key))
        return reportError({
          ...props,
          schema: entity,
          message: `Circular schema reference ${JSON.stringify(key)} cannot be resolved.`,
        });
      visited.add(key);
      const found: OpenApi.IJsonSchema | undefined = ObjectDictionary.get(
        props.components.schemas,
        key,
      );
      if (found === undefined)
        return reportError({
          ...props,
          schema: entity,
          message: `Unable to resolve schema reference ${JSON.stringify(key)}.`,
        });
      entity = found;
    }
    if (OpenApiTypeChecker.isObject(entity) === false)
      return reportError({
        ...props,
        message: "LLM only accepts object type as parameters.",
      });
    else if (!!entity.additionalProperties)
      return reportError({
        ...props,
        message: "LLM does not allow additional properties on parameters.",
      });
    return {
      success: true,
      value: entity,
    };
  };

  const reportError = (props: {
    method: string;
    message: string;
    schema: OpenApi.IJsonSchema;
    accessor?: string;
  }): IResult.IFailure<IJsonSchemaTransformError> => ({
    success: false,
    error: {
      method: props.method,
      message: `failed to compose LLM schema.`,
      reasons: [
        {
          schema: props.schema,
          message: props.message,
          accessor: props.accessor ?? "$input.schema",
        },
      ],
    },
  });
}

@typia/utils/src/converters/internal/Ope:
import { OpenApi } from "@typia/interface";

import { OpenApiExclusiveEmender } from "./OpenApiExclusiveEmender";

export namespace OpenApiConstraintShifter {
  export const shiftArray = <
    Schema extends Pick<
      OpenApi.IJsonSchema.IArray,
      "description" | "minItems" | "maxItems" | "uniqueItems"
    >,
  >(
    schema: Schema,
  ): Omit<Schema, "minItems" | "maxItems" | "uniqueItems"> => {
    const tags: string[] = [];
    if (schema.minItems !== undefined) {
      tags.push(`@minItems ${schema.minItems}`);
      delete schema.minItems;
    }
    if (schema.maxItems !== undefined) {
      tags.push(`@maxItems ${schema.maxItems}`);
      delete schema.maxItems;
    }
    if (schema.uniqueItems !== undefined) {
      if (schema.uniqueItems === true) tags.push(`@uniqueItems`);
      delete schema.uniqueItems;
    }
    schema.description = writeTagWithDescription({
      description: schema.description,
      tags,
    });
    return schema;
  };

  export const shiftNumeric = <
    Schema extends Pick<
      OpenApi.IJsonSchema.INumber | OpenApi.IJsonSchema.IInteger,
      | "description"
      | "minimum"
      | "maximum"
      | "exclusiveMinimum"
      | "exclusiveMaximum"
      | "multipleOf"
      | "default"
    >,
  >(
    schema: Schema,
  ): Omit<
    Schema,
    | "minimum"
    | "maximum"
    | "exclusiveMinimum"
    | "exclusiveMaximum"
    | "multipleOf"
    | "default"
  > => {
    Object.assign(schema, OpenApiExclusiveEmender.emend(schema));

    const tags: string[] = [];
    if (schema.minimum !== undefined) {
      tags.push(`@minimum ${schema.minimum}`);
      delete schema.minimum;
    }
    if (schema.maximum !== undefined) {
      tags.push(`@maximum ${schema.maximum}`);
      delete schema.maximum;
    }
    if (schema.exclusiveMinimum !== undefined) {
      tags.push(`@exclusiveMinimum ${schema.exclusiveMinimum}`);
      delete schema.exclusiveMinimum;
    }
    if (schema.exclusiveMaximum !== undefined) {
      tags.push(`@exclusiveMaximum ${schema.exclusiveMaximum}`);
      delete schema.exclusiveMaximum;
    }
    if (schema.multipleOf !== undefined) {
      tags.push(`@multipleOf ${schema.multipleOf}`);
      delete schema.multipleOf;
    }
    if (schema.default !== undefined) {
      tags.push(`@default ${schema.default}`);
      delete schema.default;
    }
    schema.description = writeTagWithDescription({
      description: schema.description,
      tags,
    });
    return schema;
  };

  export const shiftString = <
    Schema extends Pick<
      OpenApi.IJsonSchema.IString,
      | "description"
      | "minLength"
      | "maxLength"
      | "format"
      | "pattern"
      | "contentMediaType"
      | "default"
    >,
  >(
    schema: Schema,
  ): Omit<
    Schema,
    | "minLength"
    | "maxLength"
    | "format"
    | "pattern"
    | "contentMediaType"
    | "default"
  > => {
    const tags: string[] = [];
    if (schema.minLength !== undefined) {
      tags.push(`@minLength ${schema.minLength}`);
      delete schema.minLength;
    }
    if (schema.maxLength !== undefined) {
      tags.push(`@maxLength ${schema.maxLength}`);
      delete schema.maxLength;
    }
    if (schema.format !== undefined) {
      tags.push(`@format ${schema.format}`);
      delete schema.format;
    }
    if (schema.pattern !== undefined) {
      tags.push(`@pattern ${schema.pattern}`);
      delete schema.pattern;
    }
    if (schema.contentMediaType !== undefined) {
      tags.push(`@contentMediaType ${schema.contentMediaType}`);
      delete schema.contentMediaType;
    }
    if (schema.default !== undefined) {
      tags.push(`@default ${schema.default}`);
      delete schema.default;
    }
    schema.description = writeTagWithDescription({
      description: schema.description,
      tags,
    });
    return schema;
  };
}

const writeTagWithDescription = (props: {
  description: string | undefined;
  tags: string[];
}): string | undefined => {
  if (props.tags.length === 0) return props.description;
  return [
    ...(props.description?.length ? [props.description, "\n"] : []),
    ...props.tags,
  ].join("\n");
};

import { OpenApi } from "@typia/interface";

export namespace OpenApiDiscriminatorConverter {
  export const clone = (
    input: OpenApi.IJsonSchema.IOneOf.IDiscriminator,
  ): OpenApi.IJsonSchema.IOneOf.IDiscriminator => ({
    propertyName: input.propertyName,
    ...(input.mapping !== undefined ? { mapping: { ...input.mapping } } : {}),
  });
}

import { OpenApi } from "@typia/interface";

export namespace OpenApiExclusiveEmender {
  export const emend = <
    Schema extends Pick<
      OpenApi.IJsonSchema.INumber,
      "exclusiveMinimum" | "exclusiveMaximum" | "minimum" | "maximum"
    >,
  >(
    schema: Schema,
  ): Schema => {
    const minimum =
      typeof schema.minimum === "number" &&
      typeof schema.exclusiveMinimum === "number"
        ? {
            minimum:
              schema.minimum > schema.exclusiveMinimum
                ? schema.minimum
                : undefined,
            exclusiveMinimum:
              schema.minimum > schema.exclusiveMinimum
                ? undefined
                : schema.exclusiveMinimum,
          }
        : {};
    const maximum =
      typeof schema.maximum === "number" &&
      typeof schema.exclusiveMaximum === "number"
        ? {
            maximum:
              schema.maximum < schema.exclusiveMaximum
                ? schema.maximum
                : undefined,
            exclusiveMaximum:
              schema.maximum < schema.exclusiveMaximum
                ? undefined
                : schema.exclusiveMaximum,
          }
        : {};
    return {
      ...schema,
      ...minimum,
      ...maximum,
    };
  };
}

import { OpenApi, OpenApiV3_1 } from "@typia/interface";

import { ObjectDictionary } from "../../utils/internal/ObjectDictionary";
import { OpenApiTypeChecker } from "../../validators/OpenApiTypeChecker";
import { OpenApiDiscriminatorConverter } from "./OpenApiDiscriminatorConverter";

export namespace OpenApiV3_1Downgrader {
  export interface IComponentsCollection {
    original: OpenApi.IComponents;
    downgraded: OpenApiV3_1.IComponents;
  }

  export const downgrade = (
    input: OpenApi.IDocument,
  ): OpenApiV3_1.IDocument => {
    const collection: IComponentsCollection = downgradeComponents(
      input.components,
    );
    return {
      openapi: "3.1.0",
      servers: input.servers,
      info: input.info,
      components: collection.downgraded,
      paths: input.paths
        ? Object.fromEntries(
            Object.entries(input.paths)
              .filter(([_, v]) => v !== undefined)
              .map(
                ([key, value]) =>
                  [key, downgradePathItem(collection)(value)] as const,
              ),
          )
        : undefined,
