              },
            });
          for (const type of schema.type)
            if (type === "boolean" || type === "number" || type === "string")
              visit({
                ...schema,
                ...{
                  enum:
                    schema.enum?.length && schema.enum.filter((e) => e !== null)
                      ? schema.enum.filter((x) => typeof x === type)
                      : undefined,
                },
                type: type as any,
              });
            else if (type === "integer")
              visit({
                ...schema,
                ...{
                  enum:
                    schema.enum?.length && schema.enum.filter((e) => e !== null)
                      ? schema.enum.filter(
                          (x) =>
                            x !== null &&
                            typeof x === "number" &&
                            Number.isInteger(x),
                        )
                      : undefined,
                },
                type: type as any,
              });
            else visit({ ...schema, type: type as any });
        }
        // UNION TYPE CASE
        else if (OpenApiV3_1TypeChecker.isOneOf(schema)) {
          const tracked: boolean =
            schema === input && discriminator !== undefined;
          if (tracked && nullable.value) preserveDiscriminator = false;
          for (const branch of schema.oneOf) {
            const previous: number = union.length;
            const previousNullable: boolean = nullable.value;
            visit(branch);
            if (
              tracked &&
              (union.length !== previous + 1 ||
                nullable.value !== previousNullable)
            )
              preserveDiscriminator = false;
          }
        } else if (OpenApiV3_1TypeChecker.isAnyOf(schema))
          schema.anyOf.forEach(visit);
        else if (OpenApiV3_1TypeChecker.isAllOf(schema))
          if (schema.allOf.length === 1) visit(schema.allOf[0]!);
          else union.push(convertAllOfSchema(components)(schema));
        // ATOMIC TYPE CASE (CONSIDER ENUM VALUES)
        else if (OpenApiV3_1TypeChecker.isBoolean(schema))
          if (
            schema.enum?.length &&
            schema.enum.filter((e) => e !== null).length
          )
            for (const value of schema.enum.filter((e) => e !== null))
              union.push({
                const: value,
                ...({
                  ...schema,
                  type: undefined as any,
                  enum: undefined,
                  default: undefined,
                } satisfies OpenApiV3_1.IJsonSchema.IBoolean as any),
              } satisfies OpenApi.IJsonSchema.IConstant);
          else
            union.push({
              ...schema,
              default: schema.default ?? undefined,
              ...{
                enum: undefined,
              },
            });
        else if (
          OpenApiV3_1TypeChecker.isInteger(schema) ||
          OpenApiV3_1TypeChecker.isNumber(schema)
        )
          if (schema.enum?.length && schema.enum.filter((e) => e !== null))
            for (const value of schema.enum.filter((e) => e !== null))
              union.push({
                const: value,
                ...({
                  ...schema,
                  type: undefined as any,
                  enum: undefined,
                  default: undefined,
                  minimum: undefined,
                  maximum: undefined,
                  exclusiveMinimum: undefined,
                  exclusiveMaximum: undefined,
                  multipleOf: undefined,
                } satisfies OpenApiV3_1.IJsonSchema.IInteger as any),
              } satisfies OpenApi.IJsonSchema.IConstant);
          else
            union.push(
              OpenApiExclusiveEmender.emend({
                ...schema,
                default: schema.default ?? undefined,
                ...{
                  enum: undefined,
                },
                exclusiveMinimum:
                  typeof schema.exclusiveMinimum === "boolean"
                    ? schema.exclusiveMinimum === true
                      ? schema.minimum
                      : undefined
                    : schema.exclusiveMinimum,
                exclusiveMaximum:
                  typeof schema.exclusiveMaximum === "boolean"
                    ? schema.exclusiveMaximum === true
                      ? schema.maximum
                      : undefined
                    : schema.exclusiveMaximum,
                minimum:
                  schema.exclusiveMinimum === true ? undefined : schema.minimum,
                maximum:
                  schema.exclusiveMaximum === true ? undefined : schema.maximum,
              }),
            );
        else if (OpenApiV3_1TypeChecker.isString(schema))
          if (
            schema.enum?.length &&
            schema.enum.filter((e) => e !== null).length
          )
            for (const value of schema.enum.filter((e) => e !== null))
              union.push({
                const: value,
                ...({
                  ...schema,
                  type: undefined as any,
                  enum: undefined,
                  default: undefined,
                } satisfies OpenApiV3_1.IJsonSchema.IString as any),
              } satisfies OpenApi.IJsonSchema.IConstant);
          else
            union.push({
              ...schema,
              default: schema.default ?? undefined,
              ...{
                enum: undefined,
              },
            });
        // ARRAY TYPE CASE (CONSIDER TUPLE)
        else if (OpenApiV3_1TypeChecker.isArray(schema)) {
          if (Array.isArray(schema.items))
            union.push({
              ...schema,
              ...{
                items: undefined!,
                prefixItems: schema.items.map(convertSchema(components)),
                additionalItems:
                  typeof schema.additionalItems === "object" &&
                  schema.additionalItems !== null
                    ? convertSchema(components)(schema.additionalItems)
                    : schema.additionalItems,
              },
            } satisfies OpenApi.IJsonSchema.ITuple);
          else if (Array.isArray(schema.prefixItems))
            union.push({
              ...schema,
              ...{
                items: undefined!,
                prefixItems: schema.prefixItems.map(convertSchema(components)),
                minItems: schema.minItems ?? 0,
                additionalItems:
                  typeof schema.items === "object" && schema.items !== null
                    ? convertSchema(components)(schema.items)
                    : (schema.items ?? true),
              },
            });
          else if (schema.items === undefined)
            union.push({
              ...schema,
              ...{
                items: undefined!,
                prefixItems: [],
              },
            });
          else
            union.push({
              ...schema,
              ...{
                items: convertSchema(components)(schema.items),
                prefixItems: undefined,
                additionalItems: undefined,
              },
            });
        }
        // OBJECT TYPE CASE
        else if (OpenApiV3_1TypeChecker.isObject(schema)) {
          union.push({
            ...schema,
            properties:
              schema.properties === undefined
                ? undefined
                : Object.fromEntries(
                    Object.entries(schema.properties)
                      .filter(([_, v]) => v !== undefined)
                      .map(
                        ([key, value]) =>
                          [key, convertSchema(components)(value)] as const,
                      ),
                  ),
            additionalProperties:
              schema.additionalProperties === undefined
                ? undefined
                : typeof schema.additionalProperties === "object" &&
                    schema.additionalProperties !== null
                  ? convertSchema(components)(schema.additionalProperties)
                  : schema.additionalProperties,
            required: schema.required,
          });
        } else if (OpenApiV3_1TypeChecker.isReference(schema))
          union.push({
            ...schema,
            ...{
              $ref: `#/components/schemas/${schema.$ref.split("/").pop()}`,
            },
          });
        else if (OpenApiV3_1TypeChecker.isRecursiveReference(schema))
          union.push({
            ...schema,
            ...{
              $ref: `#/components/schemas/${schema.$recursiveRef.split("/").pop()}`,
              $recursiveRef: undefined,
            },
          });
        // THE OTHERS
        else union.push(schema);
      };

      visit(input);
      if (
        nullable.value === true &&
        !union.some((e) => (e as OpenApi.IJsonSchema.INull).type === "null")
      )
        union.push({
          type: "null",
          default: nullable.default,
        });
      if (
        union.length === 2 &&
        union.filter((x) => OpenApiTypeChecker.isNull(x)).length === 1
      ) {
        const type: OpenApi.IJsonSchema = union.filter(
          (x) => OpenApiTypeChecker.isNull(x) === false,
        )[0]!;
        for (const key of [
          "title",
          "description",
          "deprecated",
          "readOnly",
          "writeOnly",
          "example",
          "examples",
        ] as const)
          if (type[key] !== undefined) delete type[key];
      }
      return {
        ...(union.length === 0
          ? {
              type: undefined,
            }
          : union.length === 1
            ? {
                ...union[0],
              }
            : {
                oneOf: union.map((u) => ({
                  ...u,
                  nullable: undefined,
                  $defs: undefined,
                })),
                ...(preserveDiscriminator && discriminator !== undefined
                  ? { discriminator }
                  : {}),
              }),
        ...attribute,
        ...{
          nullable: undefined,
          $defs: undefined,
        },
      };
    };

  const convertAllOfSchema =
    (components: OpenApiV3_1.IComponents) =>
    (input: OpenApiV3_1.IJsonSchema.IAllOf): OpenApi.IJsonSchema => {
      const objects: Array<OpenApiV3_1.IJsonSchema.IObject | null> =
        input.allOf.map((schema) => retrieveObject(components)(schema));
      if (objects.some((obj) => obj === null))
        return {
          type: undefined,
          ...{
            allOf: undefined,
          },
        };
      return {
        ...input,
        type: "object" as const,
        properties: Object.fromEntries(
          objects
            .map((o) => Object.entries(o?.properties ?? {}))
            .flat()
            .map(
              ([key, value]) =>
                [key, convertSchema(components)(value)] as const,
            ),
        ),
        additionalProperties: objects.every(
          (o) => o?.additionalProperties === false,
        )
          ? false
          : undefined,
        ...{
          allOf: undefined,
          required: [...new Set(objects.map((o) => o?.required ?? []).flat())],
        },
      };
    };

  const retrieveObject =
    (components: OpenApiV3_1.IComponents) =>
    (
      input: OpenApiV3_1.IJsonSchema,
      visited: Set<OpenApiV3_1.IJsonSchema> = new Set(),
    ): OpenApiV3_1.IJsonSchema.IObject | null => {
      if (OpenApiV3_1TypeChecker.isObject(input))
        return input.properties !== undefined && !input.additionalProperties
          ? input
          : null;
      else if (visited.has(input)) return null;
      else visited.add(input);

      if (OpenApiV3_1TypeChecker.isReference(input))
        return retrieveObject(components)(
          ObjectDictionary.get(
            components.schemas,
            input.$ref.split("/").pop() ?? "",
          ) ?? {},
          visited,
        );
      else if (OpenApiV3_1TypeChecker.isRecursiveReference(input))
        return retrieveObject(components)(
          ObjectDictionary.get(
            components.schemas,
            input.$recursiveRef.split("/").pop() ?? "",
          ) ?? {},
          visited,
        );
      return null;
    };
}

import { OpenApi, OpenApiV3_2 } from "@typia/interface";

import { OpenApiV3_1TypeChecker } from "../../validators/OpenApiV3_1TypeChecker";
import { OpenApiV3_1Upgrader } from "./OpenApiV3_1Upgrader";

/**
 * OpenAPI v3.2 to emended OpenApi converter.
 *
 * Reuses JSON Schema conversion logic from OpenApiV3_1Upgrader since the schema
 * format is identical between v3.1 and v3.2.
 */
export namespace OpenApiV3_2Upgrader {
  export const convert = (input: OpenApiV3_2.IDocument): OpenApi.IDocument => {
    if ((input as OpenApi.IDocument)["x-typia-emended-v12"] === true)
      return input as OpenApi.IDocument;
    return {
      ...input,
      openapi: "3.2.0",
      components: convertComponents(input.components ?? {}),
      tags: input.tags?.map(convertTag),
      paths: input.paths
        ? Object.fromEntries(
            Object.entries(input.paths)
              .filter(([_, v]) => v !== undefined)
              .map(
                ([key, value]) => [key, convertPathItem(input)(value)] as const,
              ),
          )
        : undefined,
      webhooks: input.webhooks
        ? Object.fromEntries(
            Object.entries(input.webhooks)
              .filter(([_, v]) => v !== undefined)
              .map(
                ([key, value]) =>
                  [key, convertWebhooks(input)(value)!] as const,
              )
              .filter(([_, value]) => value !== undefined),
          )
        : undefined,
      "x-typia-emended-v12": true,
    };
  };

  /* -----------------------------------------------------------
    TAGS
  ----------------------------------------------------------- */
  const convertTag = (
    tag: OpenApiV3_2.IDocument.ITag,
  ): OpenApi.IDocument.ITag => ({
    name: tag.name,
    summary: tag.summary,
    description: tag.description,
    parent: tag.parent,
    kind: tag.kind,
  });

  /* -----------------------------------------------------------
    OPERATORS
  ----------------------------------------------------------- */
  const convertWebhooks =
    (doc: OpenApiV3_2.IDocument) =>
    (
      webhook:
        | OpenApiV3_2.IPath
        | OpenApiV3_2.IJsonSchema.IReference<`#/components/pathItems/${string}`>,
    ): OpenApi.IPath | undefined => {
      if (!OpenApiV3_1TypeChecker.isReference(webhook))
        return convertPathItem(doc)(webhook);
      const found: OpenApiV3_2.IPath | undefined =
        doc.components?.pathItems?.[webhook.$ref.split("/").pop() ?? ""];
      return found ? convertPathItem(doc)(found) : undefined;
    };

  const convertPathItem =
    (doc: OpenApiV3_2.IDocument) =>
    (pathItem: OpenApiV3_2.IPath): OpenApi.IPath => {
      const { parameters: _parameters, ...rest } = pathItem as any;
      return {
        ...rest,
        ...(pathItem.get
          ? { get: convertOperation(doc)(pathItem)(pathItem.get) }
          : undefined),
        ...(pathItem.put
          ? { put: convertOperation(doc)(pathItem)(pathItem.put) }
          : undefined),
        ...(pathItem.post
          ? { post: convertOperation(doc)(pathItem)(pathItem.post) }
          : undefined),
        ...(pathItem.delete
          ? { delete: convertOperation(doc)(pathItem)(pathItem.delete) }
          : undefined),
        ...(pathItem.options
          ? { options: convertOperation(doc)(pathItem)(pathItem.options) }
          : undefined),
        ...(pathItem.head
          ? { head: convertOperation(doc)(pathItem)(pathItem.head) }
          : undefined),
        ...(pathItem.patch
          ? { patch: convertOperation(doc)(pathItem)(pathItem.patch) }
          : undefined),
        ...(pathItem.trace
          ? { trace: convertOperation(doc)(pathItem)(pathItem.trace) }
          : undefined),
        ...(pathItem.query
          ? { query: convertOperation(doc)(pathItem)(pathItem.query) }
          : undefined),
        ...(pathItem.additionalOperations
          ? {
              additionalOperations: Object.fromEntries(
                Object.entries(pathItem.additionalOperations)
                  .filter(([_, v]) => v !== undefined)
                  .map(
                    ([key, value]) =>
                      [key, convertOperation(doc)(pathItem)(value)] as const,
                  ),
              ),
            }
          : undefined),
      };
    };

  const convertOperation =
    (doc: OpenApiV3_2.IDocument) =>
    (pathItem: OpenApiV3_2.IPath) =>
    (input: OpenApiV3_2.IOperation): OpenApi.IOperation => {
      const components: OpenApiV3_2.IComponents = doc.components ?? {};
      const pathParameters: OpenApiV3_2.IOperation.IParameter[] = (
        pathItem.parameters ?? []
      )
        .map(resolveParameter(components))
        .filter((p): p is OpenApiV3_2.IOperation.IParameter => p !== undefined);
      const operationParameters: OpenApiV3_2.IOperation.IParameter[] = (
        input.parameters ?? []
      )
        .map(resolveParameter(components))
        .filter((p): p is OpenApiV3_2.IOperation.IParameter => p !== undefined);
      return {
        ...input,
        parameters:
          pathItem.parameters !== undefined || input.parameters !== undefined
            ? mergeParameters(pathParameters, operationParameters).map(
                convertParameter(components),
              )
            : undefined,
        requestBody: input.requestBody
          ? convertRequestBody(doc)(input.requestBody)
          : undefined,
        responses: input.responses
          ? Object.fromEntries(
              Object.entries(input.responses)
                .filter(([_, v]) => v !== undefined)
                .map(
                  ([key, value]) =>
                    [key, convertResponse(doc)(value)!] as const,
                )
                .filter(([_, value]) => value !== undefined),
            )
          : undefined,
      };
    };

  const resolveParameter =
    (components: OpenApiV3_2.IComponents) =>
    (
      input:
        | OpenApiV3_2.IOperation.IParameter
        | OpenApiV3_2.IJsonSchema.IReference<`#/components/headers/${string}`>
        | OpenApiV3_2.IJsonSchema.IReference<`#/components/parameters/${string}`>,
    ): OpenApiV3_2.IOperation.IParameter | undefined => {
      if (!("$ref" in input)) return input;
      const key: string = input.$ref.split("/").pop() ?? "";
      if (input.$ref.startsWith("#/components/headers/")) {
        const header:
          | Omit<OpenApiV3_2.IOperation.IParameter, "in">
          | undefined = components.headers?.[key];
        if (header === undefined) return undefined;
        const { name, ...rest } = header;
        return { ...rest, name: name ?? key, in: "header" };
      }
      return components.parameters?.[key];
    };

  const mergeParameters = (
    pathParameters: OpenApiV3_2.IOperation.IParameter[],
    operationParameters: OpenApiV3_2.IOperation.IParameter[],
  ): OpenApiV3_2.IOperation.IParameter[] => {
    const map: Map<string, OpenApiV3_2.IOperation.IParameter> = new Map();
    const duplicates = (
      parameters: OpenApiV3_2.IOperation.IParameter[],
    ): OpenApiV3_2.IOperation.IParameter[] => {
      const seen: Set<string> = new Set();
      return parameters.filter((parameter) => {
        const key: string = `${parameter.in}:${parameter.name}`;
        if (seen.has(key)) return true;
        seen.add(key);
        return false;
      });
    };
    const emplace = (parameter: OpenApiV3_2.IOperation.IParameter): void => {
      map.set(`${parameter.in}:${parameter.name}`, parameter);
    };
    pathParameters.forEach(emplace);
    operationParameters.forEach(emplace);
    return [
      ...map.values(),
      ...duplicates(pathParameters),
      ...duplicates(operationParameters),
    ];
  };

  const convertParameter =
    (components: OpenApiV3_2.IComponents) =>
    (
      input: OpenApiV3_2.IOperation.IParameter,
    ): OpenApi.IOperation.IParameter => {
      const { required: inputRequired, ...rest } = input;
      const required: boolean | undefined =
        input.in === "path" ? true : inputRequired;
      const content: OpenApi.IOperation.IContent | undefined = input.content
        ? convertContent(components)(input.content)
        : undefined;
      return {
        ...rest,
        ...(required !== undefined ? { required } : {}),
        schema:
          input.schema !== undefined
            ? convertSchema(components)(input.schema)
            : (Object.values(content ?? {})[0]?.schema ?? {}),
        content,
        examples: input.examples
          ? Object.fromEntries(
              Object.entries(input.examples)
                .map(([key, value]) => [
                  key,
                  OpenApiV3_1TypeChecker.isReference(value)
                    ? components.examples?.[value.$ref.split("/").pop() ?? ""]
                    : value,
                ])
                .filter(([_, v]) => v !== undefined),
            )
          : undefined,
      };
    };

  const convertRequestBody =
    (doc: OpenApiV3_2.IDocument) =>
    (
      input:
        | OpenApiV3_2.IOperation.IRequestBody
        | OpenApiV3_2.IJsonSchema.IReference<`#/components/requestBodies/${string}`>,
    ): OpenApi.IOperation.IRequestBody | undefined => {
      if ("$ref" in input) {
        const found: OpenApiV3_2.IOperation.IRequestBody | undefined =
          doc.components?.requestBodies?.[input.$ref.split("/").pop() ?? ""];
        if (found === undefined) return undefined;
        input = found;
      }
      return {
        ...input,
        content: input.content
          ? convertContent(doc.components ?? {})(input.content)
          : undefined,
      };
    };

  const convertResponse =
    (doc: OpenApiV3_2.IDocument) =>
    (
      input:
        | OpenApiV3_2.IOperation.IResponse
        | OpenApiV3_2.IJsonSchema.IReference<`#/components/responses/${string}`>,
    ): OpenApi.IOperation.IResponse | undefined => {
      if ("$ref" in input) {
        const found: OpenApiV3_2.IOperation.IResponse | undefined =
          doc.components?.responses?.[input.$ref.split("/").pop() ?? ""];
        if (found === undefined) return undefined;
        input = found;
      }
      return {
        ...input,
        content: input.content
          ? convertContent(doc.components ?? {})(input.content)
          : undefined,
        headers: input.headers
          ? Object.fromEntries(
              Object.entries(input.headers)
                .filter(([_, v]) => v !== undefined)
                .map(([key, value]) => [
                  key,
                  convertHeader(doc.components ?? {})(key, value),
                ])
                .filter(([_, v]) => v !== undefined),
            )
          : undefined,
      };
    };

  const convertHeader =
    (components: OpenApiV3_2.IComponents) =>
    (
      key: string,
      input:
        | Omit<OpenApiV3_2.IOperation.IParameter, "in">
        | OpenApiV3_2.IJsonSchema.IReference<`#/components/headers/${string}`>,
    ): OpenApi.IOperation.IParameter | undefined => {
      if ("$ref" in input) {
        const found: Omit<OpenApiV3_2.IOperation.IParameter, "in"> | undefined =
          input.$ref.startsWith("#/components/headers/")
            ? components.headers?.[input.$ref.split("/").pop() ?? ""]
            : undefined;
        if (found === undefined) return undefined;
        input = found;
      }
      const { name: _name, ...rest } = input;
      return convertParameter(components)({
        ...rest,
        name: key,
        in: "header",
      });
    };

  const convertContent =
    (components: OpenApiV3_2.IComponents) =>
    (
      record: Record<string, OpenApiV3_2.IOperation.IMediaType>,
    ): Record<string, OpenApi.IOperation.IMediaType> =>
      Object.fromEntries(
        Object.entries(record)
          .filter(([_, v]) => v !== undefined)
          .map(
            ([key, value]) =>
              [
                key,
                {
                  ...value,
                  schema: value.schema
                    ? convertSchema(components)(value.schema)
                    : undefined,
                  itemSchema: value.itemSchema
                    ? convertSchema(components)(value.itemSchema)
                    : undefined,
                  examples: value.examples
                    ? Object.fromEntries(
                        Object.entries(value.examples)
                          .map(([key, value]) => [
                            key,
                            OpenApiV3_1TypeChecker.isReference(value)
                              ? components.examples?.[
                                  value.$ref.split("/").pop() ?? ""
                                ]
                              : value,
                          ])
                          .filter(([_, v]) => v !== undefined),
                      )
                    : undefined,
                },
              ] as const,
          ),
      );

  /* -----------------------------------------------------------
    DEFINITIONS
  ----------------------------------------------------------- */
  export const convertComponents = (
    input: OpenApiV3_2.IComponents,
  ): OpenApi.IComponents => ({
    schemas: Object.fromEntries(
      Object.entries(input.schemas ?? {})
        .filter(([_, v]) => v !== undefined)
        .map(([key, value]) => [key, convertSchema(input)(value)] as const),
    ),
    securitySchemes: input.securitySchemes
      ? Object.fromEntries(
          Object.entries(input.securitySchemes)
            .filter(([_, v]) => v !== undefined)
            .map(
              ([key, value]) => [key, convertSecurityScheme(value)] as const,
            ),
        )
      : undefined,
  });

  const convertSecurityScheme = (
    input: OpenApiV3_2.ISecurityScheme,
  ): OpenApi.ISecurityScheme => {
    if (input.type === "oauth2") {
      return {
        ...input,
        flows: {
          ...input.flows,
          deviceAuthorization: input.flows.deviceAuthorization,
        },
        oauth2MetadataUrl: input.oauth2MetadataUrl,
      };
    }
    return input;
  };

  /**
   * Reuse schema conversion from OpenApiV3_1Upgrader. OpenAPI v3.2 uses the
   * same JSON Schema (2020-12) as v3.1.
   */
  export const convertSchema =
    (components: OpenApiV3_2.IComponents) =>
    (input: OpenApiV3_2.IJsonSchema): OpenApi.IJsonSchema =>
      OpenApiV3_1Upgrader.convertSchema(components as any)(input as any);
}

import { OpenApi, OpenApiV3 } from "@typia/interface";

import { ObjectDictionary } from "../../utils/internal/ObjectDictionary";
import { OpenApiTypeChecker } from "../../validators/OpenApiTypeChecker";
import { OpenApiDiscriminatorConverter } from "./OpenApiDiscriminatorConverter";

export namespace OpenApiV3Downgrader {
  export interface IComponentsCollection {
    original: OpenApi.IComponents;
    downgraded: OpenApiV3.IComponents;
  }

  export const downgrade = (input: OpenApi.IDocument): OpenApiV3.IDocument => {
    const collection: IComponentsCollection = downgradeComponents(
      input.components,
    );
    return {
      openapi: "3.0.0",
      servers: input.servers,
      info: input.info,
      components: collection.downgraded,
      paths: input.paths
        ? Object.fromEntries(
            Object.entries(input.paths)
              .filter(([_, v]) => v !== undefined)
              .map(
                ([key, value]) =>
                  [key, downgradePathItem(collection)(value)] as const,
              ),
          )
        : undefined,
      security: input.security,
      tags: input.tags,
    };
  };

  /* -----------------------------------------------------------
    OPERATORS
  ----------------------------------------------------------- */
  const downgradePathItem =
    (collection: IComponentsCollection) =>
    (pathItem: OpenApi.IPath): OpenApiV3.IPath => {
      // Collect non-standard operations for x-additionalOperations
      const xAdditionalOperations: Record<string, OpenApiV3.IOperation> = {};

      // query method goes to x-additionalOperations
      if (pathItem.query) {
        xAdditionalOperations["query"] = downgradeOperation(collection)(
          pathItem.query,
        );
      }

      // additionalOperations also go to x-additionalOperations
      if (pathItem.additionalOperations) {
        for (const [key, value] of Object.entries(
          pathItem.additionalOperations,
        )) {
          if (value !== undefined) {
            xAdditionalOperations[key] = downgradeOperation(collection)(value);
          }
        }
      }

      return {
        ...(pathItem as any),
        ...(pathItem.get
          ? { get: downgradeOperation(collection)(pathItem.get) }
          : undefined),
        ...(pathItem.put
          ? { put: downgradeOperation(collection)(pathItem.put) }
          : undefined),
        ...(pathItem.post
          ? { post: downgradeOperation(collection)(pathItem.post) }
          : undefined),
        ...(pathItem.delete
          ? { delete: downgradeOperation(collection)(pathItem.delete) }
          : undefined),
        ...(pathItem.options
          ? { options: downgradeOperation(collection)(pathItem.options) }
          : undefined),
        ...(pathItem.head
          ? { head: downgradeOperation(collection)(pathItem.head) }
          : undefined),
        ...(pathItem.patch
          ? { patch: downgradeOperation(collection)(pathItem.patch) }
          : undefined),
        ...(pathItem.trace
          ? { trace: downgradeOperation(collection)(pathItem.trace) }
          : undefined),
        ...(Object.keys(xAdditionalOperations).length > 0
          ? { "x-additionalOperations": xAdditionalOperations }
          : undefined),
        // Remove v3.2-only properties from spread
        query: undefined,
        additionalOperations: undefined,
      };
    };

  const downgradeOperation =
    (collection: IComponentsCollection) =>
    (input: OpenApi.IOperation): OpenApiV3.IOperation => ({
      ...input,
      parameters: input.parameters
        ? input.parameters.map(downgradeParameter(collection))
        : undefined,
      requestBody: input.requestBody
        ? downgradeRequestBody(collection)(input.requestBody)
        : undefined,
      responses: input.responses
        ? Object.fromEntries(
            Object.entries(input.responses)
              .filter(([_, v]) => v !== undefined)
              .map(([key, value]) => [
                key,
                downgradeResponse(collection)(value),
              ]),
          )
        : undefined,
    });

  const downgradeParameter =
    (collection: IComponentsCollection) =>
    (input: OpenApi.IOperation.IParameter): OpenApiV3.IOperation.IParameter => {
      const { style, content: _content, ...rest } = input;
      return {
        ...rest,
        in: input.in === "querystring" ? "query" : input.in,
        style: style === "cookie" ? "form" : style,
        schema: downgradeSchema(collection)(input.schema),
      };
    };

  const downgradeRequestBody =
    (collection: IComponentsCollection) =>
    (
      input: OpenApi.IOperation.IRequestBody,
    ): OpenApiV3.IOperation.IRequestBody => ({
      ...input,
      content: input.content
        ? downgradeContent(collection)(input.content)
        : undefined,
    });

  const downgradeResponse =
    (collection: IComponentsCollection) =>
    (input: OpenApi.IOperation.IResponse): OpenApiV3.IOperation.IResponse => ({
      ...input,
      content: input.content
        ? downgradeContent(collection)(input.content)
        : undefined,
      headers: input.headers
        ? Object.fromEntries(
            Object.entries(input.headers)
              .filter(([_, v]) => v !== undefined)
              .map(([key, value]) => {
                const { name: _name, in: _in, style, ...rest } = value;
                return [
                  key,
                  {
                    ...rest,
                    style: style === "cookie" ? "form" : style,
                    schema: downgradeSchema(collection)(value.schema),
                  },
                ];
              }),
          )
        : undefined,
    });

  const downgradeContent =
    (collection: IComponentsCollection) =>
    (
      record: OpenApi.IOperation.IContent,
    ): Record<string, OpenApiV3.IOperation.IMediaType> =>
      Object.fromEntries(
        Object.entries(record)
          .filter(([_, v]) => v !== undefined)
          .map(
            ([key, value]) =>
              [
                key,
                {
                  ...value,
                  schema: value?.schema
                    ? downgradeSchema(collection)(value.schema)
                    : undefined,
                },
              ] as const,
          ),
      );

  /* -----------------------------------------------------------
    DEFINITIONS
  ----------------------------------------------------------- */
  export const downgradeComponents = (
    input: OpenApi.IComponents,
  ): IComponentsCollection => {
    const collection: IComponentsCollection = {
      original: input,
      downgraded: {
        securitySchemes: input.securitySchemes,
      },
    };
    if (input.schemas) {
      collection.downgraded.schemas = {};
      for (const [key, value] of Object.entries(input.schemas))
        if (value !== undefined)
          ObjectDictionary.set(
            collection.downgraded.schemas,
            key,
            downgradeSchema(collection)(value),
          );
    }
    return collection;
  };

  export const downgradeSchema =
    (collection: IComponentsCollection) =>
    (input: OpenApi.IJsonSchema): OpenApiV3.IJsonSchema => {
      const nullable: boolean = isNullable(new Set())(collection.original)(
        input,
      );
      const union: OpenApiV3.IJsonSchema[] = [];
      const discriminator:
        | OpenApiV3.IJsonSchema.IOneOf.IDiscriminator
        | undefined =
        OpenApiTypeChecker.isOneOf(input) && input.discriminator !== undefined
          ? OpenApiDiscriminatorConverter.clone(input.discriminator)
          : undefined;
      let preserveDiscriminator: boolean =
        discriminator !== undefined && nullable === false;
      const attribute: OpenApiV3.IJsonSchema.__IAttribute = {
        title: input.title,
        description: input.description,
        deprecated: input.deprecated,
        readOnly: input.readOnly,
        writeOnly: input.writeOnly,
        example: input.example,
        ...Object.fromEntries(
          Object.entries(input).filter(
            ([key, value]) => key.startsWith("x-") && value !== undefined,
          ),
        ),
      };
      const visit = (schema: OpenApi.IJsonSchema): void => {
        if (
          // A boolean carries its declared keywords (at minimum `default`,
          // plus every attribute OpenApiV3.IJsonSchema.IBoolean allows) through
          // the downgrade like the other primitives. Rebuilding it as a bare
          // `{ type: "boolean" }` dropped them; `omitSchemaExamples` keeps the
          // legal 3.0 keys and strips only `examples`, which 3.0 does not define.
          OpenApiTypeChecker.isBoolean(schema) ||
          OpenApiTypeChecker.isInteger(schema) ||
          OpenApiTypeChecker.isNumber(schema) ||
          OpenApiTypeChecker.isString(schema) ||
          OpenApiTypeChecker.isReference(schema)
        )
          union.push(omitSchemaExamples(schema));
        else if (OpenApiTypeChecker.isArray(schema)) {
          const next = omitSchemaExamples(schema);
          union.push({
            ...next,
            items: downgradeSchema(collection)(schema.items),
          });
        } else if (OpenApiTypeChecker.isTuple(schema)) {
          const next = omitSchemaExamples(schema);
          union.push({
            ...next,
            items: ((): OpenApiV3.IJsonSchema => {
              if (schema.additionalItems === true) return {};
              const elements = [
                ...schema.prefixItems,
                ...(typeof schema.additionalItems === "object"
                  ? [downgradeSchema(collection)(schema.additionalItems)]
                  : []),
              ];
              if (elements.length === 0) return {};
              return {
                oneOf: elements.map(downgradeSchema(collection) as any),
              };
            })(),
            minItems: schema.prefixItems.length,
            maxItems:
              !!schema.additionalItems === true
                ? undefined
                : schema.prefixItems.length,
            ...{
              prefixItems: undefined,
              additionalItems: undefined,
            },
          });
        } else if (OpenApiTypeChecker.isObject(schema)) {
          const next = omitSchemaExamples(schema);
          union.push({
            ...next,
            properties:
              schema.properties === undefined
                ? undefined
                : Object.fromEntries(
                    Object.entries(schema.properties)
                      .filter(([_, v]) => v !== undefined)
                      .map(([key, value]) => [
                        key,
                        downgradeSchema(collection)(value),
                      ]),
                  ),
            additionalProperties:
              schema.additionalProperties === undefined
                ? undefined
                : typeof schema.additionalProperties === "object"
                  ? downgradeSchema(collection)(schema.additionalProperties)
                  : schema.additionalProperties,
            required: schema.required,
          });
        } else if (OpenApiTypeChecker.isOneOf(schema)) {
          const tracked: boolean =
            schema === input && discriminator !== undefined;
          for (const branch of schema.oneOf) {
            const previous: number = union.length;
            visit(branch);
            if (tracked && union.length !== previous + 1)
              preserveDiscriminator = false;
          }
        }
      };
      const visitConstant = (schema: OpenApi.IJsonSchema): void => {
        const insert = (value: any): void => {
          const matched: OpenApiV3.IJsonSchema.INumber | undefined = union.find(
            (u) => (u as OpenApiV3.IJsonSchema.INumber).type === typeof value,
          ) as OpenApiV3.IJsonSchema.INumber | undefined;
          if (matched !== undefined) {
            matched.enum ??= [];
            matched.enum.push(value);
          } else union.push({ type: typeof value as "number", enum: [value] });
        };
        if (OpenApiTypeChecker.isConstant(schema)) insert(schema.const);
        else if (OpenApiTypeChecker.isOneOf(schema))
          for (const u of schema.oneOf)
            if (OpenApiTypeChecker.isConstant(u)) insert(u.const);
      };

      visit(input);
      visitConstant(input);
      if (nullable === true)
        for (const u of union)
          if (OpenApiTypeChecker.isReference(u as any))
            downgradeNullableReference(new Set())(collection)(u as any);
          else (u as OpenApiV3.IJsonSchema.IArray).nullable = true;
      if (nullable === true && union.length === 0)
        return { type: "null", ...attribute };
      return {
        ...(union.length === 0
          ? { type: undefined }
          : union.length === 1
            ? { ...union[0] }
            : {
                oneOf: union,
                ...(preserveDiscriminator && discriminator !== undefined
                  ? { discriminator }
                  : {}),
              }),
        ...attribute,
      };
    };

  const downgradeNullableReference =
    (visited: Set<string>) =>
    (collection: IComponentsCollection) =>
    (schema: OpenApiV3.IJsonSchema.IReference): void => {
      const key: string = schema.$ref.split("/").pop()!;
      if (key.endsWith(".Nullable")) return;

      const found: OpenApi.IJsonSchema | undefined = ObjectDictionary.get(
        collection.original.schemas,
        key,
      );
      if (found === undefined) return;
      else if (isNullable(visited)(collection.original)(found) === true) return;
      else if (
        ObjectDictionary.get(
          collection.downgraded.schemas,
          `${key}.Nullable`,
        ) === undefined
      ) {
        collection.downgraded.schemas ??= {};
        ObjectDictionary.set(
          collection.downgraded.schemas,
          `${key}.Nullable`,
          {},
        );
        ObjectDictionary.set(
          collection.downgraded.schemas,
          `${key}.Nullable`,
          downgradeSchema(collection)(
            OpenApiTypeChecker.isOneOf(found)
              ? {
                  ...found,
                  oneOf: [...found.oneOf, { type: "null" }],
                }
              : {
                  oneOf: [found, { type: "null" }],
                  title: found.title,
                  description: found.description,
                  example: found.example,
                  examples: found.examples,
                  ...Object.fromEntries(
                    Object.entries(found).filter(
                      ([key, value]) =>
                        key.startsWith("x-") && value !== undefined,
                    ),
                  ),
                },
          ),
        );
      }
      schema.$ref += ".Nullable";
    };

  const omitSchemaExamples = <Schema extends OpenApi.IJsonSchema>(
    schema: Schema,
  ): Omit<Schema, "examples"> => {
    const { examples: _examples, ...rest } = schema;
    return exclusiveBounds(rest);
  };

  /**
   * Rewrites an exclusive numeric bound into the form the 3.0 dialect defines.
   *
   * 3.0's Schema Object descends from JSON Schema draft-04, where
   * `exclusiveMinimum` and `exclusiveMaximum` are booleans qualifying `minimum`
   * and `maximum`; the numeric spelling belongs to 3.1. Carrying the number
   * through left a document that declares itself 3.0 with a 3.1 keyword, and a
   * 3.0 reader taking the value as the boolean its dialect declares finds no
   * `minimum` beside it and drops the bound entirely (#2300).
   *
   * {@link OpenApiV3Upgrader} already performs the inverse, so this makes the
   * pair a round trip.
   */
  const exclusiveBounds = <Schema extends object>(schema: Schema): Schema => {
    const target = schema as Record<string, unknown>;
    for (const [exclusive, inclusive] of [
      ["exclusiveMinimum", "minimum"],
      ["exclusiveMaximum", "maximum"],
    ] as const) {
      const value: unknown = target[exclusive];
      if (typeof value !== "number") continue;
      target[inclusive] = value;
      target[exclusive] = true;
    }
    return schema;
  };

  const isNullable =
    (visited: Set<string>) =>
    (components: OpenApi.IComponents) =>
    (schema: OpenApi.IJsonSchema): boolean => {
      if (OpenApiTypeChecker.isNull(schema)) return true;
      else if (OpenApiTypeChecker.isReference(schema)) {
        if (visited.has(schema.$ref)) return false;
        visited.add(schema.$ref);
        const key: string = schema.$ref.split("/").pop()!;
        const next: OpenApi.IJsonSchema | undefined = ObjectDictionary.get(
          components.schemas,
          key,
        );
        return next ? isNullable(visited)(components)(next) : false;
      }
      return (
        OpenApiTypeChecker.isOneOf(schema) &&
        schema.oneOf.some(isNullable(visited)(components))
      );
    };
}

import { IJsonSchemaAttribute, OpenApi, OpenApiV3 } from "@typia/interface";

import { ObjectDictionary } from "../../utils/internal/ObjectDictionary";
import { OpenApiTypeChecker } from "../../validators/OpenApiTypeChecker";
import { OpenApiV3TypeChecker } from "../../validators/OpenApiV3TypeChecker";
import { OpenApiDiscriminatorConverter } from "./OpenApiDiscriminatorConverter";
import { OpenApiExclusiveEmender } from "./OpenApiExclusiveEmender";

export namespace OpenApiV3Upgrader {
  export const convert = (input: OpenApiV3.IDocument): OpenApi.IDocument => ({
    ...input,
    components: convertComponents(input.components ?? {}),
    paths: input.paths
      ? Object.fromEntries(
          Object.entries(input.paths)
            .filter(([_, v]) => v !== undefined)
            .map(
              ([key, value]) => [key, convertPathItem(input)(value)] as const,
            ),
        )
      : undefined,
    openapi: "3.2.0",
    "x-typia-emended-v12": true,
  });

  /* -----------------------------------------------------------
    OPERATORS
  ----------------------------------------------------------- */
  const convertPathItem =
    (doc: OpenApiV3.IDocument) =>
    (pathItem: OpenApiV3.IPath): OpenApi.IPath => {
      // Convert x-additionalOperations to additionalOperations
      // Promote "query" to standard method (it's a v3.2 standard method)
      const xAdditional = pathItem["x-additionalOperations"];
      const queryOp = xAdditional?.["query"];
      const additionalOperations = xAdditional
        ? Object.fromEntries(
            Object.entries(xAdditional)
              .filter(([key, v]) => key !== "query" && v !== undefined)
              .map(([key, value]) => [
                key,
                convertOperation(doc)(pathItem)(value),
              ]),
          )
        : undefined;
      const { parameters: _parameters, ...rest } = pathItem as any;

      return {
        ...rest,
        ...(pathItem.get
          ? { get: convertOperation(doc)(pathItem)(pathItem.get) }
          : undefined),
        ...(pathItem.put
          ? { put: convertOperation(doc)(pathItem)(pathItem.put) }
          : undefined),
        ...(pathItem.post
          ? { post: convertOperation(doc)(pathItem)(pathItem.post) }
          : undefined),
        ...(pathItem.delete
          ? { delete: convertOperation(doc)(pathItem)(pathItem.delete) }
          : undefined),
        ...(pathItem.options
          ? { options: convertOperation(doc)(pathItem)(pathItem.options) }
          : undefined),
        ...(pathItem.head
          ? { head: convertOperation(doc)(pathItem)(pathItem.head) }
          : undefined),
        ...(pathItem.patch
          ? { patch: convertOperation(doc)(pathItem)(pathItem.patch) }
          : undefined),
        ...(pathItem.trace
          ? { trace: convertOperation(doc)(pathItem)(pathItem.trace) }
          : undefined),
        ...(queryOp
          ? { query: convertOperation(doc)(pathItem)(queryOp) }
          : undefined),
        ...(additionalOperations && Object.keys(additionalOperations).length > 0
          ? { additionalOperations }
          : undefined),
        "x-additionalOperations": undefined,
      };
    };

  const convertOperation =
    (doc: OpenApiV3.IDocument) =>
    (pathItem: OpenApiV3.IPath) =>
    (input: OpenApiV3.IOperation): OpenApi.IOperation => {
      const components: OpenApiV3.IComponents = doc.components ?? {};
      const pathParameters: OpenApiV3.IOperation.IParameter[] = (
        pathItem.parameters ?? []
      )
        .map(resolveParameter(components))
        .filter((p): p is OpenApiV3.IOperation.IParameter => p !== undefined);
      const operationParameters: OpenApiV3.IOperation.IParameter[] = (
        input.parameters ?? []
      )
        .map(resolveParameter(components))
        .filter((p): p is OpenApiV3.IOperation.IParameter => p !== undefined);
      return {
        ...input,
        parameters:
          pathItem.parameters !== undefined || input.parameters !== undefined
            ? mergeParameters(pathParameters, operationParameters).map(
                convertParameter(components),
              )
            : undefined,
        requestBody: input.requestBody
          ? convertRequestBody(doc)(input.requestBody)
          : undefined,
        responses: input.responses
          ? Object.fromEntries(
              Object.entries(input.responses)
                .filter(([_, v]) => v !== undefined)
                .map(
                  ([key, value]) =>
                    [key, convertResponse(doc)(value)!] as const,
                )
                .filter(([_, v]) => v !== undefined),
            )
          : undefined,
      };
    };

  const resolveParameter =
    (components: OpenApiV3.IComponents) =>
    (
      input:
        | OpenApiV3.IOperation.IParameter
        | OpenApiV3.IJsonSchema.IReference<`#/components/headers/${string}`>
        | OpenApiV3.IJsonSchema.IReference<`#/components/parameters/${string}`>,
    ): OpenApiV3.IOperation.IParameter | undefined => {
      if (!("$ref" in input)) return input;
      const key: string = input.$ref.split("/").pop() ?? "";
      if (input.$ref.startsWith("#/components/headers/")) {
        const header: Omit<OpenApiV3.IOperation.IParameter, "in"> | undefined =
          components.headers?.[key];
        if (header === undefined) return undefined;
        const { name, ...rest } = header;
        return { ...rest, name: name ?? key, in: "header" };
      }
      return components.parameters?.[key];
    };

  const mergeParameters = (
    pathParameters: OpenApiV3.IOperation.IParameter[],
    operationParameters: OpenApiV3.IOperation.IParameter[],
  ): OpenApiV3.IOperation.IParameter[] => {
    const map: Map<string, OpenApiV3.IOperation.IParameter> = new Map();
    const duplicates = (
      parameters: OpenApiV3.IOperation.IParameter[],
    ): OpenApiV3.IOperation.IParameter[] => {
      const seen: Set<string> = new Set();
      return parameters.filter((parameter) => {
        const key: string = `${parameter.in}:${parameter.name}`;
        if (seen.has(key)) return true;
        seen.add(key);
        return false;
      });
    };
    const emplace = (parameter: OpenApiV3.IOperation.IParameter): void => {
      map.set(`${parameter.in}:${parameter.name}`, parameter);
    };
    pathParameters.forEach(emplace);
    operationParameters.forEach(emplace);
    return [
      ...map.values(),
      ...duplicates(pathParameters),
      ...duplicates(operationParameters),
    ];
  };

  const convertParameter =
    (components: OpenApiV3.IComponents) =>
    (input: OpenApiV3.IOperation.IParameter): OpenApi.IOperation.IParameter => {
      const { required: inputRequired, ...rest } = input;
      const required: boolean | undefined =
        input.in === "path" ? true : inputRequired;
      return {
        ...rest,
        ...(required !== undefined ? { required } : {}),
        schema: convertSchema(components)(input.schema),
        examples: input.examples
          ? Object.fromEntries(
              Object.entries(input.examples)
                .map(([key, value]) => [
                  key,
                  OpenApiV3TypeChecker.isReference(value)
                    ? components.examples?.[value.$ref.split("/").pop() ?? ""]
                    : value,
                ])
                .filter(([_, v]) => v !== undefined),
            )
          : undefined,
      };
    };

  const convertRequestBody =
    (doc: OpenApiV3.IDocument) =>
    (
      input:
        | OpenApiV3.IOperation.IRequestBody
        | OpenApiV3.IJsonSchema.IReference<`#/components/requestBodies/${string}`>,
    ): OpenApi.IOperation.IRequestBody | undefined => {
      if ("$ref" in input) {
        const found: OpenApiV3.IOperation.IRequestBody | undefined =
          doc.components?.requestBodies?.[input.$ref.split("/").pop() ?? ""];
        if (found === undefined) return undefined;
        input = found;
      }
      return {
        ...input,
        content: input.content
          ? convertContent(doc.components ?? {})(input.content)
          : undefined,
      };
    };

  const convertResponse =
    (doc: OpenApiV3.IDocument) =>
    (
      input:
        | OpenApiV3.IOperation.IResponse
        | OpenApiV3.IJsonSchema.IReference<`#/components/responses/${string}`>,
    ): OpenApi.IOperation.IResponse | undefined => {
      if ("$ref" in input) {
        const found: OpenApiV3.IOperation.IResponse | undefined =
          doc.components?.responses?.[input.$ref.split("/").pop() ?? ""];
        if (found === undefined) return undefined;
        input = found;
      }
      return {
        ...input,
        content: input.content
          ? convertContent(doc.components ?? {})(input.content)
          : undefined,
        headers: input.headers
          ? Object.fromEntries(
              Object.entries(input.headers)
                .filter(([_, v]) => v !== undefined)
                .map(([key, value]) => [
                  key,
                  convertHeader(doc.components ?? {})(key, value),
                ])
                .filter(([_, v]) => v !== undefined),
            )
          : undefined,
      };
    };

  const convertHeader =
    (components: OpenApiV3.IComponents) =>
    (
      key: string,
      input:
        | Omit<OpenApiV3.IOperation.IParameter, "in">
        | OpenApiV3.IJsonSchema.IReference<`#/components/headers/${string}`>,
    ): OpenApi.IOperation.IParameter | undefined => {
      if ("$ref" in input) {
        const found: Omit<OpenApiV3.IOperation.IParameter, "in"> | undefined =
          input.$ref.startsWith("#/components/headers/")
            ? components.headers?.[input.$ref.split("/").pop() ?? ""]
            : undefined;
        if (found === undefined) return undefined;
        input = found;
      }
      const { name: _name, ...rest } = input;
      return convertParameter(components)({
        ...rest,
        name: key,
        in: "header",
      });
    };

  const convertContent =
    (components: OpenApiV3.IComponents) =>
    (
      record: Record<string, OpenApiV3.IOperation.IMediaType>,
    ): Record<string, OpenApi.IOperation.IMediaType> =>
      Object.fromEntries(
        Object.entries(record)
          .filter(([_, v]) => v !== undefined)
          .map(
            ([key, value]) =>
              [
                key,
                {
                  ...value,
                  schema: value.schema
                    ? convertSchema(components)(value.schema)
                    : undefined,
                  examples: value.examples
                    ? Object.fromEntries(
                        Object.entries(value.examples)
                          .map(([key, value]) => [
                            key,
                            OpenApiV3TypeChecker.isReference(value)
                              ? components.examples?.[
                                  value.$ref.split("/").pop() ?? ""
                                ]
                              : value,
                          ])
                          .filter(([_, v]) => v !== undefined),
                      )
                    : undefined,
                },
              ] as const,
          ),
      );

  /* -----------------------------------------------------------
    DEFINITIONS
  ----------------------------------------------------------- */
  export const convertComponents = (
    input: OpenApiV3.IComponents,
  ): OpenApi.IComponents => ({
    schemas: Object.fromEntries(
      Object.entries(input.schemas ?? {})
        .filter(([_, v]) => v !== undefined)
        .map(([key, value]) => [key, convertSchema(input)(value)]),
    ),
    securitySchemes: input.securitySchemes,
  });

  export const convertSchema =
    (components: OpenApiV3.IComponents) =>
    (input: OpenApiV3.IJsonSchema): OpenApi.IJsonSchema => {
      const nullable: { value: boolean; default?: null } = {
        value: false,
        default: undefined,
      };
      const union: OpenApi.IJsonSchema[] = [];
      const discriminator:
        | OpenApi.IJsonSchema.IOneOf.IDiscriminator
        | undefined =
        OpenApiV3TypeChecker.isOneOf(input) && input.discriminator !== undefined
          ? OpenApiDiscriminatorConverter.clone(input.discriminator)
          : undefined;
      let preserveDiscriminator: boolean = discriminator !== undefined;
      const attribute: IJsonSchemaAttribute = {
        title: input.title,
        description: input.description,
        deprecated: input.deprecated,
        readOnly: input.readOnly,
