      const preserveNullableBranches: { value: boolean } = { value: false };
      const nullableBranches: SwaggerV2.IJsonSchema[] = [];
      const insertConstant = (schema: OpenApi.IJsonSchema.IConstant): void => {
        const value: boolean | number | string = schema.const;
        const type: "boolean" | "number" | "string" =
          typeof value === "boolean"
            ? "boolean"
            : typeof value === "number"
              ? "number"
              : "string";
        const branchAttribute: SwaggerV2.IJsonSchema.__IAttribute =
          getAttribute(schema);
        if (
          schema !== input &&
          Object.values(branchAttribute).some((value) => value !== undefined)
        ) {
          union.push({ type, enum: [value], ...branchAttribute } as
            | SwaggerV2.IJsonSchema.IBoolean
            | SwaggerV2.IJsonSchema.INumber
            | SwaggerV2.IJsonSchema.IString);
          return;
        }
        const old = constantGroups.get(type);
        if (old !== undefined) {
          old.enum ??= [];
          if (old.enum.includes(value as never) === false)
            old.enum.push(value as never);
          return;
        }
        const created = {
          type,
          enum: [value],
        } as
          | SwaggerV2.IJsonSchema.IBoolean
          | SwaggerV2.IJsonSchema.INumber
          | SwaggerV2.IJsonSchema.IString;
        constantGroups.set(type, created);
        union.push(created);
      };
      const visit = (schema: OpenApi.IJsonSchema): void => {
        if (schema !== input && Object.keys(getAttribute(schema)).length > 0)
          preserveNullableBranches.value = true;
        if (OpenApiTypeChecker.isNull(schema))
          nullableBranches.push({
            type: "null",
            default: schema.default,
            ...getAttribute(schema),
          });
        else if (OpenApiTypeChecker.isConstant(schema)) insertConstant(schema);
        else if (
          OpenApiTypeChecker.isBoolean(schema) ||
          OpenApiTypeChecker.isInteger(schema) ||
          OpenApiTypeChecker.isNumber(schema) ||
          OpenApiTypeChecker.isString(schema)
        )
          union.push({
            ...schema,
            examples: schema.examples
              ? Object.values(schema.examples)
              : undefined,
          });
        else if (OpenApiTypeChecker.isReference(schema))
          union.push({
            $ref: `#/definitions/${schema.$ref.split("/").pop()}`,
            ...(schema === input ? {} : getAttribute(schema)),
          });
        else if (OpenApiTypeChecker.isArray(schema))
          union.push({
            ...schema,
            items: downgradeSchema(collection)(schema.items),
            examples: schema.examples
              ? Object.values(schema.examples)
              : undefined,
          });
        else if (OpenApiTypeChecker.isTuple(schema))
          union.push({
            ...schema,
            items: ((): SwaggerV2.IJsonSchema => {
              if (schema.additionalItems === true) return {};
              const elements = [
                ...schema.prefixItems,
                ...(typeof schema.additionalItems === "object"
                  ? [downgradeSchema(collection)(schema.additionalItems)]
                  : []),
              ];
              if (elements.length === 0) return {};
              return {
                "x-oneOf": elements.map(downgradeSchema(collection) as any),
              };
            })(),
            minItems: schema.prefixItems.length,
            maxItems:
              !!schema.additionalItems === true
                ? undefined
                : schema.prefixItems.length,
            ...{
              prefixItems: undefined,
              additionalItems: undefined,
            },
            examples: schema.examples
              ? Object.values(schema.examples)
              : undefined,
          });
        else if (OpenApiTypeChecker.isObject(schema))
          union.push({
            ...schema,
            properties:
              schema.properties === undefined
                ? undefined
                : Object.fromEntries(
                    Object.entries(schema.properties)
                      .filter(([_, v]) => v !== undefined)
                      .map(([key, value]) => [
                        key,
                        downgradeSchema(collection)(value),
                      ]),
                  ),
            additionalProperties:
              schema.additionalProperties === undefined
                ? undefined
                : typeof schema.additionalProperties === "object"
                  ? downgradeSchema(collection)(schema.additionalProperties)
                  : schema.additionalProperties,
            required: schema.required,
            examples:
              schema.examples === undefined
                ? undefined
                : Object.values(schema.examples),
          });
        else if (OpenApiTypeChecker.isOneOf(schema))
          schema.oneOf.forEach(visit);
      };

      visit(input);
      const nullableDefault: boolean = nullableBranches.some(
        (branch) =>
          SwaggerV2TypeChecker.isNullOnly(branch) && branch.default === null,
      );
      const canInlineNullableDefault: boolean =
        union.length === 1 &&
        (SwaggerV2TypeChecker.isBoolean(union[0]!) ||
          SwaggerV2TypeChecker.isInteger(union[0]!) ||
          SwaggerV2TypeChecker.isNumber(union[0]!) ||
          SwaggerV2TypeChecker.isString(union[0]!));
      if (
        nullable === true &&
        (preserveNullableBranches.value === true ||
          (nullableDefault === true && canInlineNullableDefault === false))
      ) {
        const branches: SwaggerV2.IJsonSchema[] = [
          ...union,
          ...(nullableBranches.length > 0
            ? nullableBranches
            : [{ type: "null" } as SwaggerV2.IJsonSchema]),
        ];
        if (branches.length === 1) return { ...branches[0], ...attribute };
        return {
          "x-oneOf": branches,
          ...attribute,
        };
      }
      if (nullable) {
        for (const u of union)
          if (OpenApiTypeChecker.isReference(u as any))
            downgradeNullableReference(new Set())(collection)(u as any);
          else {
            (u as SwaggerV2.IJsonSchema.IArray)["x-nullable"] = true;
            if (nullableDefault === true)
              (
                u as
                  | SwaggerV2.IJsonSchema.IBoolean
                  | SwaggerV2.IJsonSchema.IInteger
                  | SwaggerV2.IJsonSchema.INumber
                  | SwaggerV2.IJsonSchema.IString
              ).default = null;
          }
      }

      if (nullable === true && union.length === 0)
        return { ...(nullableBranches[0] ?? { type: "null" }), ...attribute };
      return {
        ...(union.length === 0
          ? { type: undefined }
          : union.length === 1
            ? { ...union[0] }
            : { "x-oneOf": union }),
        ...attribute,
        ...(union.length > 1 ? { discriminator: undefined } : {}),
      };
    };

  const downgradeNullableReference =
    (visited: Set<string>) =>
    (collection: IComponentsCollection) =>
    (schema: SwaggerV2.IJsonSchema.IReference): void => {
      const key: string = schema.$ref.split("/").pop()!;
      if (key.endsWith(".Nullable")) return;

      const found: OpenApi.IJsonSchema | undefined = ObjectDictionary.get(
        collection.original.schemas,
        key,
      );
      if (found === undefined) return;
      else if (isNullable(visited)(collection.original)(found) === true) return;
      else if (
        ObjectDictionary.get(collection.downgraded, `${key}.Nullable`) ===
        undefined
      ) {
        ObjectDictionary.set(collection.downgraded, `${key}.Nullable`, {});
        ObjectDictionary.set(
          collection.downgraded,
          `${key}.Nullable`,
          downgradeSchema(collection)(
            OpenApiTypeChecker.isOneOf(found)
              ? {
                  ...found,
                  oneOf: [...found.oneOf, { type: "null" }],
                }
              : {
                  title: found.title,
                  description: found.description,
                  example: found.example,
                  examples: found.examples
                    ? Object.values(found.examples)
                    : undefined,
                  ...Object.fromEntries(
                    Object.entries(found).filter(
                      ([key, value]) =>
                        key.startsWith("x-") && value !== undefined,
                    ),
                  ),
                  oneOf: [found, { type: "null" }],
                },
          ),
        );
      }
      schema.$ref += ".Nullable";
    };

  const downgradeSecurityScheme = (
    input: OpenApi.ISecurityScheme,
  ): SwaggerV2.ISecurityDefinition[] => {
    if (input.type === "apiKey") return [input];
    else if (input.type === "http")
      if (input.scheme === "basic")
        return [{ type: "basic", description: input.description }];
      else return [];
    else if (input.type === "oauth2") {
      const output: SwaggerV2.ISecurityDefinition[] = [];
      if (input.flows.implicit)
        output.push({
          type: "oauth2",
          flow: "implicit",
          authorizationUrl: input.flows.implicit.authorizationUrl,
          scopes: input.flows.implicit.scopes,
        });
      if (input.flows.password)
        output.push({
          type: "oauth2",
          flow: "password",
          tokenUrl: input.flows.password.tokenUrl,
          scopes: input.flows.password.scopes,
        });
      if (input.flows.clientCredentials)
        output.push({
          type: "oauth2",
          flow: "application",
          tokenUrl: input.flows.clientCredentials.tokenUrl,
          scopes: input.flows.clientCredentials.scopes,
        });
      if (input.flows.authorizationCode)
        output.push({
          type: "oauth2",
          flow: "accessCode",
          authorizationUrl: input.flows.authorizationCode.authorizationUrl,
          tokenUrl: input.flows.authorizationCode.tokenUrl,
          scopes: input.flows.authorizationCode.scopes,
        });
      return output;
    }
    return [];
  };

  const isNullable =
    (visited: Set<string>) =>
    (components: OpenApi.IComponents) =>
    (schema: OpenApi.IJsonSchema): boolean => {
      if (OpenApiTypeChecker.isNull(schema)) return true;
      else if (OpenApiTypeChecker.isReference(schema)) {
        if (visited.has(schema.$ref)) return false;
        visited.add(schema.$ref);
        const key: string = schema.$ref.split("/").pop()!;
        const next: OpenApi.IJsonSchema | undefined = ObjectDictionary.get(
          components.schemas,
          key,
        );
        return next ? isNullable(visited)(components)(next) : false;
      }
      return (
        OpenApiTypeChecker.isOneOf(schema) &&
        schema.oneOf.some(isNullable(visited)(components))
      );
    };

  interface ISwaggerServer {
    host?: string;
    basePath?: string;
    schemes?: SwaggerV2.Scheme[];
  }

  interface IDowngradedRequestBody {
    consumes?: string[];
    parameters: SwaggerV2.IOperation.IParameter[];
  }

  interface IDowngradedResponse {
    produces?: string[];
    response: SwaggerV2.IOperation.IResponse;
  }

  interface IDowngradedMedia {
    types?: string[];
    schema?: OpenApi.IJsonSchema;
    examples?: Record<string, any>;
  }

  const downgradeServers = (
    servers: OpenApi.IServer[] | undefined,
    scope: string,
  ): ISwaggerServer => {
    if (!servers?.length) return {};
    const parsed: ISwaggerServer[] = servers.map((server) => {
      if (server.description !== undefined)
        throw new TypeError(
          `SwaggerV2Downgrader: ${scope} descriptions are not representable.`,
        );
      if (
        Object.keys(server.variables ?? {}).length > 0 ||
        server.url.includes("{")
      )
        throw new TypeError(
          `SwaggerV2Downgrader: ${scope} contain template variables.`,
        );
      if (/[?#]/.test(server.url))
        throw new TypeError(
          `SwaggerV2Downgrader: ${scope} contain a query or fragment.`,
        );
      const absolute: RegExpMatchArray | null = server.url.match(
        /^([A-Za-z][A-Za-z0-9+.-]*):\/\/([^/?#]+)(\/[^?#]*)?$/,
      );
      if (absolute) {
        const scheme: string = absolute[1]!.toLowerCase();
        if (isSwaggerScheme(scheme) === false)
          throw new TypeError(
            `SwaggerV2Downgrader: ${scope} use an unsupported scheme.`,
          );
        if (absolute[2]!.includes("@"))
          throw new TypeError(
            `SwaggerV2Downgrader: ${scope} contain user information.`,
          );
        return {
          schemes: [scheme],
          host: absolute[2]!,
          basePath: normalizeBasePath(absolute[3]),
        };
      }
      const network: RegExpMatchArray | null = server.url.match(
        /^\/\/([^/?#]+)(\/[^?#]*)?$/,
      );
      if (network) {
        if (network[1]!.includes("@"))
          throw new TypeError(
            `SwaggerV2Downgrader: ${scope} contain user information.`,
          );
        return {
          host: network[1]!,
          basePath: normalizeBasePath(network[2]),
        };
      }
      if (server.url.startsWith("/"))
        return { basePath: normalizeBasePath(server.url) };
      throw new TypeError(
        `SwaggerV2Downgrader: ${scope} contain a relative URL Swagger 2 cannot represent.`,
      );
    });
    const first: ISwaggerServer = parsed[0]!;
    if (
      parsed.some(
        (server) =>
          sameAuthority(server.host, first.host) === false ||
          server.basePath !== first.basePath,
      )
    )
      throw new TypeError(
        `SwaggerV2Downgrader: ${scope} must share one host and basePath.`,
      );
    const withoutScheme: boolean = parsed.some(
      (server) => server.schemes === undefined,
    );
    const withScheme: boolean = parsed.some(
      (server) => server.schemes !== undefined,
    );
    if (withoutScheme && withScheme)
      throw new TypeError(
        `SwaggerV2Downgrader: ${scope} mix explicit and scheme-relative URLs.`,
      );
    return {
      host: first.host,
      basePath: first.basePath,
      schemes: withScheme
        ? [...new Set(parsed.flatMap((server) => server.schemes ?? []))]
        : undefined,
    };
  };

  const downgradeOperationSchemes = (
    document: ISwaggerServer,
    servers: OpenApi.IServer[] | undefined,
  ): SwaggerV2.Scheme[] | undefined => {
    if (servers === undefined) return undefined;
    const operation: ISwaggerServer = downgradeServers(
      servers,
      "operation servers",
    );
    if (
      sameAuthority(operation.host, document.host) === false ||
      operation.basePath !== document.basePath
    )
      throw new TypeError(
        "SwaggerV2Downgrader: operation servers cannot override host or basePath.",
      );
    if (sameStrings(operation.schemes, document.schemes)) return undefined;
    if (operation.schemes === undefined)
      throw new TypeError(
        "SwaggerV2Downgrader: an operation cannot remove document schemes.",
      );
    return operation.schemes;
  };

  const downgradeMedia = (
    content: OpenApi.IOperation.IContent | undefined,
    scope: string,
  ): IDowngradedMedia => {
    if (content === undefined) return {};
    const entries: [string, OpenApi.IOperation.IMediaType][] = Object.entries(
      content,
    ).filter(
      (entry): entry is [string, OpenApi.IOperation.IMediaType] =>
        entry[1] !== undefined,
    );
    if (entries.length === 0) return { types: [] };
    const first = entries[0]![1];
    if (first.itemSchema !== undefined)
      throw new TypeError(
        `SwaggerV2Downgrader: ${scope} itemSchema is not representable.`,
      );
    if (Object.keys(first.examples ?? {}).length > 0)
      throw new TypeError(
        `SwaggerV2Downgrader: ${scope} named examples are not representable.`,
      );
    for (const [_, media] of entries.slice(1)) {
      if (media.itemSchema !== undefined)
        throw new TypeError(
          `SwaggerV2Downgrader: ${scope} itemSchema is not representable.`,
        );
      if (Object.keys(media.examples ?? {}).length > 0)
        throw new TypeError(
          `SwaggerV2Downgrader: ${scope} named examples are not representable.`,
        );
      if (!sameJson(media.schema, first.schema))
        throw new TypeError(
          `SwaggerV2Downgrader: ${scope} media types must share one schema.`,
        );
    }
    const examples: Array<[string, any]> = entries
      .filter(([_, media]) => media.example !== undefined)
      .map(([type, media]) => [type, media.example]);
    return {
      types: [...new Set(entries.map(([type]) => type))],
      schema: first.schema,
      examples: examples.length > 0 ? Object.fromEntries(examples) : undefined,
    };
  };

  const normalizeBasePath = (path: string | undefined): string | undefined => {
    if (!path || path === "/") return undefined;
    const prefixed: string = path.startsWith("/") ? path : `/${path}`;
    return prefixed.replace(/\/+$/, "");
  };

  const sameStrings = (
    x: string[] | undefined,
    y: string[] | undefined,
  ): boolean =>
    x === undefined || y === undefined
      ? x === y
      : x.length === y.length && x.every((value, index) => value === y[index]);

  const sameAuthority = (
    x: string | undefined,
    y: string | undefined,
  ): boolean =>
    x === undefined || y === undefined
      ? x === y
      : x.toLowerCase() === y.toLowerCase();

  const sameStringSet = (x: string[], y: string[]): boolean =>
    x.length === y.length && x.every((value) => y.includes(value));

  const isFormMediaType = (type: string): boolean =>
    type === "application/x-www-form-urlencoded" ||
    type === "multipart/form-data";

  const isSwaggerScheme = (input: string): input is SwaggerV2.Scheme =>
    input === "http" || input === "https" || input === "ws" || input === "wss";

  const sameJson = (x: unknown, y: unknown): boolean =>
    JSON.stringify(canonicalize(x)) === JSON.stringify(canonicalize(y));

  const canonicalize = (value: unknown): unknown => {
    if (Array.isArray(value)) return value.map(canonicalize);
    if (value === null || typeof value !== "object") return value;
    return Object.fromEntries(
      Object.entries(value)
        .sort(([x], [y]) => x.localeCompare(y))
        .map(([key, entry]) => [key, canonicalize(entry)]),
    );
  };
}

import { IJsonSchemaAttribute, OpenApi, SwaggerV2 } from "@typia/interface";

import { ObjectDictionary } from "../../utils/internal/ObjectDictionary";
import { OpenApiTypeChecker } from "../../validators/OpenApiTypeChecker";
import { SwaggerV2TypeChecker } from "../../validators/SwaggerV2TypeChecker";
import { OpenApiExclusiveEmender } from "./OpenApiExclusiveEmender";

export namespace SwaggerV2Upgrader {
  export const convert = (input: SwaggerV2.IDocument): OpenApi.IDocument => ({
    openapi: "3.2.0",
    info: input.info,
    components: convertComponents(input),
    paths: input.paths
      ? Object.fromEntries(
          Object.entries(input.paths)
            .filter(([_, v]) => v !== undefined)
            .map(
              ([key, value]) => [key, convertPathItem(input)(value)] as const,
            ),
        )
      : undefined,
    servers: convertServers(input),
    security: input.security,
    tags: input.tags,
    "x-typia-emended-v12": true,
  });

  /* -----------------------------------------------------------
    OPERATORS
  ----------------------------------------------------------- */
  const convertPathItem =
    (doc: SwaggerV2.IDocument) =>
    (pathItem: SwaggerV2.IPath): OpenApi.IPath => {
      // Convert x-additionalOperations to additionalOperations
      // Promote "query" to standard method (it's a v3.2 standard method)
      const xAdditional = pathItem["x-additionalOperations"];
      const queryOp = xAdditional?.["query"];
      const additionalOperations = xAdditional
        ? Object.fromEntries(
            Object.entries(xAdditional)
              .filter(([key, v]) => key !== "query" && v !== undefined)
              .map(([key, value]) => [
                key,
                convertOperation(doc)(pathItem)(value),
              ]),
          )
        : undefined;
      const { parameters: _parameters, ...rest } = pathItem as any;

      return {
        ...rest,
        ...(pathItem.get
          ? { get: convertOperation(doc)(pathItem)(pathItem.get) }
          : undefined),
        ...(pathItem.put
          ? { put: convertOperation(doc)(pathItem)(pathItem.put) }
          : undefined),
        ...(pathItem.post
          ? { post: convertOperation(doc)(pathItem)(pathItem.post) }
          : undefined),
        ...(pathItem.delete
          ? { delete: convertOperation(doc)(pathItem)(pathItem.delete) }
          : undefined),
        ...(pathItem.options
          ? { options: convertOperation(doc)(pathItem)(pathItem.options) }
          : undefined),
        ...(pathItem.head
          ? { head: convertOperation(doc)(pathItem)(pathItem.head) }
          : undefined),
        ...(pathItem.patch
          ? { patch: convertOperation(doc)(pathItem)(pathItem.patch) }
          : undefined),
        ...(pathItem.trace
          ? { trace: convertOperation(doc)(pathItem)(pathItem.trace) }
          : undefined),
        ...(queryOp
          ? { query: convertOperation(doc)(pathItem)(queryOp) }
          : undefined),
        ...(additionalOperations && Object.keys(additionalOperations).length > 0
          ? { additionalOperations }
          : undefined),
        "x-additionalOperations": undefined,
      };
    };

  const convertOperation =
    (doc: SwaggerV2.IDocument) =>
    (pathItem: SwaggerV2.IPath) =>
    (input: SwaggerV2.IOperation): OpenApi.IOperation => {
      const resolve = (
        p: SwaggerV2.IOperation.IParameter | SwaggerV2.IJsonSchema.IReference,
      ): SwaggerV2.IOperation.IParameter | undefined =>
        "$ref" in p ? doc.parameters?.[p.$ref.split("/").pop() ?? ""] : p;
      const pathParameters: SwaggerV2.IOperation.IParameter[] = (
        pathItem.parameters ?? []
      )
        .map(resolve)
        .filter((p): p is SwaggerV2.IOperation.IParameter => p !== undefined);
      const operationParameters: SwaggerV2.IOperation.IParameter[] = (
        input.parameters ?? []
      )
        .map((p) =>
          resolve(
            p as
              | SwaggerV2.IOperation.IParameter
              | SwaggerV2.IJsonSchema.IReference,
          ),
        )
        .filter((p): p is SwaggerV2.IOperation.IParameter => p !== undefined);
      const parameters: SwaggerV2.IOperation.IGeneralParameter[] =
        mergeParameters(
          pathParameters.filter(isGeneralParameter),
          operationParameters.filter(isGeneralParameter),
        );
      const formData: SwaggerV2.IOperation.IGeneralParameter[] =
        parameters.filter((parameter) => parameter.in === "formData");
      const body: SwaggerV2.IOperation.IBodyParameter | undefined = [
        ...operationParameters,
        ...pathParameters,
      ].find(isBodyParameter) as
        | SwaggerV2.IOperation.IBodyParameter
        | undefined;
      if (body !== undefined && formData.length > 0)
        throw new TypeError(
          "SwaggerV2Upgrader: body and formData parameters cannot coexist.",
        );
      const consumes: string[] = selectMediaTypes(input.consumes, doc.consumes);
      const produces: string[] = selectMediaTypes(input.produces, doc.produces);
      return {
        ...input,
        parameters:
          pathItem.parameters !== undefined || input.parameters !== undefined
            ? parameters
                .filter((parameter) => parameter.in !== "formData")
                .map(convertParameter(doc.definitions ?? {}))
            : undefined,
        requestBody: body
          ? convertRequestBody(doc.definitions ?? {}, consumes)(body)
          : formData.length > 0
            ? convertFormData(doc.definitions ?? {}, consumes)(formData)
            : undefined,
        responses: input.responses
          ? Object.fromEntries(
              Object.entries(input.responses)
                .filter(([_, v]) => v !== undefined)
                .map(
                  ([key, value]) =>
                    [key, convertResponse(doc, produces)(value)!] as const,
                )
                .filter(([_, v]) => v !== undefined),
            )
          : undefined,
        servers:
          input.schemes !== undefined
            ? convertServers({ ...doc, schemes: input.schemes })
            : undefined,
        ...{
          consumes: undefined,
          produces: undefined,
          schemes: undefined,
        },
      };
    };

  const isBodyParameter = (
    input: SwaggerV2.IOperation.IParameter,
  ): input is SwaggerV2.IOperation.IBodyParameter =>
    input.in === "body" ||
    (input as SwaggerV2.IOperation.IBodyParameter).schema !== undefined;

  const isGeneralParameter = (
    input: SwaggerV2.IOperation.IParameter,
  ): input is SwaggerV2.IOperation.IGeneralParameter =>
    isBodyParameter(input) === false;

  const mergeParameters = (
    pathParameters: SwaggerV2.IOperation.IGeneralParameter[],
    operationParameters: SwaggerV2.IOperation.IGeneralParameter[],
  ): SwaggerV2.IOperation.IGeneralParameter[] => {
    const map: Map<string, SwaggerV2.IOperation.IGeneralParameter> = new Map();
    const emplace = (
      parameter: SwaggerV2.IOperation.IGeneralParameter,
    ): void => {
      map.set(`${parameter.in}:${parameter.name}`, parameter);
    };
    pathParameters.forEach(emplace);
    operationParameters.forEach(emplace);
    return [...map.values()];
  };

  const convertParameter =
    (definitions: Record<string, SwaggerV2.IJsonSchema>) =>
    (
      input: SwaggerV2.IOperation.IGeneralParameter,
    ): OpenApi.IOperation.IParameter => {
      if (isFileParameter(input))
        throw new TypeError(
          "SwaggerV2Upgrader: file parameters must be located in formData.",
        );
      const {
        name,
        in: location,
        required: inputRequired,
        description,
        ...schema
      } = input as SwaggerV2.IOperation.IGeneralParameter & {
        required?: boolean | string[];
      };
      const required: boolean | undefined =
        location === "path"
          ? true
          : typeof inputRequired === "boolean"
            ? inputRequired
            : undefined;
      return {
        name,
        in: location as any,
        description,
        schema: convertSchema(definitions)({
          ...schema,
          ...(Array.isArray(inputRequired)
            ? { required: inputRequired }
            : undefined),
        } as SwaggerV2.IJsonSchema),
        ...(required !== undefined ? { required } : {}),
      };
    };

  const convertFormData =
    (
      definitions: Record<string, SwaggerV2.IJsonSchema>,
      mediaTypes: string[],
    ) =>
    (
      parameters: SwaggerV2.IOperation.IGeneralParameter[],
    ): OpenApi.IOperation.IRequestBody => {
      if (
        mediaTypes.length === 0 ||
        mediaTypes.some((type) => isFormMediaType(type) === false)
      )
        throw new TypeError(
          "SwaggerV2Upgrader: formData parameters require only form media types.",
        );
      const schema: OpenApi.IJsonSchema.IObject = {
        type: "object",
        properties: Object.fromEntries(
          parameters.map((parameter) => [
            parameter.name,
            convertFormDataSchema(definitions)(parameter),
          ]),
        ),
        required: parameters
          .filter((parameter) => isRequiredParameter(parameter))
          .map((parameter) => parameter.name),
      };
      return {
        required: schema.required!.length > 0 ? true : undefined,
        content: Object.fromEntries(
          mediaTypes.map((type) => [type, { schema }]),
        ),
      };
    };

  const convertFormDataSchema =
    (definitions: Record<string, SwaggerV2.IJsonSchema>) =>
    (input: SwaggerV2.IOperation.IGeneralParameter): OpenApi.IJsonSchema => {
      const {
        name: _name,
        in: _in,
        required: _required,
        description,
        ...schema
      } = input as SwaggerV2.IOperation.IGeneralParameter & {
        required?: boolean | string[];
      };
      if ((schema as { type?: string }).type === "file") {
        const {
          type: _type,
          format: _format,
          ...attributes
        } = schema as SwaggerV2.IJsonSchema.IString;
        return {
          ...attributes,
          type: "string",
          format: "binary",
          description,
        } as OpenApi.IJsonSchema;
      }
      const converted: OpenApi.IJsonSchema = convertSchema(definitions)({
        ...schema,
        description:
          (schema as { description?: string }).description ?? description,
      } as SwaggerV2.IJsonSchema);
      if (isFormDataSchema(converted) === false)
        throw new TypeError(
          "SwaggerV2Upgrader: formData parameters must use simple schemas.",
        );
      return converted;
    };
  const convertRequestBody =
    (
      definitions: Record<string, SwaggerV2.IJsonSchema>,
      mediaTypes: string[],
    ) =>
    (
      input: SwaggerV2.IOperation.IBodyParameter,
    ): OpenApi.IOperation.IRequestBody => {
      if (mediaTypes.length === 0)
        throw new TypeError(
          "SwaggerV2Upgrader: body parameters require a consumed media type.",
        );
      return {
        description: input.description,
        ...(input.required !== undefined ? { required: input.required } : {}),
        content: Object.fromEntries(
          mediaTypes.map((type) => [
            type,
            {
              schema: convertSchema(definitions)(input.schema),
            },
          ]),
        ),
      };
    };

  const convertResponse =
    (doc: SwaggerV2.IDocument, mediaTypes: string[]) =>
    (
      input:
        | SwaggerV2.IOperation.IResponse
        | SwaggerV2.IJsonSchema.IReference<`#/definitions/responses/${string}`>,
    ): OpenApi.IOperation.IResponse | undefined => {
      if ("$ref" in input) {
        const found: SwaggerV2.IOperation.IResponse | undefined =
          doc.responses?.[input.$ref.split("/").pop() ?? ""]!;
        if (found === undefined) return undefined;
        input = found;
      }
      const exampleTypes: string[] = Object.keys(input.examples ?? {});
      const hasPayload: boolean =
        input.schema !== undefined ||
        exampleTypes.length > 0 ||
        input.example !== undefined;
      if (hasPayload && mediaTypes.length === 0)
        throw new TypeError(
          "SwaggerV2Upgrader: response payloads require a produced media type.",
        );
      if (exampleTypes.some((type) => mediaTypes.includes(type) === false))
        throw new TypeError(
          "SwaggerV2Upgrader: response examples must match produced media types.",
        );
      return {
        description: input.description,
        content:
          input.schema !== undefined ||
          exampleTypes.length > 0 ||
          input.example !== undefined
            ? Object.fromEntries(
                mediaTypes.map((type) => [
                  type,
                  {
                    schema:
                      input.schema !== undefined
                        ? convertSchema(doc.definitions ?? {})(input.schema)
                        : undefined,
                    example: Object.hasOwn(input.examples ?? {}, type)
                      ? input.examples![type]
                      : input.example,
                  },
                ]),
              )
            : undefined,
        headers: input.headers
          ? Object.fromEntries(
              Object.entries(input.headers)
                .filter(([_, v]) => v !== undefined)
                .map(
                  ([key, value]) =>
                    [
                      key,
                      {
                        name: key,
                        in: "header",
                        schema: convertSchema(doc.definitions ?? {})(value),
                      },
                    ] as const,
                ),
            )
          : undefined,
      };
    };

  const selectMediaTypes = (
    operation: string[] | undefined,
    document: string[] | undefined,
  ): string[] => [
    ...new Set(
      operation !== undefined
        ? operation
        : document !== undefined
          ? document
          : ["application/json"],
    ),
  ];

  const convertServers = (
    input: Pick<SwaggerV2.IDocument, "host" | "basePath" | "schemes">,
  ): OpenApi.IServer[] | undefined => {
    if (/[?#]/.test(input.host ?? "") || /[?#]/.test(input.basePath ?? ""))
      throw new TypeError(
        "SwaggerV2Upgrader: host and basePath cannot contain a query or fragment.",
      );
    const basePath: string = normalizeBasePath(input.basePath);
    if (!input.host) {
      if (input.schemes?.length)
        throw new TypeError(
          "SwaggerV2Upgrader: schemes require host to compose server URLs.",
        );
      return basePath ? [{ url: basePath }] : undefined;
    }

    const absolute: RegExpMatchArray | null = input.host.match(
      /^([A-Za-z][A-Za-z0-9+.-]*):\/\/([^/?#]+)(\/[^?#]*)?$/,
    );
    const embeddedScheme: string | undefined = absolute?.[1]?.toLowerCase();
    const host: string = absolute?.[2] ?? input.host.replace(/^\/\//, "");
    if (host.includes("@"))
      throw new TypeError(
        "SwaggerV2Upgrader: host cannot contain user information.",
      );
    const hostPath: string = normalizeBasePath(absolute?.[3]);
    const path: string = joinBasePaths(hostPath, basePath);
    const schemes: string[] = [
      ...new Set(
        input.schemes?.length
          ? input.schemes
          : embeddedScheme
            ? [embeddedScheme]
            : [],
      ),
    ];
    if (schemes.some((scheme) => isSwaggerScheme(scheme) === false))
      throw new TypeError(
        "SwaggerV2Upgrader: schemes must be http, https, ws, or wss.",
      );
    return schemes.length
      ? (schemes as SwaggerV2.Scheme[]).map((scheme) => ({
          url: `${scheme}://${host}${path}`,
        }))
      : [{ url: `//${host}${path}` }];
  };

  const normalizeBasePath = (path: string | undefined): string => {
    if (!path || path === "/") return path ?? "";
    const prefixed: string = path.startsWith("/") ? path : `/${path}`;
    return prefixed.replace(/\/+$/, "");
  };

  const joinBasePaths = (x: string, y: string): string =>
    x.length === 0 && y.length === 0
      ? ""
      : normalizeBasePath(`${x}/${y}`.replace(/\/+/g, "/"));

  const isFormMediaType = (type: string): boolean =>
    type === "application/x-www-form-urlencoded" ||
    type === "multipart/form-data";

  const isFormDataSchema = (input: OpenApi.IJsonSchema): boolean => {
    if (isFormDataScalarSchema(input)) return true;
    if (OpenApiTypeChecker.isArray(input) === false) return false;
    return isFormDataSchema(input.items);
  };

  const isFormDataScalarSchema = (input: OpenApi.IJsonSchema): boolean => {
    if (
      OpenApiTypeChecker.isBoolean(input) ||
      OpenApiTypeChecker.isInteger(input) ||
      OpenApiTypeChecker.isNumber(input)
    )
      return true;
    if (OpenApiTypeChecker.isString(input)) return input.format !== "binary";
    if (OpenApiTypeChecker.isConstant(input)) return true;
    if (OpenApiTypeChecker.isOneOf(input) === false) return false;
    const nonNull: OpenApi.IJsonSchema[] = input.oneOf.filter(
      (schema) => OpenApiTypeChecker.isNull(schema) === false,
    );
    const nullCount: number = input.oneOf.length - nonNull.length;
    if (nullCount > 1 || nonNull.length === 0) return false;
    if (nonNull.every(OpenApiTypeChecker.isConstant))
      return (
        new Set(
          nonNull.map(
            (schema) => typeof (schema as OpenApi.IJsonSchema.IConstant).const,
          ),
        ).size === 1
      );
    return (
      nullCount === 1 && nonNull.length === 1 && isFormDataSchema(nonNull[0]!)
    );
  };

  const isSwaggerScheme = (input: string): input is SwaggerV2.Scheme =>
    input === "http" || input === "https" || input === "ws" || input === "wss";

  const isFileParameter = (
    input: SwaggerV2.IOperation.IGeneralParameter,
  ): input is SwaggerV2.IOperation.IGeneralParameter.IFile & {
    name: string;
    in: string;
    description?: string;
  } => (input as { type?: string }).type === "file";

  const isRequiredParameter = (
    input: SwaggerV2.IOperation.IGeneralParameter,
  ): boolean => (input as { required?: boolean }).required === true;

  /* -----------------------------------------------------------
    DEFINITIONS
  ----------------------------------------------------------- */
  export const convertComponents = (
    input: SwaggerV2.IDocument,
  ): OpenApi.IComponents => ({
    schemas: Object.fromEntries(
      Object.entries(input.definitions ?? {})
        .filter(([_, v]) => v !== undefined)
        .map(([key, value]) => [
          key,
          convertSchema(input.definitions ?? {})(value),
        ]),
    ),
    securitySchemes: input.securityDefinitions
      ? Object.fromEntries(
          Object.entries(input.securityDefinitions)
            .filter(([_, v]) => v !== undefined)
            .map(([key, value]) => [key, convertSecurityScheme(value)])
            .filter(([_, v]) => v !== undefined),
        )
      : undefined,
  });

  const convertSecurityScheme = (
    input: SwaggerV2.ISecurityDefinition,
  ): OpenApi.ISecurityScheme => {
    if (input.type === "apiKey") return input;
    else if (input.type === "basic")
      return {
        type: "http",
        scheme: "basic",
        description: input.description,
      };
    else if (input.type === "oauth2")
      if (input.flow === "implicit")
        return {
          type: "oauth2",
          description: input.description,
          flows: {
            implicit: {
              authorizationUrl: input.authorizationUrl,
              scopes: input.scopes,
            },
          },
        };
      else if (input.flow === "accessCode")
        return {
          type: "oauth2",
          description: input.description,
          flows: {
            authorizationCode: {
              authorizationUrl: input.authorizationUrl,
              tokenUrl: input.tokenUrl,
              scopes: input.scopes,
            },
          },
        };
      else if (input.flow === "password")
        return {
          type: "oauth2",
          description: input.description,
          flows: {
            password: {
              tokenUrl: input.tokenUrl,
              scopes: input.scopes,
            },
          },
        };
      else if (input.flow === "application")
        return {
          type: "oauth2",
          description: input.description,
          flows: {
            clientCredentials: {
              tokenUrl: input.tokenUrl,
              scopes: input.scopes,
            },
          },
        };
      else return undefined!;
    return undefined!;
  };

  export const convertSchema =
    (definitions: Record<string, SwaggerV2.IJsonSchema>) =>
    (input: SwaggerV2.IJsonSchema): OpenApi.IJsonSchema => {
      const nullable: { value: boolean; default?: null } = {
        value: false,
        default: undefined,
      };
      const union: OpenApi.IJsonSchema[] = [];
      const getAttribute = (
        schema: SwaggerV2.IJsonSchema,
      ): IJsonSchemaAttribute =>
        Object.fromEntries(
          Object.entries({
            title: schema.title,
            description: schema.description,
            deprecated: schema.deprecated,
            readOnly: schema.readOnly,
            example: schema.example,
            examples: schema.examples
              ? Object.fromEntries(schema.examples.map((v, i) => [`v${i}`, v]))
              : undefined,
            ...Object.fromEntries(
              Object.entries(schema).filter(
                ([key, value]) =>
                  key.startsWith("x-") &&
                  key !== "x-anyOf" &&
                  key !== "x-oneOf" &&
                  key !== "x-nullable" &&
                  value !== undefined,
              ),
            ),
          }).filter(([_, value]) => value !== undefined),
        ) as IJsonSchemaAttribute;
      const attribute: IJsonSchemaAttribute = getAttribute(input);
      const visit = (schema: SwaggerV2.IJsonSchema): void => {
        // NULLABLE PROPERTY
        if (
          (schema as SwaggerV2.IJsonSchema.__ISignificant<any>)[
            "x-nullable"
          ] === true
        ) {
          nullable.value ||= true;
          if ((schema as SwaggerV2.IJsonSchema.INumber).default === null)
            nullable.default = null;
        }
        if (
          Array.isArray((schema as SwaggerV2.IJsonSchema.INumber).enum) &&
          (schema as SwaggerV2.IJsonSchema.INumber).enum?.length &&
          (schema as SwaggerV2.IJsonSchema.INumber).enum?.some(
            (e) => e === null,
          )
        )
          nullable.value ||= true;
        // UNION TYPE CASE
        if (SwaggerV2TypeChecker.isAnyOf(schema))
          schema["x-anyOf"].forEach(visit);
        else if (SwaggerV2TypeChecker.isOneOf(schema))
          schema["x-oneOf"].forEach(visit);
        else if (SwaggerV2TypeChecker.isAllOf(schema))
          if (schema.allOf.length === 1) visit(schema.allOf[0]!);
          else union.push(convertAllOfSchema(definitions)(schema));
        // ATOMIC TYPE CASE (CONSIDER ENUM VALUES)
        else if (
          SwaggerV2TypeChecker.isBoolean(schema) ||
          SwaggerV2TypeChecker.isInteger(schema) ||
          SwaggerV2TypeChecker.isNumber(schema) ||
          SwaggerV2TypeChecker.isString(schema)
        )
          if (schema.enum?.length)
            union.push(
              ...schema.enum
                .filter((v) => v !== null)
                .map((value) => ({
                  const: value,
                  ...(schema === input ? {} : getAttribute(schema)),
                })),
            );
          else if (
            SwaggerV2TypeChecker.isInteger(schema) ||
            SwaggerV2TypeChecker.isNumber(schema)
          )
            union.push(
              OpenApiExclusiveEmender.emend({
                ...schema,
                default: (schema.default ?? undefined) satisfies
                  | boolean
                  | number
                  | string
                  | undefined as any,
                examples: schema.examples
                  ? Object.fromEntries(
                      schema.examples.map((v, i) => [`v${i}`, v]),
                    )
                  : undefined,
                exclusiveMinimum:
                  typeof schema.exclusiveMinimum === "boolean"
                    ? schema.exclusiveMinimum === true
                      ? schema.minimum
                      : undefined
                    : schema.exclusiveMinimum,
                exclusiveMaximum:
                  typeof schema.exclusiveMaximum === "boolean"
                    ? schema.exclusiveMaximum === true
                      ? schema.maximum
                      : undefined
                    : schema.exclusiveMaximum,
                minimum:
                  schema.exclusiveMinimum === true ? undefined : schema.minimum,
                maximum:
                  schema.exclusiveMaximum === true ? undefined : schema.maximum,
                ...{ enum: undefined },
              }),
            );
          else
            union.push({
              ...schema,
              default: (schema.default ?? undefined) satisfies
                | boolean
                | number
                | string
                | undefined as any,
              examples: schema.examples
                ? Object.fromEntries(
                    schema.examples.map((v, i) => [`v${i}`, v]),
                  )
                : undefined,
              ...{ enum: undefined },
            });
        // INSTANCE TYPE CASE
        else if (SwaggerV2TypeChecker.isArray(schema))
          union.push({
            ...schema,
            items: convertSchema(definitions)(schema.items),
            examples: schema.examples
              ? Object.fromEntries(schema.examples.map((v, i) => [`v${i}`, v]))
              : undefined,
          });
        else if (SwaggerV2TypeChecker.isObject(schema)) {
          union.push({
            ...schema,
            properties:
              schema.properties === undefined
                ? undefined
                : Object.fromEntries(
                    Object.entries(schema.properties)
                      .filter(([_, v]) => v !== undefined)
                      .map(([key, value]) => [
                        key,
                        convertSchema(definitions)(value),
                      ]),
                  ),
            additionalProperties:
              schema.additionalProperties === undefined
                ? undefined
                : typeof schema.additionalProperties === "object" &&
                    schema.additionalProperties !== null
                  ? convertSchema(definitions)(schema.additionalProperties)
                  : schema.additionalProperties,
            examples:
              schema.examples === undefined
                ? undefined
                : Object.fromEntries(
                    schema.examples.map((v, i) => [`v${i}`, v]),
                  ),
            required: schema.required,
          });
        } else if (SwaggerV2TypeChecker.isReference(schema))
          union.push({
            ...schema,
            $ref: schema.$ref.replace(
              "#/definitions/",
              "#/components/schemas/",
            ),
            examples: schema.examples
              ? Object.fromEntries(schema.examples.map((v, i) => [`v${i}`, v]))
              : undefined,
          });
        else
          union.push({
            ...schema,
            examples: schema.examples
              ? Object.fromEntries(schema.examples.map((v, i) => [`v${i}`, v]))
              : undefined,
          });
      };

      visit(input);
      if (
        nullable.value === true &&
        !union.some((e) => (e as OpenApi.IJsonSchema.INull).type === "null")
      )
        union.push({
          type: "null",
          default: nullable.default,
        });
      if (
        union.length === 2 &&
        SwaggerV2TypeChecker.isAnyOf(input) === false &&
        SwaggerV2TypeChecker.isOneOf(input) === false &&
        union.filter((x) => OpenApiTypeChecker.isNull(x)).length === 1
      ) {
        const type: OpenApi.IJsonSchema = union.filter(
          (x) => OpenApiTypeChecker.isNull(x) === false,
        )[0]!;
        for (const key of [
          "title",
          "description",
          "deprecated",
          "example",
          "examples",
        ] as const)
          if (type[key] !== undefined) delete type[key];
      }
      return {
        ...(union.length === 0
          ? { type: undefined }
          : union.length === 1
            ? { ...union[0] }
            : { oneOf: union.map((u) => ({ ...u, "x-nullable": undefined })) }),
        ...attribute,
        ...{ "x-nullable": undefined },
      };
    };

  const convertAllOfSchema =
    (definitions: Record<string, SwaggerV2.IJsonSchema>) =>
    (input: SwaggerV2.IJsonSchema.IAllOf): OpenApi.IJsonSchema => {
      const objects: Array<SwaggerV2.IJsonSchema.IObject | null> =
        input.allOf.map((schema) => retrieveObject(definitions)(schema));
      if (objects.some((obj) => obj === null))
        return {
          type: undefined,
          ...{
            allOf: undefined,
          },
        };
      return {
        ...input,
        type: "object" as const,
        properties: Object.fromEntries(
          objects
            .map((o) => Object.entries(o?.properties ?? {}))
            .flat()
            .map(
              ([key, value]) =>
                [key, convertSchema(definitions)(value)] as const,
            ),
        ),
        additionalProperties: objects.every(
          (o) => o?.additionalProperties === false,
        )
          ? false
          : undefined,
        ...{
          allOf: undefined,
          required: [...new Set(objects.map((o) => o?.required ?? []).flat())],
        },
      };
    };

  const retrieveObject =
    (definitions: Record<string, SwaggerV2.IJsonSchema>) =>
    (
      input: SwaggerV2.IJsonSchema,
      visited: Set<SwaggerV2.IJsonSchema> = new Set(),
    ): SwaggerV2.IJsonSchema.IObject | null => {
      if (SwaggerV2TypeChecker.isObject(input))
        return input.properties !== undefined && !input.additionalProperties
          ? input
          : null;
      else if (visited.has(input)) return null;
      else visited.add(input);

      if (SwaggerV2TypeChecker.isReference(input))
        return retrieveObject(definitions)(
          ObjectDictionary.get(
            definitions,
            input.$ref.split("/").pop() ?? "",
          ) ?? {},
          visited,
        );
      return null;
    };
}

@typia/utils/src/converters/LlmSchemaCon:
import {
  IJsonSchemaAttribute,
  IJsonSchemaTransformError,
  ILlmSchema,
  IResult,
  OpenApi,
} from "@typia/interface";

import { JsonDescriptor } from "../utils/internal/JsonDescriptor";
import { LlmReference } from "../utils/internal/LlmReference";
import { ObjectDictionary } from "../utils/internal/ObjectDictionary";
import { OpenApiComponentName } from "../utils/internal/OpenApiComponentName";
import { OpenApiSchemaSanitizer } from "../utils/internal/OpenApiSchemaSanitizer";
import { LlmTypeChecker } from "../validators/LlmTypeChecker";
import { OpenApiTypeChecker } from "../validators/OpenApiTypeChecker";
import { LlmDescriptionInverter } from "./internal/LlmDescriptionInverter";
import { LlmParametersFinder } from "./internal/LlmParametersComposer";
import { OpenApiConstraintShifter } from "./internal/OpenApiConstraintShifter";

/**
 * OpenAPI to LLM schema converter.
 *
 * `LlmSchemaConverter` converts OpenAPI JSON schemas to LLM-compatible
 * {@link ILlmSchema} format. LLMs don't fully support JSON Schema, so this
 * simplifies schemas by removing unsupported features (tuples, `const`, mixed
 * unions).
 *
 * Main functions:
 *
 * - {@link parameters}: Convert object schema to {@link ILlmSchema.IParameters}
 * - {@link schema}: Convert any schema to {@link ILlmSchema}
 * - {@link invert}: Extract constraints from description back to schema
 *
 * Configuration options ({@link ILlmSchema.IConfig}):
 *
 * - `strict`: OpenAI structured output mode (all properties required)
 *
 * @author Jeongho Nam - https://github.com/samchon
 */
export namespace LlmSchemaConverter {
  /**
   * Get configuration with defaults applied.
   *
   * @param config Partial configuration
   * @returns Full configuration with defaults
   */
  export const getConfig = (
    config?: Partial<ILlmSchema.IConfig> | undefined,
  ): ILlmSchema.IConfig => ({
    strict: config?.strict ?? false,
  });

  /* -----------------------------------------------------------
    CONVERTERS
  ----------------------------------------------------------- */
  /**
   * Convert OpenAPI object schema to LLM parameters schema.
   *
   * @param props.config Conversion configuration
   * @param props.components OpenAPI components for reference resolution
   * @param props.schema Object or reference schema to convert
   * @param props.accessor Error path accessor
   * @param props.refAccessor Reference path accessor
   * @returns Converted parameters or error
   */
  export const parameters = (props: {
    config?: Partial<ILlmSchema.IConfig>;
    components: OpenApi.IComponents;
    schema: OpenApi.IJsonSchema.IObject | OpenApi.IJsonSchema.IReference;
    accessor?: string;
    refAccessor?: string;
  }): IResult<ILlmSchema.IParameters, IJsonSchemaTransformError> => {
    const config: ILlmSchema.IConfig = getConfig(props.config);
    const entity: IResult<
      OpenApi.IJsonSchema.IObject,
      IJsonSchemaTransformError
    > = LlmParametersFinder.parameters({
      ...props,
      method: "LlmSchemaConverter.parameters",
    });
    if (entity.success === false) return entity;

    const $defs: Record<string, ILlmSchema> = {};
    const result: IResult<ILlmSchema, IJsonSchemaTransformError> = transform({
      ...props,
      config,
      $defs,
      schema: entity.value,
    });
    if (result.success === false) return result;
    return {
      success: true,
      value: {
        ...(result.value as ILlmSchema.IObject),
        additionalProperties: false,
        $defs,
        description: OpenApiTypeChecker.isReference(props.schema)
          ? JsonDescriptor.cascade({
              prefix: "#/components/schemas/",
              components: props.components,
              schema: {
                ...props.schema,
                description: result.value.description,
              },
              escape: true,
              key: LlmReference.readOpenApi(props.schema.$ref)!,
            })
          : result.value.description,
      } satisfies ILlmSchema.IParameters,
    };
  };

  /**
   * Convert OpenAPI schema to LLM schema.
   *
   * @param props.config Conversion configuration
   * @param props.components OpenAPI components for reference resolution
   * @param props.$defs Definition store (mutated with referenced types)
   * @param props.schema Schema to convert
   * @param props.accessor Error path accessor
   * @param props.refAccessor Reference path accessor
   * @returns Converted schema or error
   */
  export const schema = (props: {
    config?: Partial<ILlmSchema.IConfig>;
    components: OpenApi.IComponents;
    $defs: Record<string, ILlmSchema>;
    schema: OpenApi.IJsonSchema;
    accessor?: string;
    refAccessor?: string;
  }): IResult<ILlmSchema, IJsonSchemaTransformError> =>
    transform({
      config: getConfig(props.config),
      components: props.components,
      $defs: props.$defs,
      schema: props.schema,
      accessor: props.accessor,
      refAccessor: props.refAccessor,
    });

  const transform = (props: {
    config: ILlmSchema.IConfig;
    components: OpenApi.IComponents;
    $defs: Record<string, ILlmSchema>;
    schema: OpenApi.IJsonSchema;
    accessor?: string;
    refAccessor?: string;
  }): IResult<ILlmSchema, IJsonSchemaTransformError> => {
    // PREPARE ASSETS
    const union: Array<ILlmSchema> = [];
    const attribute: IJsonSchemaAttribute = {
      title: props.schema.title,
      description: props.schema.description,
      deprecated: props.schema.deprecated,
      readOnly: props.schema.readOnly,
      writeOnly: props.schema.writeOnly,
      example: props.schema.example,
      examples: props.schema.examples,
      ...Object.fromEntries(
        Object.entries(props.schema).filter(
          ([key, value]) => key.startsWith("x-") && value !== undefined,
        ),
      ),
    };

    // VALIDADTE SCHEMA
    const reasons: IJsonSchemaTransformError.IReason[] = [];
    const validateReference = (
      schema: OpenApi.IJsonSchema,
      reference: string,
      accessor: string,
    ): string | undefined => {
      const key: string | undefined = LlmReference.readOpenApi(reference);
      if (key === undefined) {
        reasons.push({
          schema,
          accessor,
          message: `invalid local schema reference ${JSON.stringify(reference)}.`,
        });
        return undefined;
      } else if (
        ObjectDictionary.get(props.components.schemas, key) === undefined
      ) {
        reasons.push({
          schema,
          accessor,
          message: `unable to find reference type ${JSON.stringify(key)}.`,
        });
        return undefined;
      }
      return key;
    };
    const visited: Set<string> = new Set();
    const validate = (next: OpenApi.IJsonSchema, accessor: string): void => {
      if (props.config.strict === true)
        reasons.push(...validateStrict(next, accessor));
      if (OpenApiTypeChecker.isReference(next)) {
        const key: string | undefined = validateReference(
          next,
          next.$ref,
          accessor,
        );
        if (key === undefined || visited.has(key)) return;
        visited.add(key);
        validate(
          ObjectDictionary.get(props.components.schemas, key)!,
          `${props.refAccessor ?? "$input.components.schemas"}[${JSON.stringify(key)}]`,
        );
      } else if (OpenApiTypeChecker.isOneOf(next)) {
        if (next.discriminator?.mapping !== undefined)
          for (const [key, reference] of Object.entries(
            next.discriminator.mapping,
          ))
            validateReference(
              next,
              reference,
              `${accessor}.discriminator.mapping[${JSON.stringify(key)}]`,
            );
        next.oneOf.forEach((schema, index) =>
          validate(schema, `${accessor}.oneOf[${index}]`),
        );
      } else if (OpenApiTypeChecker.isObject(next)) {
        for (const [key, schema] of Object.entries(next.properties ?? {}))
          validate(schema, `${accessor}.properties[${JSON.stringify(key)}]`);
        if (
          typeof next.additionalProperties === "object" &&
          next.additionalProperties !== null
        )
          validate(
            next.additionalProperties,
            `${accessor}.additionalProperties`,
          );
      } else if (OpenApiTypeChecker.isArray(next))
        validate(next.items, `${accessor}.items`);
      else if (OpenApiTypeChecker.isTuple(next)) {
        reasons.push({
          accessor,
          schema: next,
          message: `LLM does not allow tuple type.`,
        });
        (next.prefixItems ?? []).forEach((schema, index) =>
          validate(schema, `${accessor}.prefixItems[${index}]`),
        );
        if (
          typeof next.additionalItems === "object" &&
          next.additionalItems !== null
        )
          validate(next.additionalItems, `${accessor}.additionalItems`);
      }
    };
    validate(props.schema, props.accessor ?? "$input.schema");
    if (reasons.length > 0)
      return {
        success: false,
        error: {
          method: "LlmSchemaConverter.schema",
          message: "Failed to compose LLM schema",
          reasons,
        },
      };

    const visitConstant = (input: OpenApi.IJsonSchema): void => {
      const insert = (value: any): void => {
        const matched:
          | ILlmSchema.IString
          | ILlmSchema.INumber
          | ILlmSchema.IBoolean
          | undefined = union.find(
          (u) =>
            (u as (IJsonSchemaAttribute & { type: string }) | undefined)
              ?.type === typeof value,
        ) as ILlmSchema.IString | undefined;
        if (matched !== undefined) {
          matched.enum ??= [];
          matched.enum.push(value);
        } else
          union.push({
            type: typeof value as "number",
            enum: [value],
          });
      };
      if (OpenApiTypeChecker.isConstant(input)) insert(input.const);
      else if (OpenApiTypeChecker.isOneOf(input))
        input.oneOf.forEach(visitConstant);
    };
    const visit = (input: OpenApi.IJsonSchema, accessor: string): void => {
      if (OpenApiTypeChecker.isOneOf(input)) {
        // UNION TYPE
        input.oneOf.forEach((s, i) => visit(s, `${accessor}.oneOf[${i}]`));
      } else if (OpenApiTypeChecker.isReference(input)) {
        // REFERENCE TYPE
        const key: string | undefined = LlmReference.readOpenApi(input.$ref);
        if (key === undefined) return; // unreachable after validation
        const target: OpenApi.IJsonSchema | undefined = ObjectDictionary.get(
          props.components.schemas,
          key,
        );
        if (target === undefined) return;
        else {
          // KEEP THE REFERENCE TYPE
          const out = () => {
            union.push({
              ...input,
              $ref: LlmReference.write(key),
            });
          };
          if (ObjectDictionary.has(props.$defs, key)) return out();

          ObjectDictionary.set(props.$defs, key, {});
          const converted: IResult<ILlmSchema, IJsonSchemaTransformError> =
            transform({
              config: props.config,
              components: props.components,
              $defs: props.$defs,
              schema: target,
              refAccessor: props.refAccessor,
              accessor: `${props.refAccessor ?? "$def"}[${JSON.stringify(key)}]`,
            });
          if (converted.success === false) return; // UNREACHABLE
          ObjectDictionary.set(props.$defs, key, converted.value);
          return out();
        }
      } else if (OpenApiTypeChecker.isObject(input)) {
        // OBJECT TYPE
        const properties: Record<string, ILlmSchema> = Object.fromEntries(
          Object.entries(input.properties ?? {})
            .map(([key, value]) => {
              const converted: IResult<ILlmSchema, IJsonSchemaTransformError> =
                transform({
                  config: props.config,
                  components: props.components,
                  $defs: props.$defs,
                  schema: value,
                  refAccessor: props.refAccessor,
                  accessor: `${props.accessor ?? "$input.schema"}.properties[${JSON.stringify(key)}]`,
                });
              if (converted.success === false) {
                reasons.push(...converted.error.reasons);
                return [key, null];
              }
              return [key, converted.value];
            })
            .filter(([, value]) => value !== null),
        );
        if (Object.values(properties).some((v) => v === null)) return;

        const additionalProperties: ILlmSchema | boolean | undefined | null =
          (() => {
            if (
              typeof input.additionalProperties === "object" &&
              input.additionalProperties !== null
            ) {
              const converted: IResult<ILlmSchema, IJsonSchemaTransformError> =
                transform({
                  config: props.config,
                  components: props.components,
                  $defs: props.$defs,
                  schema: input.additionalProperties,
                  refAccessor: props.refAccessor,
                  accessor: `${accessor}.additionalProperties`,
                });
              if (converted.success === false) {
                reasons.push(...converted.error.reasons);
                return null;
              }
              return converted.value;
            }
            return props.config.strict === true
              ? false
              : input.additionalProperties;
          })();
        if (additionalProperties === null) return;
        union.push({
          ...input,
          properties,
          additionalProperties,
          required: input.required ?? [],
          description:
            props.config.strict === true
              ? JsonDescriptor.take(input)
              : input.description,
        });
      } else if (OpenApiTypeChecker.isArray(input)) {
        // ARRAY TYPE
        const items: IResult<ILlmSchema, IJsonSchemaTransformError> = transform(
          {
            config: props.config,
            components: props.components,
            $defs: props.$defs,
            schema: input.items,
            refAccessor: props.refAccessor,
            accessor: `${accessor}.items`,
          },
        );
        if (items.success === false) {
          reasons.push(...items.error.reasons);
          return;
        }
        union.push(
          props.config.strict === true
            ? OpenApiConstraintShifter.shiftArray({
                ...input,
                items: items.value,
              })
            : {
                ...input,
                items: items.value,
              },
        );
      } else if (OpenApiTypeChecker.isString(input))
        union.push(
          props.config.strict === true
            ? OpenApiConstraintShifter.shiftString({ ...input })
            : input,
        );
      else if (
        OpenApiTypeChecker.isNumber(input) ||
        OpenApiTypeChecker.isInteger(input)
      )
        union.push(
          props.config.strict === true
            ? OpenApiConstraintShifter.shiftNumeric({ ...input })
            : input,
        );
      else if (OpenApiTypeChecker.isTuple(input))
        return; // UNREACHABLE
      else if (OpenApiTypeChecker.isConstant(input) === false)
        union.push({ ...input });
    };

    visitConstant(props.schema);
    visit(props.schema, props.accessor ?? "$input.schema");

    if (reasons.length > 0)
      return {
        success: false,
        error: {
          method: "LlmSchemaConverter.schema",
          message: "Failed to compose LLM schema",
          reasons,
        },
      };
    else if (union.length === 0)
      return {
        // unknown type
        success: true,
        value: {
          ...attribute,
          type: undefined,
        },
      };
    else if (union.length === 1)
      return {
        // single type
        success: true,
        value: {
          ...attribute,
          ...union[0],
          description:
            props.config.strict === true &&
            LlmTypeChecker.isReference(union[0]!)
              ? undefined
              : (union[0]!.description ?? attribute.description),
        },
      };
    return {
      success: true,
      value: {
        ...attribute,
        anyOf: union.map((u) => ({
          ...u,
          description:
            props.config.strict === true && LlmTypeChecker.isReference(u)
              ? undefined
              : u.description,
        })),
        "x-discriminator":
          OpenApiTypeChecker.isOneOf(props.schema) &&
          props.schema.discriminator !== undefined &&
          props.schema.oneOf.length === union.length &&
          union.every(
            (e) => LlmTypeChecker.isReference(e) || LlmTypeChecker.isNull(e),
          )
            ? {
                propertyName: props.schema.discriminator.propertyName,
                mapping:
                  props.schema.discriminator.mapping !== undefined
                    ? convertDiscriminatorMapping(
                        props.schema.discriminator.mapping,
                      )
                    : undefined,
              }
            : undefined,
      },
    };
  };

  /* -----------------------------------------------------------
    INVERTERS
  ----------------------------------------------------------- */
  /**
   * Convert LLM schema back to OpenAPI schema.
   *
   * Restores constraint information from description tags and converts `$defs`
   * references to `#/components/schemas`.
   *
   * Only `strict` conversions move constraints into the description, so only a
   * `strict` inversion reads them back. Pass the same `config` the schema was
   * converted with; the default is the same non-strict default {@link getConfig}
   * applies, under which the constraint keywords are still on the schema and a
   * description is only ever prose.
   *
   * @param props.config Configuration the schema was converted with
   * @param props.components Target components (mutated with definitions)
   * @param props.schema LLM schema to invert
   * @param props.$defs LLM schema definitions
   * @returns OpenAPI JSON schema
   */
  export const invert = (props: {
    config?: Partial<ILlmSchema.IConfig>;
    components: OpenApi.IComponents;
    schema: ILlmSchema;
    $defs: Record<string, ILlmSchema>;
  }): OpenApi.IJsonSchema =>
    invertInternal({
      ...props,
      config: getConfig(props.config),
      // One allocation per conversion, seeded with the component names the
      // caller already owns. Recursive inversion reuses it instead of
      // recomputing, so a reference and its stored component never disagree.
      //
      // Seed with getOwnPropertyNames, not keys: LlmReference.resolve finds a
      // definition through ObjectDictionary.get, which keys off
      // hasOwnProperty. Seeding with the enumerable-only view would let an own
      // non-enumerable definition resolve without ever being allocated.
      allocation: OpenApiComponentName.allocate({
        keys: Object.getOwnPropertyNames(props.$defs ?? {}),
        reserved: Object.getOwnPropertyNames(props.components.schemas ?? {}),
      }),
      emitted: new Set(),
    });

  const invertInternal = (props: {
    config: ILlmSchema.IConfig;
    components: OpenApi.IComponents;
    schema: ILlmSchema;
    $defs: Record<string, ILlmSchema>;
    allocation: Map<string, string>;
    emitted: Set<string>;
  }): OpenApi.IJsonSchema => {
    const union: OpenApi.IJsonSchema[] = [];
    const attribute: IJsonSchemaAttribute = {
      title: props.schema.title,
      description: props.schema.description,
      deprecated: props.schema.deprecated,
      readOnly: props.schema.readOnly,
      writeOnly: props.schema.writeOnly,
      example: props.schema.example,
      examples: props.schema.examples,
      ...Object.fromEntries(
        Object.entries(props.schema).filter(
          ([key, value]) => key.startsWith("x-") && value !== undefined,
        ),
      ),
    };

    const next = (schema: ILlmSchema): OpenApi.IJsonSchema =>
      invertInternal({
        config: props.config,
        components: props.components,
        $defs: props.$defs,
        schema,
        allocation: props.allocation,
        emitted: props.emitted,
      });
    const visit = (schema: ILlmSchema): void => {
      if (LlmTypeChecker.isArray(schema))
        union.push({
          ...schema,
          ...LlmDescriptionInverter.array({
            config: props.config,
            description: schema.description,
          }),
          items: next(schema.items),
        });
      else if (LlmTypeChecker.isObject(schema))
        union.push(
          OpenApiSchemaSanitizer.omitEmptyRequired({
            ...schema,
            properties: Object.fromEntries(
              Object.entries(schema.properties ?? {}).map(([key, value]) => [
                key,
                next(value),
              ]),
            ),
            additionalProperties:
              typeof schema.additionalProperties === "object" &&
              schema.additionalProperties !== null
                ? next(schema.additionalProperties)
                : schema.additionalProperties,
          }),
        );
      else if (LlmTypeChecker.isAnyOf(schema)) schema.anyOf.forEach(visit);
      else if (LlmTypeChecker.isReference(schema)) {
        const resolved: LlmReference.IResolved | undefined =
          LlmReference.resolve(props.$defs, schema.$ref);
        if (resolved === undefined) {
          union.push({ oneOf: [] });
          return;
        }
        // The allocation seeds from the same own-property view that resolve
        // uses, so a resolved key is always allocated. Escape rather than fall
        // back to the raw key regardless: the grammar invariant must hold even
        // if the two views ever diverge again.
        const componentKey: string =
          props.allocation.get(resolved.key) ??
          OpenApiComponentName.escape(resolved.key);
        // Gate on what this conversion has emitted, not on what the components
        // already contain. A caller's pre-existing component of the same name
        // is an allocation input, not a cache hit: treating it as one would
        // silently drop this definition and alias it to an unrelated schema.
        if (props.emitted.has(componentKey) === false) {
          props.emitted.add(componentKey);
          props.components.schemas ??= {};
          ObjectDictionary.set(props.components.schemas, componentKey, {});
          ObjectDictionary.set(
            props.components.schemas,
            componentKey,
            next(resolved.schema),
          );
        }
        union.push({
          ...schema,
          $ref: LlmReference.writeOpenApi(componentKey),
        });
      } else if (LlmTypeChecker.isBoolean(schema))
        if (!!schema.enum?.length)
          schema.enum.forEach((v) =>
            union.push({
              const: v,
            }),
          );
        else union.push(schema);
      else if (
        LlmTypeChecker.isInteger(schema) ||
        LlmTypeChecker.isNumber(schema)
      )
        if (!!schema.enum?.length)
          schema.enum.forEach((v) =>
            union.push({
              const: v,
            }),
          );
        else
          union.push({
            ...schema,
            ...LlmDescriptionInverter.numeric({
              config: props.config,
              description: schema.description,
            }),
            ...{ enum: undefined },
          });
      else if (LlmTypeChecker.isString(schema))
        if (!!schema.enum?.length)
          schema.enum.forEach((v) =>
            union.push({
              const: v,
            }),
          );
        else
          union.push({
            ...schema,
            ...LlmDescriptionInverter.string({
              config: props.config,
              description: schema.description,
            }),
            ...{ enum: undefined },
          });
      else
        union.push({
          ...schema,
        });
    };
    visit(props.schema);

    return {
      ...attribute,
      ...(union.length === 0
        ? { type: undefined }
        : union.length === 1
          ? { ...union[0] }
          : {
              oneOf: union.map((u) => ({ ...u, nullable: undefined })),
              discriminator:
                LlmTypeChecker.isAnyOf(props.schema) &&
                props.schema["x-discriminator"] !== undefined
                  ? {
                      propertyName:
                        props.schema["x-discriminator"].propertyName,
                      mapping:
                        props.schema["x-discriminator"].mapping !== undefined
                          ? invertDiscriminatorMapping(
                              props.$defs,
                              props.schema["x-discriminator"].mapping,
                              props.allocation,
                            )
                          : undefined,
                    }
                  : undefined,
            }),
    } satisfies OpenApi.IJsonSchema;
  };
}

const convertDiscriminatorMapping = (
  mapping: Record<string, string>,
): Record<string, string> | undefined => {
  const entries: [string, string][] = [];
  for (const [discriminator, reference] of Object.entries(mapping)) {
    const key: string | undefined = LlmReference.readOpenApi(reference);
    if (key === undefined) return undefined;
    entries.push([discriminator, LlmReference.write(key)]);
  }
  return Object.fromEntries(entries);
};

const invertDiscriminatorMapping = (
  $defs: Record<string, ILlmSchema>,
  mapping: Record<string, string>,
  allocation: Map<string, string>,
): Record<string, string> | undefined => {
  const entries: [string, string][] = [];
  for (const [discriminator, reference] of Object.entries(mapping)) {
    const resolved: LlmReference.IResolved | undefined = LlmReference.resolve(
      $defs,
      reference,
    );
    if (resolved === undefined) return undefined;
    entries.push([
      discriminator,
      LlmReference.writeOpenApi(
        allocation.get(resolved.key) ??
          OpenApiComponentName.escape(resolved.key),
      ),
    ]);
  }
  return Object.fromEntries(entries);
};

const validateStrict = (
  schema: OpenApi.IJsonSchema,
  accessor: string,
): IJsonSchemaTransformError.IReason[] => {
  const reasons: IJsonSchemaTransformError.IReason[] = [];
  if (OpenApiTypeChecker.isObject(schema)) {
    if (!!schema.additionalProperties)
      reasons.push({
        schema: schema,
        accessor: `${accessor}.additionalProperties`,
        message:
          "LLM does not allow additionalProperties in strict mode, the dynamic key typed object.",
      });
    for (const key of Object.keys(schema.properties ?? {}))
      if (schema.required?.includes(key) !== true)
        reasons.push({
          schema: schema,
          accessor: `${accessor}.properties.${key}`,
          message: "LLM does not allow optional properties in strict mode.",
        });
  }
  return reasons;
};

@typia/utils/src/converters/OpenApiConve:
import {
  OpenApi,
  OpenApiV3,
  OpenApiV3_1,
  OpenApiV3_2,
  SwaggerV2,
} from "@typia/interface";

import { OpenApiV3Downgrader } from "./internal/OpenApiV3Downgrader";
import { OpenApiV3Upgrader } from "./internal/OpenApiV3Upgrader";
import { OpenApiV3_1Downgrader } from "./internal/OpenApiV3_1Downgrader";
import { OpenApiV3_1Upgrader } from "./internal/OpenApiV3_1Upgrader";
import { OpenApiV3_2Upgrader } from "./internal/OpenApiV3_2Upgrader";
import { SwaggerV2Downgrader } from "./internal/SwaggerV2Downgrader";
import { SwaggerV2Upgrader } from "./internal/SwaggerV2Upgrader";

/**
 * OpenAPI version converter.
 *
 * `OpenApiConverter` converts between different OpenAPI specification versions:
 * Swagger v2.0, OpenAPI v3.0, OpenAPI v3.1, OpenAPI v3.2, and typia's emended
 * {@link OpenApi} format. Also converts individual components (schemas,
 * operations, paths).
 *
 * Upgrade path (to emended v3.2):
 *
 * - Swagger v2.0 → emended v3.2
 * - OpenAPI v3.0 → emended v3.2
 * - OpenAPI v3.1 → emended v3.2
 * - OpenAPI v3.2 → emended v3.2
 *
 * Downgrade path (from emended v3.2):
 *
 * - Emended v3.2 → Swagger v2.0
 * - Emended v3.2 → OpenAPI v3.0
 * - Emended v3.2 → OpenAPI v3.1
 *
 * The emended format normalizes ambiguous expressions: dereferences `$ref`,
 * merges `allOf`, converts `nullable` to union types, etc.
 *
 * @author Jeongho Nam - https://github.com/samchon
 */
export namespace OpenApiConverter {
  /* -----------------------------------------------------------
    DOCUMENTS
  ----------------------------------------------------------- */
  /**
   * Upgrade document to typia's emended OpenAPI v3.2 format.
   *
   * @param document Source document (Swagger v2.0, OpenAPI v3.0/v3.1/v3.2)
   * @returns Emended OpenAPI v3.2 document
   */
  export function upgradeDocument(
    document:
      | SwaggerV2.IDocument
      | OpenApiV3.IDocument
      | OpenApiV3_1.IDocument
      | OpenApiV3_2.IDocument
      | OpenApi.IDocument,
  ): OpenApi.IDocument {
    if (isUpgraded(document)) return document;
    else if (is_v32(document)) return OpenApiV3_2Upgrader.convert(document);
    else if (is_v31(document)) return OpenApiV3_1Upgrader.convert(document);
    else if (is_v30(document)) return OpenApiV3Upgrader.convert(document);
    else if (is_v20(document)) return SwaggerV2Upgrader.convert(document);
    document satisfies never;
    throw new Error("Invalid OpenAPI document");
  }

  /**
   * Downgrade document to Swagger v2.0 format.
   *
   * @param document Source emended OpenAPI document
   * @param version Target version "2.0"
   * @returns Swagger v2.0 document
   */
  export function downgradeDocument(
    document: OpenApi.IDocument,
    version: "2.0",
  ): SwaggerV2.IDocument;

  /**
   * Downgrade document to OpenAPI v3.0 format.
   *
   * @param document Source emended OpenAPI document
   * @param version Target version "3.0"
   * @returns OpenAPI v3.0 document
   */
  export function downgradeDocument(
    document: OpenApi.IDocument,
    version: "3.0",
  ): OpenApiV3.IDocument;

  export function downgradeDocument(
    document: OpenApi.IDocument,
    version: "3.1",
  ): OpenApiV3_1.IDocument;

  /** @internal */
  export function downgradeDocument(
    document: OpenApi.IDocument,
    version: "2.0" | "3.0" | "3.1",
  ): SwaggerV2.IDocument | OpenApiV3.IDocument | OpenApiV3_1.IDocument {
    if (version === "2.0") return SwaggerV2Downgrader.downgrade(document);
    else if (version === "3.0") return OpenApiV3Downgrader.downgrade(document);
    else if (version === "3.1")
      return OpenApiV3_1Downgrader.downgrade(document);

    version satisfies never;
    throw new Error("Invalid OpenAPI version");
  }

  /* -----------------------------------------------------------
    COMPONENTS
  ----------------------------------------------------------- */
  /**
   * Upgrade components to typia's emended format.
   *
   * @param input Source components (Swagger v2.0, OpenAPI v3.0/v3.1/v3.2)
   * @returns Emended OpenAPI components
   */
  export function upgradeComponents(
    input:
      | OpenApiV3_2.IComponents
      | OpenApiV3_1.IComponents
      | OpenApiV3.IComponents
      | SwaggerV2.IDocument,
  ): OpenApi.IComponents {
    if (is_v20(input)) return SwaggerV2Upgrader.convertComponents(input);
    return OpenApiV3_1Upgrader.convertComponents(input as any);
  }

  /**
   * Downgrade components to Swagger v2.0 definitions.
   *
   * @param input Source emended components
   * @param version Target version "2.0"
   * @returns Swagger v2.0 definitions record
   */
  export function downgradeComponents(
    input: OpenApi.IComponents,
    version: "2.0",
  ): Record<string, SwaggerV2.IJsonSchema>;

  /**
   * Downgrade components to OpenAPI v3.0 format.
   *
   * @param input Source emended components
   * @param version Target version "3.0"
   * @returns OpenAPI v3.0 components
   */
  export function downgradeComponents(
    input: OpenApi.IComponents,
    version: "3.0",
  ): OpenApiV3.IComponents;

  /**
   * Downgrade components to OpenAPI v3.1 format.
   *
   * @param input Source emended components
   * @param version Target version "3.1"
   * @returns OpenAPI v3.1 components
   */
  export function downgradeComponents(
    input: OpenApi.IComponents,
    version: "3.1",
