      parameters,
      parse: (str: string): IJsonParseResult<T> => parse(str, parameters),
      coerce: (input: unknown): T => coerce(input, parameters),
      validate: (input: unknown): IValidation<T> =>
        validator(input) as IValidation<T>,
    };
  }
}

