import { OpenApi } from "@typia/interface";

import { NamingConvention } from "../../utils/NamingConvention";
import { ObjectDictionary } from "../../utils/internal/ObjectDictionary";
import { IOpenApiValidatorContext } from "./IOpenApiValidatorContext";
import { OpenApiStationValidator } from "./OpenApiStationValidator";

export namespace OpenApiObjectValidator {
  export const validate = (
    ctx: IOpenApiValidatorContext<OpenApi.IJsonSchema.IObject>,
  ): boolean => {
    if (
      typeof ctx.value !== "object" ||
      ctx.value === null ||
      Array.isArray(ctx.value) ||
      isJsonObject(ctx.value) === false
    )
      return ctx.report(ctx);
    return [
      ...Object.entries(ctx.schema.properties ?? {}).map(([key, value]) =>
        OpenApiStationValidator.validate({
          ...ctx,
          schema: value,
          value: ObjectDictionary.get(ctx.value as Record<string, any>, key),
          path:
            ctx.path +
            (NamingConvention.variable(key)
              ? `.${key}`
              : `[${JSON.stringify(key)}]`),
          required: ctx.schema.required?.includes(key) ?? false,
        }),
      ),
      ...(typeof ctx.schema.additionalProperties === "object" &&
      ctx.schema.additionalProperties !== null
        ? // A key whose value is `undefined` has no JSON form, so it is not an
          // additional property to constrain. Validating it as a required value
          // would reject what `typia.is` and `typia.equals` both accept on an
          // index-signature type.
          Object.entries(ctx.value)
            .filter(
              ([key, value]) =>
                value !== undefined &&
                Object.keys(ctx.schema.properties ?? {}).includes(key) ===
                  false,
            )
            .map(([key, value]) =>
              OpenApiStationValidator.validate({
                ...ctx,
                schema: ctx.schema.additionalProperties as OpenApi.IJsonSchema,
                value,
                path:
                  ctx.path +
                  (NamingConvention.variable(key)
                    ? `.${key}`
                    : `[${JSON.stringify(key)}]`),
                required: true,
              }),
            )
        : []),
      // Whether a stray property is superfluous is asked only of a closed
      // object. An `additionalProperties` that opens the object — `true` for
      // any value, or a schema constraining it — declares that undeclared keys
      // are legitimate members, so they are never superfluous and `equals` has
      // nothing to decide. `typia.equals` agrees: it accepts an extra key on a
      // type carrying an index signature and rejects one on a type without.
      //
      // The previous `typeof !== "object"` test read only whether the keyword
      // was a schema, so it excluded `{ ... }` but not `true`, and closed an
      // object that had explicitly declared itself open. Reading the boolean is
      // what lets one document mix an open and a closed object under a single
      // `equals`, which no option value could otherwise satisfy.
      ...(ctx.equals === true && !ctx.schema.additionalProperties
        ? [validateEquals(ctx)]
        : []),
    ].every((v) => v);
  };

  const isJsonObject = (value: object): boolean => {
    try {
      return Object.prototype.toString.call(value) === "[object Object]";
    } catch {
      return false;
    }
  };

  const validateEquals = (
    ctx: IOpenApiValidatorContext<OpenApi.IJsonSchema.IObject>,
  ): boolean => {
    const regular: Set<string> = new Set(
      Object.keys(ctx.schema.properties ?? {}),
    );
    return Object.entries(ctx.value as object)
      .map(([key, value]) => {
        if (regular.has(key) === true) return true;
        // A key whose value is `undefined` has no JSON form — `JSON.stringify`
        // erases it — so the value does not carry it as a property and it
        // cannot be superfluous. `typia.equals` agrees, and typia's own emitter
        // erases `undefined` and `never` members from the schema while the
        // generated value still spells the keys out.
        if (value === undefined) return true;
        return ctx.report({
          ...ctx,
          path:
            ctx.path +
            (NamingConvention.variable(key)
              ? `.${key}`
              : `[${JSON.stringify(key)}]`),
          value,
          expected: "undefined",
          description: [
            `The property \`${key}\` is not defined in the object type.`,
            "",
            "Please remove the property next time.",
          ].join("\n"),
        });
      })
      .every((v) => v);
  };
}

import { OpenApi } from "@typia/interface";

import { MapUtil } from "../../utils";
import { LlmReference } from "../../utils/internal/LlmReference";
import { ObjectDictionary } from "../../utils/internal/ObjectDictionary";
import { OpenApiTypeChecker } from "../OpenApiTypeChecker";
import { IOpenApiValidatorContext } from "./IOpenApiValidatorContext";
import { OpenApiStationValidator } from "./OpenApiStationValidator";

export namespace OpenApiOneOfValidator {
  export const validate = (
    ctx: IOpenApiValidatorContext<OpenApi.IJsonSchema.IOneOf>,
    references: ReadonlySet<string> = new Set(),
  ): boolean => {
    const discriminator: IDiscriminator = getDiscriminator(ctx);
    const candidates: IDiscriminatorBranch[] = discriminator.branches.filter(
      (item) => item.predicator(ctx.value),
    );
    if (candidates.length !== 0) {
      for (const item of candidates)
        if (
          OpenApiStationValidator.validate(
            {
              ...ctx,
              schema: item.schema,
              exceptionable: false,
              equals: false,
            },
            undefined,
            references,
          )
        )
          return ctx.equals === true
            ? OpenApiStationValidator.validate(
                {
                  ...ctx,
                  schema: item.schema,
                },
                undefined,
                references,
              )
            : true;
        else if (item.retryable === false)
          return OpenApiStationValidator.validate(
            {
              ...ctx,
              schema: item.schema,
            },
            undefined,
            references,
          );
      return OpenApiStationValidator.validate(
        {
          ...ctx,
          schema: candidates[0]!.schema,
        },
        undefined,
        references,
      );
    }
    if (discriminator.branches.length !== 0)
      return validate(
        {
          ...ctx,
          schema: {
            oneOf: discriminator.remainders,
          },
        },
        references,
      );

    const matched: OpenApi.IJsonSchema | undefined =
      discriminator.remainders.find((schema) =>
        OpenApiStationValidator.validate(
          {
            ...ctx,
            schema,
            exceptionable: false,
            equals: false,
          },
          undefined,
          references,
        ),
      );
    if (matched === undefined) return ctx.report(ctx);
    return ctx.equals === true
      ? OpenApiStationValidator.validate(
          {
            ...ctx,
            schema: matched,
          },
          undefined,
          references,
        )
      : true;
  };

  const getDiscriminator = (
    ctx: IOpenApiValidatorContext<OpenApi.IJsonSchema.IOneOf>,
  ): IDiscriminator => {
    const resolvedList: IFlatSchema[] = ctx.schema.oneOf.map((schema) =>
      getFlattened({
        components: ctx.components,
        schema,
        visited: new Set(),
      }),
    );

    // FIND ANY TYPE
    const anything: IFlatSchema | undefined = resolvedList.find((resolved) =>
      OpenApiTypeChecker.isUnknown(resolved.escaped),
    );
    if (anything)
      return {
        branches: [],
        remainders: [anything.schema],
      };

    // CHECK NULLABLES
    const nullables: IFlatSchema<OpenApi.IJsonSchema.INull>[] =
      resolvedList.filter(
        (resolved): resolved is IFlatSchema<OpenApi.IJsonSchema.INull> =>
          OpenApiTypeChecker.isNull(resolved.schema),
      );
    const significant: IFlatSchema<OpenApi.IJsonSchema>[] = resolvedList.filter(
      (resolved) => false === OpenApiTypeChecker.isNull(resolved.escaped),
    );
    if (significant.length === 1)
      return {
        branches: [
          {
            schema: significant[0]!.schema,
            predicator: (value) => value !== null,
            retryable: false,
          },
        ],
        remainders: nullables.map((nullable) => nullable.schema),
      };

    // DISCRIMINATIONS
    const tuples = significant.filter((flat) =>
      OpenApiTypeChecker.isTuple(flat.escaped),
    );
    const arrays = significant.filter(
      (flat): flat is IFlatSchema<OpenApi.IJsonSchema.IArray> =>
        OpenApiTypeChecker.isArray(flat.escaped),
    );
    const branches: IDiscriminatorBranch[] = [
      ...(tuples.length === 0 && arrays.length !== 0
        ? discriminateArrays(ctx, arrays)
        : []),
      ...discriminateObjects(
        ctx,
        significant.filter(
          (flat): flat is IFlatSchema<OpenApi.IJsonSchema.IObject> =>
            OpenApiTypeChecker.isObject(flat.escaped),
        ),
        tuples.length + arrays.length === 0,
      ),
    ];
    return {
      branches,
      remainders: ctx.schema.oneOf.filter(
        (x) => branches.some((y) => y.schema === x) === false,
      ),
    };
  };

  const discriminateArrays = (
    ctx: IOpenApiValidatorContext<OpenApi.IJsonSchema.IOneOf>,
    arraySchemas: IFlatSchema<OpenApi.IJsonSchema.IArray>[],
  ): IDiscriminatorBranch[] => {
    if (arraySchemas.length === 1)
      return [
        {
          schema: arraySchemas[0]!.schema,
          predicator: (value) => Array.isArray(value),
          retryable: true,
        },
      ];
    return arraySchemas
      .filter((flat, i, array) =>
        array.every(
          (item, j) =>
            i === j ||
            OpenApiTypeChecker.covers({
              components: ctx.components,
              x: item.escaped.items,
              y: flat.escaped.items,
            }) === false,
        ),
      )
      .map(
        (flat) =>
          ({
            schema: flat.schema,
            predicator: (value) =>
              Array.isArray(value) &&
              (value.length === 0 ||
                OpenApiStationValidator.validate({
                  ...ctx,
                  schema: (flat.escaped as OpenApi.IJsonSchema.IArray).items,
                  value: value[0]!,
                  path: `${ctx.path}[0]`,
                  exceptionable: false,
                  equals: false,
                })),
            retryable: true,
          }) satisfies IDiscriminatorBranch,
      );
  };

  const discriminateObjects = (
    ctx: IOpenApiValidatorContext<OpenApi.IJsonSchema.IOneOf>,
    objectSchemas: IFlatSchema<OpenApi.IJsonSchema.IObject>[],
    noArray: boolean,
  ): IDiscriminatorBranch[] => {
    if (objectSchemas.length === 1)
      return [
        {
          schema: objectSchemas[0]!.schema,
          predicator: noArray
            ? (value) => typeof value === "object" && value !== null
            : (value) =>
                typeof value === "object" &&
                value !== null &&
                Array.isArray(value) === false,
          retryable: false,
        },
      ];

    // KEEP ONLY REQUIRED PROPERTIES
    objectSchemas = objectSchemas
      .filter(
        (flat) =>
          flat.escaped.properties !== undefined &&
          flat.escaped.required !== undefined,
      )
      .map(
        (flat) =>
          ({
            ...flat,
            escaped: {
              ...flat.escaped,
              properties: Object.fromEntries(
                Object.entries(flat.escaped.properties ?? {}).map(
                  ([key, value]) => [
                    key,
                    getFlattened({
                      components: ctx.components,
                      schema: value,
                      visited: new Set(),
                    }).escaped,
                  ],
                ),
              ),
            },
          }) satisfies IFlatSchema<OpenApi.IJsonSchema.IObject>,
      );

    // PROPERTY MATRIX
    const matrix: Map<string, Array<OpenApi.IJsonSchema | null>> = new Map();
    objectSchemas.forEach((obj, i) => {
      for (const [key, value] of Object.entries(obj.escaped.properties ?? {})) {
        if (!!obj.escaped.required?.includes(key) === false) continue;
        MapUtil.take(matrix, key, () =>
          new Array(objectSchemas.length).fill(null),
        )[i] = value;
      }
    });

    // THE BRANCHES
    return objectSchemas
      .map((obj, i) => {
        const candidates: string[] = [];
        for (const [key, value] of Object.entries(
          obj.escaped.properties ?? {},
        )) {
          if (!!obj.escaped.required?.includes(key) === false) continue;

          const neighbors: OpenApi.IJsonSchema[] = matrix
            .get(key)!
            .filter((_oppo, j) => i !== j)
            .filter((oppo) => oppo !== null);
          const unique: boolean = OpenApiTypeChecker.isConstant(value)
            ? neighbors.every(
                (oppo) =>
                  OpenApiTypeChecker.isConstant(oppo) &&
                  value.const !== oppo.const,
              )
            : neighbors.length === 0;
          if (unique) candidates.push(key);
        }
        if (candidates.length === 0) return null;
        const top: string =
          candidates.find((key) =>
            OpenApiTypeChecker.isConstant(obj.escaped.properties![key]!),
          ) ?? candidates[0]!;
        const target: OpenApi.IJsonSchema = obj.escaped.properties![top]!;
        return {
          schema: obj.schema,
          predicator: OpenApiTypeChecker.isConstant(target)
            ? (value) =>
                typeof value === "object" &&
                value !== null &&
                ObjectDictionary.get(value as Record<string, unknown>, top) ===
                  target.const
            : (value) =>
                typeof value === "object" &&
                value !== null &&
                ObjectDictionary.has(value, top),
          retryable: false,
        } satisfies IDiscriminatorBranch;
      })
      .filter((b) => b !== null);
  };
}

const getFlattened = (props: {
  components: OpenApi.IComponents;
  schema: OpenApi.IJsonSchema;
  visited: Set<string>;
}): IFlatSchema => {
  if (OpenApiTypeChecker.isReference(props.schema)) {
    const key: string | undefined = LlmReference.readOpenApi(props.schema.$ref);
    if (key === undefined || props.visited.has(key))
      return {
        schema: props.schema,
        escaped: { oneOf: [] },
      };
    props.visited.add(key);
    const found: OpenApi.IJsonSchema | undefined = ObjectDictionary.get(
      props.components.schemas,
      key,
    );
    if (found === undefined)
      return {
        schema: props.schema,
        escaped: { oneOf: [] },
      };
    return {
      ...getFlattened({
        components: props.components,
        schema: found,
        visited: props.visited,
      }),
      schema: props.schema,
    };
  }
  return {
    schema: props.schema,
    escaped: props.schema,
  };
};

interface IDiscriminator {
  branches: IDiscriminatorBranch[];
  remainders: OpenApi.IJsonSchema[];
}

interface IDiscriminatorBranch {
  schema: OpenApi.IJsonSchema;
  predicator: (value: unknown) => boolean;
  /**
   * Whether a failed predicate match may fall through to another candidate.
   *
   * Array first-element probes are tentative, while object key discriminators
   * establish ordered ownership of the value and its validation errors.
   */
  retryable: boolean;
}

interface IFlatSchema<
  Schema extends OpenApi.IJsonSchema = OpenApi.IJsonSchema,
> {
  schema: OpenApi.IJsonSchema;
  escaped: Schema;
}

import { OpenApi } from "@typia/interface";

import { OpenApiTypeChecker } from "../OpenApiTypeChecker";

export namespace OpenApiSchemaNamingRule {
  export const getName = (
    schema: OpenApi.IJsonSchema,
    union: boolean = false,
  ): string => {
    // COALESCE
    if (OpenApiTypeChecker.isUnknown(schema)) return "unknown";
    else if (OpenApiTypeChecker.isNull(schema)) return "null";
    else if (OpenApiTypeChecker.isOneOf(schema))
      return schema.oneOf.map((child) => getName(child, true)).join(" | ");
    // ATOMICS
    else if (OpenApiTypeChecker.isConstant(schema))
      return JSON.stringify(schema.const);
    else if (OpenApiTypeChecker.isBoolean(schema)) return "boolean";
    else if (OpenApiTypeChecker.isInteger(schema))
      return joinIntersection(getNameOfInteger(schema), union);
    else if (OpenApiTypeChecker.isNumber(schema))
      return joinIntersection(getNameOfNumber(schema), union);
    else if (OpenApiTypeChecker.isString(schema))
      return joinIntersection(getNameOfString(schema), union);
    // INSTANCES
    else if (OpenApiTypeChecker.isReference(schema))
      return schema.$ref.split("/").pop() ?? "unknown";
    else if (OpenApiTypeChecker.isObject(schema)) return "__object";
    else if (OpenApiTypeChecker.isArray(schema))
      return joinIntersection(getNameOfArray(schema), union);
    else if (OpenApiTypeChecker.isTuple(schema)) return getNameOfTuple(schema);
    return "unknown";
  };

  const getNameOfInteger = (schema: OpenApi.IJsonSchema.IInteger): string[] => {
    // `minimum`, `maximum`, `exclusiveMinimum`, and `exclusiveMaximum` are all
    // numbers in the declaration, each an independent bound rather than a
    // boolean modifier on another. Read every one on its own value, so an
    // exclusive bound is never dropped (including the falsy `0`) nor labeled
    // with a sibling's value.
    //
    // The normalized integer schema does not model `format`, but
    // `OpenApiConverter` passes an external document's `format` (`"int32"` /
    // `"int64"`) straight through, so read it defensively and echo only what is
    // there as `tags.Type<...>` — mirroring `OpenApiIntegerValidator.describeType`,
    // which names the same declared width and invents none.
    const format: unknown = (schema as { format?: unknown }).format;
    return [
      "number",
      ...(typeof format === "string"
        ? [`tags.Type<${JSON.stringify(format)}>`]
        : []),
      ...(schema.minimum !== undefined
        ? [`tags.Minimum<${schema.minimum}>`]
        : []),
      ...(schema.exclusiveMinimum !== undefined
        ? [`tags.ExclusiveMinimum<${schema.exclusiveMinimum}>`]
        : []),
      ...(schema.maximum !== undefined
        ? [`tags.Maximum<${schema.maximum}>`]
        : []),
      ...(schema.exclusiveMaximum !== undefined
        ? [`tags.ExclusiveMaximum<${schema.exclusiveMaximum}>`]
        : []),
      ...(schema.multipleOf !== undefined
        ? [`tags.MultipleOf<${schema.multipleOf}>`]
        : []),
    ];
  };

  // Read each numeric bound on its own value, as in `getNameOfInteger`. Unlike
  // integers, no `format` is echoed: `OpenApiNumberValidator` reports a bare
  // `number & ...` and never names a number's `format`, so echoing one here
  // would disagree with the validator on what the schema declares.
  const getNameOfNumber = (schema: OpenApi.IJsonSchema.INumber): string[] => [
    "number",
    ...(schema.minimum !== undefined
      ? [`tags.Minimum<${schema.minimum}>`]
      : []),
    ...(schema.exclusiveMinimum !== undefined
      ? [`tags.ExclusiveMinimum<${schema.exclusiveMinimum}>`]
      : []),
    ...(schema.maximum !== undefined
      ? [`tags.Maximum<${schema.maximum}>`]
      : []),
    ...(schema.exclusiveMaximum !== undefined
      ? [`tags.ExclusiveMaximum<${schema.exclusiveMaximum}>`]
      : []),
    ...(schema.multipleOf !== undefined
      ? [`tags.MultipleOf<${schema.multipleOf}>`]
      : []),
  ];

  const getNameOfString = (schema: OpenApi.IJsonSchema.IString): string[] => [
    "string",
    ...(schema.format !== undefined
      ? [`tags.Format<${JSON.stringify(schema.format)}>`]
      : []),
    ...(schema.pattern !== undefined && schema.format === undefined
      ? [`tags.Pattern<${JSON.stringify(schema.pattern)}>`]
      : []),
    ...(schema.contentMediaType !== undefined
      ? [`tags.ContentMediaType<${JSON.stringify(schema.contentMediaType)}>`]
      : []),
    ...(schema.minLength !== undefined
      ? [`tags.MinLength<${schema.minLength}>`]
      : []),
    ...(schema.maxLength !== undefined
      ? [`tags.MaxLength<${schema.maxLength}>`]
      : []),
  ];

  const getNameOfArray = (schema: OpenApi.IJsonSchema.IArray): string[] => [
    `Array<${getName(schema.items)}>`,
    ...(schema.minItems !== undefined
      ? [`tags.MinItems<${schema.minItems}>`]
      : []),
    ...(schema.maxItems !== undefined
      ? [`tags.MaxItems<${schema.maxItems}>`]
      : []),
    ...(schema.uniqueItems !== undefined ? [`tags.UniqueItems`] : []),
  ];

  const getNameOfTuple = (schema: OpenApi.IJsonSchema.ITuple): string =>
    "[" +
    [
      ...schema.prefixItems.map((child) => getName(child)),
      ...(schema.additionalItems === true
        ? ["...Array<unknown>"]
        : typeof schema.additionalItems === "object" &&
            schema.additionalItems !== null
          ? [`...Array<${getName(schema.additionalItems)}>`]
          : []),
    ].join(", ") +
    "]";

  const joinIntersection = (elements: string[], union: boolean): string => {
    const str: string = elements.join(" & ");
    return union ? `(${str})` : str;
  };
}

import { OpenApi } from "@typia/interface";

import { LlmReference } from "../../utils/internal/LlmReference";
import { ObjectDictionary } from "../../utils/internal/ObjectDictionary";
import { OpenApiTypeChecker } from "../OpenApiTypeChecker";
import { IOpenApiValidatorContext } from "./IOpenApiValidatorContext";
import { OpenApiArrayValidator } from "./OpenApiArrayValidator";
import { OpenApiBooleanValidator } from "./OpenApiBooleanValidator";
import { OpenApiConstantValidator } from "./OpenApiConstantValidator";
import { OpenApiIntegerValidator } from "./OpenApiIntegerValidator";
import { OpenApiNumberValidator } from "./OpenApiNumberValidator";
import { OpenApiObjectValidator } from "./OpenApiObjectValidator";
import { OpenApiOneOfValidator } from "./OpenApiOneOfValidator";
import { OpenApiSchemaNamingRule } from "./OpenApiSchemaNamingRule";
import { OpenApiStringValidator } from "./OpenApiStringValidator";
import { OpenApiTupleValidator } from "./OpenApiTupleValidator";

export namespace OpenApiStationValidator {
  export const validate = (
    ctx: Omit<IOpenApiValidatorContext<OpenApi.IJsonSchema>, "expected">,
    expected?: string,
    references: ReadonlySet<string> = new Set(),
  ): boolean => {
    // THE TYPE NAME
    expected ??= (() => {
      const name = OpenApiSchemaNamingRule.getName(ctx.schema);
      return ctx.required ? name : `${name} | undefined`;
    })();

    // COALESCE
    if (OpenApiTypeChecker.isUnknown(ctx.schema)) return true;
    else if (ctx.value === undefined)
      return (
        ctx.required === false ||
        ctx.report({
          ...ctx,
          expected,
        })
      );
    else if (OpenApiTypeChecker.isNull(ctx.schema))
      return (
        ctx.value === null ||
        ctx.report({
          ...ctx,
          expected,
        })
      );
    // NESTED
    else if (OpenApiTypeChecker.isReference(ctx.schema)) {
      let schema: OpenApi.IJsonSchema = ctx.schema;
      const visited: Set<string> = new Set(references);
      while (OpenApiTypeChecker.isReference(schema)) {
        const key: string | undefined = LlmReference.readOpenApi(schema.$ref);
        if (key === undefined)
          return ctx.report({
            ...ctx,
            expected,
            description: `Malformed schema reference ${JSON.stringify(schema.$ref)}.`,
          });
        if (visited.has(key))
          return ctx.report({
            ...ctx,
            expected,
            description: `Circular schema reference ${JSON.stringify(key)} cannot be resolved.`,
          });
        visited.add(key);
        const found: OpenApi.IJsonSchema | undefined = ObjectDictionary.get(
          ctx.components.schemas,
          key,
        );
        if (found === undefined)
          return ctx.report({
            ...ctx,
            expected,
            description: `Unable to resolve schema reference ${JSON.stringify(key)}.`,
          });
        schema = found;
      }
      return OpenApiStationValidator.validate(
        { ...ctx, schema },
        expected,
        visited,
      );
    } else if (OpenApiTypeChecker.isOneOf(ctx.schema))
      return OpenApiOneOfValidator.validate(
        {
          ...ctx,
          schema: ctx.schema,
          expected,
        },
        references,
      );
    // ATOMICS
    else if (OpenApiTypeChecker.isConstant(ctx.schema))
      return OpenApiConstantValidator.validate({
        ...ctx,
        schema: ctx.schema,
        expected,
      });
    else if (OpenApiTypeChecker.isBoolean(ctx.schema))
      return OpenApiBooleanValidator.validate({
        ...ctx,
        schema: ctx.schema,
        expected,
      });
    else if (OpenApiTypeChecker.isInteger(ctx.schema))
      return OpenApiIntegerValidator.validate({
        ...ctx,
        schema: ctx.schema,
        expected,
      });
    else if (OpenApiTypeChecker.isNumber(ctx.schema))
      return OpenApiNumberValidator.validate({
        ...ctx,
        schema: ctx.schema,
        expected,
      });
    else if (OpenApiTypeChecker.isString(ctx.schema))
      return OpenApiStringValidator.validate({
        ...ctx,
        schema: ctx.schema,
        expected,
      });
    // INSTANCES
    else if (OpenApiTypeChecker.isArray(ctx.schema))
      return OpenApiArrayValidator.validate({
        ...ctx,
        schema: ctx.schema,
        expected,
      });
    else if (OpenApiTypeChecker.isTuple(ctx.schema))
      return OpenApiTupleValidator.validate({
        ...ctx,
        schema: ctx.schema,
        expected,
      });
    else if (OpenApiTypeChecker.isObject(ctx.schema))
      return OpenApiObjectValidator.validate({
        ...ctx,
        schema: ctx.schema,
        expected,
      });
    return true;
  };
}

import { OpenApi } from "@typia/interface";

import { _isStringFormat } from "../functional/_isStringFormat";
import { _stringLength } from "../functional/_stringLength";
import { IOpenApiValidatorContext } from "./IOpenApiValidatorContext";

export namespace OpenApiStringValidator {
  export const validate = (
    ctx: IOpenApiValidatorContext<OpenApi.IJsonSchema.IString>,
  ): boolean => {
    if (typeof ctx.value !== "string") return ctx.report(ctx);
    const length: number | null =
      ctx.schema.minLength !== undefined || ctx.schema.maxLength !== undefined
        ? _stringLength(ctx.value)
        : null;
    return (
      [
        ctx.schema.minLength !== undefined
          ? length! >= ctx.schema.minLength ||
            ctx.report({
              ...ctx,
              expected: `string & MinLength<${ctx.schema.minLength}>`,
            })
          : true,
        ctx.schema.maxLength !== undefined
          ? length! <= ctx.schema.maxLength ||
            ctx.report({
              ...ctx,
              expected: `string & MaxLength<${ctx.schema.maxLength}>`,
            })
          : true,
        ctx.schema.pattern !== undefined
          ? new RegExp(ctx.schema.pattern).test(ctx.value) ||
            ctx.report({
              ...ctx,
              expected: `string & Pattern<${JSON.stringify(ctx.schema.pattern)}>`,
            })
          : true,
        ctx.schema.format
          ? _isStringFormat(ctx.schema.format, ctx.value) ||
            ctx.report({
              ...ctx,
              expected: `string & Format<${JSON.stringify(ctx.schema.format)}>`,
            })
          : true,
      ].every((v) => v) || ctx.report(ctx)
    );
  };
}

import { OpenApi } from "@typia/interface";

import { _isUniqueItems } from "../functional/_isUniqueItems";
import { IOpenApiValidatorContext } from "./IOpenApiValidatorContext";
import { OpenApiStationValidator } from "./OpenApiStationValidator";

export namespace OpenApiTupleValidator {
  export const validate = (
    ctx: IOpenApiValidatorContext<OpenApi.IJsonSchema.ITuple>,
  ): boolean => {
    if (!Array.isArray(ctx.value)) return ctx.report(ctx);

    const array: unknown[] = ctx.value;
    const length: number = array.length;
    const minimum: number =
      ctx.schema.minItems ?? ctx.schema.prefixItems.length;
    if (length < minimum)
      return ctx.report({
        ...ctx,
        expected: `Array<> & MinItems<${minimum}>`,
      });
    if (ctx.schema.maxItems !== undefined && length > ctx.schema.maxItems)
      return ctx.report({
        ...ctx,
        expected: `Array<> & MaxItems<${ctx.schema.maxItems}>`,
      });
    if (ctx.schema.uniqueItems === true && !_isUniqueItems(array))
      return ctx.report({
        ...ctx,
        expected: "Array<> & UniqueItems",
      });
    if (
      length > ctx.schema.prefixItems.length &&
      (ctx.schema.additionalItems === false ||
        ctx.schema.additionalItems === undefined)
    )
      return ctx.report(ctx);

    return Array.from({ length }, (_, index) => {
      const schema: OpenApi.IJsonSchema | undefined =
        index < ctx.schema.prefixItems.length
          ? ctx.schema.prefixItems[index]
          : typeof ctx.schema.additionalItems === "object" &&
              ctx.schema.additionalItems !== null
            ? ctx.schema.additionalItems
            : undefined;
      const value: unknown = array[index];
      if (Object.hasOwn(array, index) === false || value === undefined)
        return ctx.report({
          ...ctx,
          value,
          path: `${ctx.path}[${index}]`,
        });
      return schema === undefined
        ? true
        : OpenApiStationValidator.validate({
            ...ctx,
            schema,
            value,
            path: `${ctx.path}[${index}]`,
            required: true,
          });
    }).every((value) => value);
  };
}

@typia/utils/src/validators/LlmTypeCheck:
import { ILlmSchema } from "@typia/interface";

import { MapUtil } from "../utils/MapUtil";
import { LlmReference } from "../utils/internal/LlmReference";
import { ObjectDictionary } from "../utils/internal/ObjectDictionary";
import { OpenApiTypeCheckerBase } from "../utils/internal/OpenApiTypeCheckerBase";

/**
 * Type checker for LLM function calling schema.
 *
 * `LlmTypeChecker` is a type checker of {@link ILlmSchema}, the type schema for
 * LLM (Large Language Model) function calling.
 *
 * This checker provides type guard functions for validating schema types, and
 * operators for traversing and comparing schemas.
 *
 * @author Jeongho Nam - https://github.com/samchon
 */
export namespace LlmTypeChecker {
  /* -----------------------------------------------------------
    TYPE CHECKERS
  ----------------------------------------------------------- */
  /**
   * Test whether the schema is a null type.
   *
   * @param schema Target schema
   * @returns Whether null type or not
   */
  export const isNull = (schema: ILlmSchema): schema is ILlmSchema.INull =>
    (schema as ILlmSchema.INull).type === "null";

  /**
   * Test whether the schema is an unknown type.
   *
   * @param schema Target schema
   * @returns Whether unknown type or not
   */
  export const isUnknown = (
    schema: ILlmSchema,
  ): schema is ILlmSchema.IUnknown =>
    (schema as ILlmSchema.IUnknown).type === undefined &&
    !isAnyOf(schema) &&
    !isReference(schema);

  /**
   * Test whether the schema is a boolean type.
   *
   * @param schema Target schema
   * @returns Whether boolean type or not
   */
  export const isBoolean = (
    schema: ILlmSchema,
  ): schema is ILlmSchema.IBoolean =>
    (schema as ILlmSchema.IBoolean).type === "boolean";

  /**
   * Test whether the schema is an integer type.
   *
   * @param schema Target schema
   * @returns Whether integer type or not
   */
  export const isInteger = (
    schema: ILlmSchema,
  ): schema is ILlmSchema.IInteger =>
    (schema as ILlmSchema.IInteger).type === "integer";

  /**
   * Test whether the schema is a number type.
   *
   * @param schema Target schema
   * @returns Whether number type or not
   */
  export const isNumber = (schema: ILlmSchema): schema is ILlmSchema.INumber =>
    (schema as ILlmSchema.INumber).type === "number";

  /**
   * Test whether the schema is a string type.
   *
   * @param schema Target schema
   * @returns Whether string type or not
   */
  export const isString = (schema: ILlmSchema): schema is ILlmSchema.IString =>
    (schema as ILlmSchema.IString).type === "string";

  /**
   * Test whether the schema is an array type.
   *
   * @param schema Target schema
   * @returns Whether array type or not
   */
  export const isArray = (schema: ILlmSchema): schema is ILlmSchema.IArray =>
    (schema as ILlmSchema.IArray).type === "array" &&
    (schema as ILlmSchema.IArray).items !== undefined;

  /**
   * Test whether the schema is an object type.
   *
   * @param schema Target schema
   * @returns Whether object type or not
   */
  export const isObject = (schema: ILlmSchema): schema is ILlmSchema.IObject =>
    (schema as ILlmSchema.IObject).type === "object";

  /**
   * Test whether the schema is a reference type.
   *
   * @param schema Target schema
   * @returns Whether reference type or not
   */
  export const isReference = (
    schema: ILlmSchema,
  ): schema is ILlmSchema.IReference => (schema as any).$ref !== undefined;

  /**
   * Test whether the schema is a union type.
   *
   * @param schema Target schema
   * @returns Whether union type or not
   */
  export const isAnyOf = (schema: ILlmSchema): schema is ILlmSchema.IAnyOf =>
    (schema as ILlmSchema.IAnyOf).anyOf !== undefined;

  /* -----------------------------------------------------------
    OPERATORS
  ----------------------------------------------------------- */
  /**
   * Visit every nested schemas.
   *
   * Visit every nested schemas of the target, and apply the `props.closure`
   * function.
   *
   * Here is the list of occurring nested visitings:
   *
   * - {@link ILlmSchema.IAnyOf.anyOf}
   * - {@link ILlmSchema.IReference}
   * - {@link ILlmSchema.IObject.properties}
   * - {@link ILlmSchema.IArray.items}
   *
   * @param props Properties for visiting
   */
  export const visit = (props: {
    closure: (schema: ILlmSchema, accessor: string) => void;
    $defs?: Record<string, ILlmSchema> | undefined;
    schema: ILlmSchema;
    accessor?: string;
    refAccessor?: string;
  }): void => {
    const already: Set<string> = new Set();
    const refAccessor: string = props.refAccessor ?? "$input.$defs";
    const next = (schema: ILlmSchema, accessor: string): void => {
      props.closure(schema, accessor);
      if (LlmTypeChecker.isReference(schema)) {
        const resolved: LlmReference.IResolved | undefined =
          LlmReference.resolve(props.$defs, schema.$ref);
        if (resolved === undefined || already.has(resolved.key)) return;
        already.add(resolved.key);
        next(
          resolved.schema,
          `${refAccessor}[${JSON.stringify(resolved.key)}]`,
        );
      } else if (LlmTypeChecker.isAnyOf(schema))
        schema.anyOf.forEach((s, i) => next(s, `${accessor}.anyOf[${i}]`));
      else if (LlmTypeChecker.isObject(schema)) {
        for (const [key, value] of Object.entries(schema.properties))
          next(value, `${accessor}.properties[${JSON.stringify(key)}]`);
        if (
          typeof schema.additionalProperties === "object" &&
          schema.additionalProperties !== null
        )
          next(schema.additionalProperties, `${accessor}.additionalProperties`);
      } else if (LlmTypeChecker.isArray(schema))
        next(schema.items, `${accessor}.items`);
    };
    next(props.schema, props.accessor ?? "$input.schemas");
  };

  /**
   * Test whether the `x` schema covers the `y` schema.
   *
   * @param props Properties for testing
   * @returns Whether the `x` schema covers the `y` schema
   */
  export const covers = (props: {
    $defs?: Record<string, ILlmSchema> | undefined;
    x: ILlmSchema;
    y: ILlmSchema;
  }): boolean =>
    coverStation({
      $defs: props.$defs,
      x: props.x,
      y: props.y,
      visited: new Map(),
    });

  const coverStation = (p: {
    $defs?: Record<string, ILlmSchema> | undefined;
    visited: Map<ILlmSchema, Map<ILlmSchema, boolean>>;
    x: ILlmSchema;
    y: ILlmSchema;
  }): boolean => {
    const cache: boolean | undefined = p.visited.get(p.x)?.get(p.y);
    if (cache !== undefined) return cache;

    // FOR RECURSIVE CASE
    const nested: Map<ILlmSchema, boolean> = MapUtil.take(
      p.visited,
      p.x,
      () => new Map(),
    );
    nested.set(p.y, true);

    // COMPUTE IT
    const result: boolean = coverSchema(p);
    nested.set(p.y, result);
    return result;
  };

  const coverSchema = (p: {
    $defs?: Record<string, ILlmSchema> | undefined;
    visited: Map<ILlmSchema, Map<ILlmSchema, boolean>>;
    x: ILlmSchema;
    y: ILlmSchema;
  }): boolean => {
    // CHECK EQUALITY
    if (p.x === p.y)
      return isReference(p.x) ? hasReference(p.$defs, p.x) : true;
    else if (isReference(p.x) && isReference(p.y) && p.x.$ref === p.y.$ref)
      return hasReference(p.$defs, p.x);

    // COMPARE WITH FLATTENING
    const alpha: ILlmSchema[] = flatSchema(p.$defs, p.x);
    const beta: ILlmSchema[] = flatSchema(p.$defs, p.y);
    if (alpha.some((x) => isUnknown(x))) return true;
    else if (beta.some((x) => isUnknown(x))) return false;
    return beta.every((b) =>
      alpha.some((a) =>
        coverEscapedSchema({
          $defs: p.$defs,
          visited: p.visited,
          x: a,
          y: b,
        }),
      ),
    );
  };

  const coverEscapedSchema = (p: {
    $defs?: Record<string, ILlmSchema> | undefined;
    visited: Map<ILlmSchema, Map<ILlmSchema, boolean>>;
    x: ILlmSchema;
    y: ILlmSchema;
  }): boolean => {
    // CHECK EQUALITY
    if (p.x === p.y)
      return isReference(p.x) ? hasReference(p.$defs, p.x) : true;
    else if (isUnknown(p.x)) return true;
    else if (isUnknown(p.y)) return false;
    else if (isNull(p.x)) return isNull(p.y);
    // ATOMIC CASE
    else if (isBoolean(p.x)) return isBoolean(p.y) && coverBoolean(p.x, p.y);
    else if (isInteger(p.x)) return isInteger(p.y) && coverInteger(p.x, p.y);
    else if (isNumber(p.x)) return isNumber(p.y) && coverNumber(p.x, p.y);
    else if (isString(p.x)) return isString(p.y) && coverString(p.x, p.y);
    // INSTANCE CASE
    else if (isArray(p.x))
      return (
        isArray(p.y) &&
        coverArray({
          $defs: p.$defs,
          visited: p.visited,
          x: p.x,
          y: p.y,
        })
      );
    else if (isObject(p.x))
      return (
        isObject(p.y) &&
        coverObject({
          $defs: p.$defs,
          visited: p.visited,
          x: p.x,
          y: p.y,
        })
      );
    else if (isReference(p.x)) return isReference(p.y) && p.x.$ref === p.y.$ref;
    return false;
  };

  const coverArray = (p: {
    $defs?: Record<string, ILlmSchema> | undefined;
    visited: Map<ILlmSchema, Map<ILlmSchema, boolean>>;
    x: ILlmSchema.IArray;
    y: ILlmSchema.IArray;
  }): boolean => {
    if (
      !(
        p.x.minItems === undefined ||
        (p.y.minItems !== undefined && p.x.minItems <= p.y.minItems)
      )
    )
      return false;
    else if (
      !(
        p.x.maxItems === undefined ||
        (p.y.maxItems !== undefined && p.x.maxItems >= p.y.maxItems)
      )
    )
      return false;
    return coverStation({
      $defs: p.$defs,
      visited: p.visited,
      x: p.x.items,
      y: p.y.items,
    });
  };

  const coverObject = (p: {
    $defs?: Record<string, ILlmSchema> | undefined;
    visited: Map<ILlmSchema, Map<ILlmSchema, boolean>>;
    x: ILlmSchema.IObject;
    y: ILlmSchema.IObject;
  }): boolean => {
    if (!p.x.additionalProperties && !!p.y.additionalProperties) return false;
    else if (
      !!p.x.additionalProperties &&
      !!p.y.additionalProperties &&
      ((typeof p.x.additionalProperties === "object" &&
        p.y.additionalProperties === true) ||
        (typeof p.x.additionalProperties === "object" &&
          typeof p.y.additionalProperties === "object" &&
          !coverStation({
            $defs: p.$defs,
            visited: p.visited,
            x: p.x.additionalProperties,
            y: p.y.additionalProperties,
          })))
    )
      return false;
    return Object.entries(p.y.properties ?? {}).every(([key, b]) => {
      const a: ILlmSchema | undefined = ObjectDictionary.get(
        p.x.properties,
        key,
      );
      if (a === undefined) return false;
      else if (
        (p.x.required?.includes(key) ?? false) === true &&
        (p.y.required?.includes(key) ?? false) === false
      )
        return false;
      return coverStation({
        $defs: p.$defs,
        visited: p.visited,
        x: a,
        y: b,
      });
    });
  };

  const coverBoolean = (
    x: ILlmSchema.IBoolean,
    y: ILlmSchema.IBoolean,
  ): boolean => {
    if (!!x.enum?.length)
      return !!y.enum?.length && y.enum.every((v) => x.enum!.includes(v));
    return true;
  };

  const coverInteger = (
    x: ILlmSchema.IInteger,
    y: ILlmSchema.IInteger,
  ): boolean => {
    if (!!x.enum?.length)
      return !!y.enum?.length && y.enum.every((v) => x.enum!.includes(v));
    return OpenApiTypeCheckerBase.coverInteger(x, y);
  };

  const coverNumber = (
    x: ILlmSchema.INumber,
    y: ILlmSchema.IInteger | ILlmSchema.INumber,
  ): boolean => {
    if (!!x.enum?.length)
      return !!y.enum?.length && y.enum.every((v) => x.enum!.includes(v));
    return OpenApiTypeCheckerBase.coverNumber(x, y);
  };

  const coverString = (
    x: ILlmSchema.IString,
    y: ILlmSchema.IString,
  ): boolean => {
    if (!!x.enum?.length)
      return !!y.enum?.length && y.enum.every((v) => x.enum!.includes(v));
    return OpenApiTypeCheckerBase.coverString(x, y);
  };

  const flatSchema = (
    $defs: Record<string, ILlmSchema> | undefined,
    schema: ILlmSchema,
  ): ILlmSchema[] => {
    schema = escapeReference($defs, schema);
    if (isAnyOf(schema))
      return schema.anyOf.map((v) => flatSchema($defs, v)).flat();
    return [schema];
  };

  const escapeReference = (
    $defs: Record<string, ILlmSchema> | undefined,
    schema: ILlmSchema,
  ): ILlmSchema => LlmReference.dereference($defs, schema) ?? schema;

  const hasReference = (
    $defs: Record<string, ILlmSchema> | undefined,
    schema: ILlmSchema.IReference,
  ): boolean => LlmReference.dereference($defs, schema) !== undefined;
}

