export const _isUniqueItems = (elements: any[]): boolean => {
  for (let i = 0; i < elements.length; i++)
    for (let j = i + 1; j < elements.length; j++)
      if (equals(new WeakMap())(elements[i], elements[j])) return false;
  return true;
};

const equals = (visited: WeakMap<object, WeakMap<object, boolean>>) => {
  const next = (a: any, b: any): boolean => {
    if (a === b) return true;
    if (
      a === null ||
      b === null ||
      typeof a !== "object" ||
      typeof b !== "object"
    )
      return false;

    const previous: boolean | undefined = visited.get(a)?.get(b);
    if (previous !== undefined) return previous;
    const pairs: WeakMap<object, boolean> =
      visited.get(a) ?? new WeakMap<object, boolean>();
    visited.set(a, pairs);
    pairs.set(b, true);

    const result: boolean = compare(a, b);
    pairs.set(b, result);
    return result;
  };

  const compare = (a: object, b: object): boolean => {
    if (Array.isArray(a)) {
      if (!Array.isArray(b) || a.length !== b.length) return false;
      for (let i = 0; i < a.length; i++) {
        const aHas: boolean = Object.hasOwn(a, i);
        if (aHas !== Object.hasOwn(b, i) || (aHas && !next(a[i], b[i])))
          return false;
      }
      return true;
    }
    if (Array.isArray(b)) return false;

    if (a instanceof Set) {
      if (!(b instanceof Set) || a.size !== b.size) return false;
      const unmatched: any[] = [...b];
      for (const value of a) {
        const index: number = unmatched.findIndex((candidate) =>
          next(value, candidate),
        );
        if (index === -1) return false;
        unmatched.splice(index, 1);
      }
      return true;
    }
    if (a instanceof Map) {
      if (!(b instanceof Map) || a.size !== b.size) return false;
      const unmatched: [any, any][] = [...b];
      for (const [key, value] of a) {
        const index: number = unmatched.findIndex(
          ([candidateKey, candidateValue]) =>
            next(key, candidateKey) && next(value, candidateValue),
        );
        if (index === -1) return false;
        unmatched.splice(index, 1);
      }
      return true;
    }

    if (a instanceof Boolean)
      return b instanceof Boolean && a.valueOf() === b.valueOf();
    if (Object.prototype.toString.call(a) === "[object BigInt]")
      return (
        Object.prototype.toString.call(b) === "[object BigInt]" &&
        a.valueOf() === b.valueOf()
      );
    if (Object.prototype.toString.call(a) === "[object Symbol]")
      return (
        Object.prototype.toString.call(b) === "[object Symbol]" &&
        a.valueOf() === b.valueOf()
      );
    if (a instanceof Number)
      return b instanceof Number && a.valueOf() === b.valueOf();
    if (a instanceof String)
      return b instanceof String && a.valueOf() === b.valueOf();
    if (a instanceof Date)
      return b instanceof Date && a.getTime() === b.getTime();
    if (a instanceof RegExp)
      return (
        b instanceof RegExp && a.source === b.source && a.flags === b.flags
      );

    if (typeof File !== "undefined" && a instanceof File)
      return (
        b instanceof File &&
        a.name === b.name &&
        a.size === b.size &&
        a.type === b.type &&
        a.lastModified === b.lastModified
      );
    if (typeof Blob !== "undefined" && a instanceof Blob)
      return b instanceof Blob && a.size === b.size && a.type === b.type;

    if (a instanceof DataView) {
      if (!(b instanceof DataView) || a.byteLength !== b.byteLength)
        return false;
      return bytes(a.buffer, a.byteOffset, a.byteLength).every(
        (value, index) =>
          value === bytes(b.buffer, b.byteOffset, b.byteLength)[index],
      );
    }
    if (ArrayBuffer.isView(a)) {
      if (
        !ArrayBuffer.isView(b) ||
        b instanceof DataView ||
        Object.getPrototypeOf(a) !== Object.getPrototypeOf(b) ||
        a.byteLength !== b.byteLength
      )
        return false;
      const x: Uint8Array = bytes(a.buffer, a.byteOffset, a.byteLength);
      const y: Uint8Array = bytes(b.buffer, b.byteOffset, b.byteLength);
      return x.every((value, index) => value === y[index]);
    }
    if (a instanceof ArrayBuffer)
      return (
        b instanceof ArrayBuffer &&
        a.byteLength === b.byteLength &&
        bytes(a).every((value, index) => value === bytes(b)[index])
      );
    if (
      typeof SharedArrayBuffer !== "undefined" &&
      a instanceof SharedArrayBuffer
    )
      return (
        b instanceof SharedArrayBuffer &&
        a.byteLength === b.byteLength &&
        bytes(a).every((value, index) => value === bytes(b)[index])
      );

    const keys: PropertyKey[] = Reflect.ownKeys(a).filter((key) =>
      Object.prototype.propertyIsEnumerable.call(a, key),
    );
    return (
      keys.length ===
        Reflect.ownKeys(b).filter((key) =>
          Object.prototype.propertyIsEnumerable.call(b, key),
        ).length &&
      keys.every(
        (key) =>
          Object.prototype.propertyIsEnumerable.call(b, key) &&
          next((a as any)[key], (b as any)[key]),
      )
    );
  };
  return next;
};

const bytes = (
  buffer: ArrayBufferLike,
  byteOffset: number = 0,
  byteLength: number = buffer.byteLength,
): Uint8Array => new Uint8Array(buffer, byteOffset, byteLength);

typia/src/internal/_jsonStringifyArray.t:
/**
 * Serializes the elements of an array the way ECMAScript `JSON.stringify` does.
 *
 * `SerializeJSONArray` walks index `0` to `LengthOfArrayLike(value) - 1` and
 * writes `null` wherever the element serializes to `undefined`. Neither
 * `Array.prototype.map` nor `Array.prototype.join` reproduces that:
 *
 * - `map` never visits a hole and leaves one behind, and `join` renders a hole as
 *   empty text, so a sparse array joined into malformed text such as `[,1]`. A
 *   hole exists at runtime whatever the element type declares, so this is not
 *   an `any` concern.
 * - `join` renders a mapped `undefined` as empty text too, which is what an `any`
 *   or `unknown` element holding a function, a symbol, or a `toJSON` that
 *   returns nothing serializes to.
 *
 * The length is converted with `ToLength` and read once, which is both what
 * `JSON.stringify` does and what `Array.prototype.every` - the traversal
 * typia's own array checkers emit - does, so the checker and the serializer
 * walk one index range rather than two that merely usually coincide.
 *
 * @param elements Array being serialized.
 * @param mapper Serializer of one element, emitted by the transform.
 * @returns Comma separated element text, without the enclosing brackets.
 * @internal
 */
export const _jsonStringifyArray = <T>(
  elements: ArrayLike<T>,
  mapper: (elem: T, index: number) => string,
): string => {
  const length: number = Math.min(
    Math.max(Math.trunc(elements.length) || 0, 0),
    Number.MAX_SAFE_INTEGER,
  );
  let output: string = "";
  for (let i: number = 0; i < length; ++i) {
    const elem: T | undefined = elements[i];
    // A hole and an explicit `undefined` are answered without calling the
    // mapper, because the mapper is the element type's own serializer and a
    // typed one has no answer for a missing value. Everything else is answered
    // from the mapper's *result*: an element that is present but serializes to
    // nothing — a function, a symbol, or a `toJSON` returning nothing in an
    // `any` slot — is `null` in an array position, exactly as
    // SerializeJSONArray specifies, and testing the input instead would let its
    // text become the literal `undefined`.
    const text: string | undefined =
      elem === undefined ? undefined : mapper(elem, i);
    output += (i === 0 ? "" : ",") + (text === undefined ? "null" : text);
  }
  return output;
};

