import { IValidation } from "@typia/interface";

export const _validateReport = (array: IValidation.IError[]) => {
  const isAncestor = (ancestor: string, descendant: string): boolean =>
    descendant === ancestor ||
    descendant.startsWith(`${ancestor}.`) ||
    descendant.startsWith(`${ancestor}[`);
  const reportable = (path: string): boolean => {
    if (array.length === 0) return true;
    const last: string = array[array.length - 1]!.path;
    return isAncestor(path, last) === false && isAncestor(last, path) === false;
  };
  return (exceptable: boolean, error: IValidation.IError): false => {
    if (exceptable && reportable(error.path)) {
      if (error.value === undefined)
        error.description ??= [
          "The value at this path is `undefined`.",
          "",
          `Please fill the \`${error.expected}\` typed value next time.`,
        ].join("\n");
      array.push(error);
    }
    return false;
  };
};

typia/src/internal/private/__notationRen:
/**
 * Shared outer walk for the `camel`/`pascal` notations.
 *
 * Mirrors the `CamelCase<T>` / `PascalCase<T>` typings: leading underscores are
 * preserved verbatim, an all-underscore key stays untouched, and the presence
 * of any remaining underscore — not the number of non-empty segments — selects
 * the `snake` conversion. Routing on underscore presence keeps a trailing or
 * doubled underscore (`fooBar_`) on the same path the type takes, instead of
 * collapsing it to the underscore-free `plain` path.
 */
export const __notationRename =
  (props: { plain: (str: string) => string; snake: (str: string) => string }) =>
  (str: string): string => {
    let prefix: string = "";
    while (str.startsWith("_")) {
      prefix += "_";
      str = str.substring(1);
    }
    if (str.length === 0) return prefix;
    return `${prefix}${str.includes("_") ? props.snake(str) : props.plain(str)}`;
  };

typia/src/internal/private/__randomCompo:
import { _randomInteger } from "../_randomInteger";

/**
 * Splits `total` into `count` parts, each inside `[minimum, maximum]`.
 *
 * Used where a format's length is the sum of its segments — an IPv4 octet spans
 * one to three digits, an IPv6 group one to four — so a requested total length
 * is realized by choosing how many characters each segment contributes instead
 * of redrawing whole addresses and hoping one lands in the window (issue
 * #2284).
 *
 * The caller guarantees `count * minimum <= total <= count * maximum`; each
 * part is drawn from the range that still leaves the remaining parts
 * satisfiable.
 */
export const __randomComposition = (props: {
  total: number;
  count: number;
  minimum: number;
  maximum: number;
}): number[] => {
  const parts: number[] = [];
  let remaining: number = props.total;
  for (let i: number = 0; i < props.count; ++i) {
    const rest: number = props.count - i - 1;
    const value: number = _randomInteger({
      type: "integer",
      minimum: Math.max(props.minimum, remaining - rest * props.maximum),
      maximum: Math.min(props.maximum, remaining - rest * props.minimum),
    });
    parts.push(value);
    remaining -= value;
  }
  return parts;
};

/** Draws `length` decimal digits, leading zeros included. */
export const __randomDigits = (length: number): string => {
  let text: string = "";
  for (let i: number = 0; i < length; ++i)
    text += String(_randomInteger({ type: "integer", minimum: 0, maximum: 9 }));
  return text;
};

/** Draws a decimal number of exactly `length` digits without a leading zero. */
export const __randomNumeric = (length: number): string =>
  length <= 1
    ? String(_randomInteger({ type: "integer", minimum: 0, maximum: 9 }))
    : String(_randomInteger({ type: "integer", minimum: 1, maximum: 9 })) +
      __randomDigits(length - 1);

typia/src/internal/private/__randomEpoch:
import { _randomInteger } from "../_randomInteger";

export interface __IEpochProps {
  minimum?: number;
  maximum?: number;
}

/**
 * Draws an epoch millisecond inside the requested bounds.
 *
 * Shared by the `date` and `date-time` generators, which had the same bound
 * expression written twice: `props?.maximum ?? props?.minimum === undefined`
 * parses as `props?.maximum ?? (props?.minimum === undefined)` because `??`
 * binds looser than `===`, so any supplied `maximum` made the condition truthy
 * and was replaced by `Date.now()`, while `maximum: 0` fell through to
 * `undefined + one year` and produced `NaN` (issue #2287). Keeping the
 * resolution in one place is what stops the two copies from drifting again.
 *
 * With no bound at all the window ends at the present instant; with only a
 * lower bound it spans one year from there.
 */
export const __randomEpoch = (props?: __IEpochProps): number => {
  const minimum: number = props?.minimum ?? 0;
  const maximum: number =
    props?.maximum ??
    (props?.minimum === undefined ? Date.now() : props.minimum + YEAR);
  return _randomInteger({
    type: "integer",
    minimum,
    maximum,
  });
};

const YEAR = 365 * 24 * 60 * 60 * 1_000;

typia/src/json.ts:
import {
  IJsonSchemaApplication,
  IJsonSchemaCollection,
  IJsonSchemaUnit,
  IValidation,
  Primitive,
} from "@typia/interface";

import { TypeGuardError } from "./TypeGuardError";
import { NoTransformConfigurationError } from "./transformers/NoTransformConfigurationError";

/* ===========================================================
    JSON
      - METADATA
      - PARSE
      - STRINGIFY
      - FACTORY FUNCTIONS
==============================================================
    METADATA
----------------------------------------------------------- */
/**
 * Generates JSON schema for type `T`.
 *
 * @danger You must configure the generic argument `Type`
 */
export function schema(): never;

/**
 * Generates JSON schema for type `T`.
 *
 * Creates {@link IJsonSchemaUnit} containing a main schema and shared
 * components. Named types are stored in `components` for `$ref` referencing.
 *
 * Specify OpenAPI version via `Version` generic (`"3.0"` or `"3.1"`). Default
 * is `"3.1"`. Key difference: `"3.1"` supports tuple types.
 *
 * @template Type Target type
 * @template Version OpenAPI version (`"3.0"` | `"3.1"`). Default `"3.1"`
 * @returns JSON schema unit
 */
export function schema<
  Type extends unknown,
  Version extends "3.0" | "3.1" = "3.1",
>(): IJsonSchemaUnit<Version, Type>;

/** @internal */
export function schema(): never {
  NoTransformConfigurationError("json.schema");
}

/**
 * Generates JSON schemas for multiple types.
 *
 * @danger You must configure the generic argument `Types`
 */
export function schemas(): never;

/**
 * Generates JSON schemas for multiple types.
 *
 * Creates {@link IJsonSchemaCollection} containing schemas for all types in the
 * tuple. Named types are stored in `components` for `$ref` referencing.
 *
 * Specify OpenAPI version via `Version` generic (`"3.0"` or `"3.1"`). Default
 * is `"3.1"`. Key difference: `"3.1"` supports tuple types.
 *
 * @template Types Tuple of target types
 * @template Version OpenAPI version (`"3.0"` | `"3.1"`). Default `"3.1"`
 * @returns JSON schema collection
 */
export function schemas<
  Types extends unknown[],
  Version extends "3.0" | "3.1" = "3.1",
>(): IJsonSchemaCollection<Version, Types>;

/** @internal */
export function schemas(): never {
  NoTransformConfigurationError("json.schemas");
}

/**
 * Generates JSON function schema application.
 *
 * @danger You must configure the generic argument `Class`
 */
export function application(): never;

/**
 * Generates JSON function schema application from class/interface.
 *
 * Creates {@link IJsonSchemaApplication} from a TypeScript class or interface,
 * generating JSON schemas for all methods, parameters, and return types.
 * Designed for building custom LLM function calling schemas.
 *
 * The returned object contains:
 *
 * - `functions`: Array of function metadata with parameter/return schemas
 * - `components`: Shared schema components for `$ref` referencing
 *
 * Use cases:
 *
 * - Custom LLM function calling schema formats
 * - API documentation or code generation tools
 * - Alternative LLM integrations that need full JSON Schema
 *
 * For standard LLM function calling, use {@link llm.application} instead, which
 * builds the LLM-optimized function schema directly.
 *
 * @template Class Target class or interface type
 * @template Version OpenAPI version (`"3.0"` | `"3.1"`). Default `"3.1"`
 * @returns JSON function schema application
 */
export function application<
  Class extends object,
  Version extends "3.0" | "3.1" = "3.1",
>(): IJsonSchemaApplication<Version, Class>;

/** @internal */
export function application(): never {
  NoTransformConfigurationError("json.application");
}

/* -----------------------------------------------------------
    PARSE
----------------------------------------------------------- */
/**
 * Parses JSON string with assertion.
 *
 * @danger You must configure the generic argument `T`
 */
export function assertParse(
  input: string,
  errorFactory?: undefined | ((props: TypeGuardError.IProps) => Error),
): never;

/**
 * Parses JSON string with assertion.
 *
 * Combines `JSON.parse()` with {@link assert}. Throws {@link TypeGuardError} when
 * parsed value doesn't match type `T`.
 *
 * Related functions:
 *
 * - {@link isParse} — Returns `null` instead of throwing
 * - {@link validateParse} — Returns detailed validation errors
 *
 * @template T Target type for parsed value
 * @param input JSON string to parse
 * @param errorFactory Custom error factory receiving
 *   {@link TypeGuardError.IProps}
 * @returns Parsed value of type `T`
 * @throws {TypeGuardError} When parsed value doesn't conform to type `T`
 */
export function assertParse<T>(
  input: string,
  errorFactory?: undefined | ((props: TypeGuardError.IProps) => Error),
): Primitive<T>;

/** @internal */
export function assertParse<T>(): Primitive<T> {
  NoTransformConfigurationError("json.assertParse");
}

/**
 * Parses JSON string with type checking.
 *
 * @danger You must configure the generic argument `T`
 */
export function isParse(input: string): never;

/**
 * Parses JSON string with type checking.
 *
 * Combines `JSON.parse()` with {@link is}. Returns `null` when parsed value
 * doesn't match type `T`.
 *
 * Related functions:
 *
 * - {@link assertParse} — Throws instead of returning `null`
 * - {@link validateParse} — Returns detailed validation errors
 *
 * @template T Target type for parsed value
 * @param input JSON string to parse
 * @returns Parsed value of type `T`, or `null` if invalid
 */
export function isParse<T>(input: string): Primitive<T> | null;

/** @internal */
export function isParse<T>(): Primitive<T> | null {
  NoTransformConfigurationError("json.isParse");
}

/**
 * Parses JSON string with validation.
 *
 * @danger You must configure the generic argument `T`
 */
export function validateParse(input: string): never;

/**
 * Parses JSON string with validation.
 *
 * Combines `JSON.parse()` with {@link validate}. Returns
 * {@link IValidation.IFailure} with all errors on mismatch, or
 * {@link IValidation.ISuccess} with parsed value.
 *
 * Related functions:
 *
 * - {@link assertParse} — Throws on first error
 * - {@link isParse} — Returns `null` instead of error details
 *
 * @template T Target type for parsed value
 * @param input JSON string to parse
 * @returns Validation result containing parsed value or errors
 */
export function validateParse<T>(input: string): IValidation<Primitive<T>>;

/** @internal */
export function validateParse<T>(): IValidation<Primitive<T>> {
  NoTransformConfigurationError("json.validateParse");
}

/* -----------------------------------------------------------
    STRINGIFY
----------------------------------------------------------- */
/**
 * Converts value to JSON string (8x faster).
 *
 * Generates optimized JSON conversion code specific to type `T`, achieving ~8x
 * faster performance than native `JSON.stringify()`.
 *
 * Does not validate the input. For validation, use:
 *
 * - {@link assertStringify} — Throws on type mismatch
 * - {@link isStringify} — Returns `null` on type mismatch
 * - {@link validateStringify} — Returns detailed validation errors
 *
 * @template T Type of input value
 * @param input Value to stringify
 * @returns JSON string
 */
export function stringify<T>(input: T): string;

/** @internal */
export function stringify(): never {
  NoTransformConfigurationError("json.stringify");
}

/**
 * Converts value to JSON string with assertion (5x faster).
